      toast.error('Danh mß╗Ñc ch╞░a ─æ╞░ß╗úc li├¬n kß║┐t vß╗¢i PKGX. Vui l├▓ng mapping trong C├ái ─æß║╖t > PKGX.');
      return;
    }
    
    toast.loading(`─Éang ─æß╗ông bß╗Ö SEO danh mß╗Ñc...`, { id: 'pkgx-category-sync-seo' });
    
    try {
      const pkgxSeo = category.websiteSeo?.pkgx;
      // Fallback chain: SEO PKGX ΓåÆ SEO Chung ΓåÆ name
