        // Auto-refresh ─æß╗â cß║¡p nhß║¡t store
        await refreshCategoryFromPkgx(pkgxCatId);
        
        toast.success(`─É├ú ─æß╗ông bß╗Ö m├┤ tß║ú cho danh mß╗Ñc: ${category.name}`, { id: 'pkgx-category-sync-desc' });
