        await refreshCategoryFromPkgx(pkgxCatId);
        
        toast.success(`─É├ú ─æß╗ông bß╗Ö tß║Ñt cß║ú th├┤ng tin danh mß╗Ñc: ${category.name}`, { id: 'pkgx-category-sync-all' });
        logAction({
          action: 'sync_category_all',
          status: 'success',
          message: `─É├ú ─æß╗ông bß╗Ö tß║Ñt cß║ú: ${category.name}`,
          details: { categoryId: category.systemId, pkgxCatId },
        });
      } else {
