            updateInventory(p.productSystemId, branchSystemId, adjustQuantity);
            
            const issueLabel = p.issueType === 'missing' ? 'Thiß║┐u' : p.issueType === 'excess' ? 'Thß╗½a' : p.issueType === 'defective' ? 'Hß╗Ång' : 'Kh├íc';
            const adjustLabel = adjustQuantity > 0 ? `+${adjustQuantity}` : adjustQuantity;
            return {
              productSystemId: p.productSystemId,
              productId: p.productId,
              productName: p.productName,
              quantityAdjusted: adjustQuantity,
              reason: `─Éiß╗üu chß╗ënh kho khiß║┐u nß║íi ${complaint.id} (${issueLabel}: ${adjustLabel})`,
              branchSystemId: branchSystemId,
            };
          })
          .filter((item): item is NonNullable<typeof item> => Boolean(item));
        
        if (adjustedItems.length > 0) {
          inventoryAdjustment = {
            adjusted: true,
            adjustedBy: currentUser.systemId,
            adjustedAt: new Date(),
            adjustmentNote: `─Éiß╗üu chß╗ënh kho theo x├íc minh khiß║┐u nß║íi - ${adjustedItems.length} sß║ún phß║⌐m`,
            items: adjustedItems,
          };
          
          toast.success(MSG.SUCCESS.INVENTORY_ADJUSTED(adjustedItems.length));
        }
      }
      
      const penaltyEmployeeName = responsibleEmployee?.fullName;

      const newAction: ComplaintAction = {
        id: asSystemId(`action_${Date.now()}`),
        actionType: "verified-correct",
        performedBy: currentUser.systemId,
        performedAt: new Date(),
        note: `Ph╞░╞íng ├ín: ${method === "refund" ? "Ho├án tiß╗ün" : "B├╣ trß║ú h├áng"}${method === "refund" ? `\nSß╗æ tiß╗ün ho├án trß║ú: ${cost.toLocaleString("vi-VN")} ─æ` : ''}\nChi ph├¡ ph├ít sinh: ${incurredCost.toLocaleString("vi-VN")} ─æ\nL├╜ do: ${reason}${paymentId ? `\n─É├ú tß║ío phiß║┐u chi: ${paymentId}` : ''}${incurredCost > 0 && receiptId ? `\n─É├ú tß║ío phiß║┐u thu: ${receiptId}${penaltyEmployeeName ? ` (Thu tß╗½ ${penaltyEmployeeName})` : ''}` : ''}${inventoryAdjustment ? `\n─É├ú ─æiß╗üu chß╗ënh kho: ${inventoryAdjustment.items.length} sß║ún phß║⌐m` : ''}`,
        metadata: {
          method,
          cost,
          incurredCost,
          reason,
          paymentSystemId,
          receiptSystemId,
        },
      };
      
      // DEBUG: Log metadata duoc luu
      
      // Update affectedProducts voi so luong da xac minh
      const updatedAffectedProducts = complaint.affectedProducts?.map(p => ({
        ...p,
        quantityMissing: confirmedQuantities?.[p.productSystemId] ?? p.quantityMissing, // Update voi so luong xac minh
      }));
      
      updateComplaint(complaint.systemId, {
        isVerifiedCorrect: true,
        verification: "verified-correct",
        resolution: method === "refund" ? "refund" : "replacement",
        resolutionNote: method === "refund" 
          ? `Ho├án tiß╗ün: ${cost.toLocaleString("vi-VN")} ─æ\nChi ph├¡ ph├ít sinh: ${incurredCost.toLocaleString("vi-VN")} ─æ\nL├╜ do: ${reason}`
          : `B├╣ trß║ú h├áng cho kh├ích\nChi ph├¡ ph├ít sinh: ${incurredCost.toLocaleString("vi-VN")} ─æ\nL├╜ do: ${reason}`,
        compensationAmount: cost,
        incurredCost: incurredCost,
        compensationReason: reason,
        affectedProducts: updatedAffectedProducts, // Luu so luong da xac minh
        inventoryAdjustment: inventoryAdjustment, // Luu thong tin dieu chinh kho
        timeline: [...complaint.timeline, newAction],
      } as Partial<Complaint>);
      
      const successMessage = method === "refund" 
        ? "─É├ú x├íc nhß║¡n khiß║┐u nß║íi ─æ├║ng v├á tß║ío phiß║┐u ho├án tiß╗ün"
        : "─É├ú x├íc nhß║¡n khiß║┐u nß║íi ─æ├║ng, ghi nhß║¡n b├╣ trß║ú h├áng cho kh├ích";
      complaintNotifications.onVerified(successMessage);
    } catch (error) {
      console.error("Error creating payment/receipt:", error);
      toast.error("C├│ lß╗ùi khi tß║ío phiß║┐u chi");
    }
  }, [complaint, updateComplaint, employee, currentUser, assignedEmployee, relatedOrder]);
  // ΓÜí OPTIMIZED: Removed employees, orders arrays from deps - use memoized assignedEmployee, relatedOrder instead

  // REPLACED: handleSubmitIncorrectEvidence ΓåÆ verificationHandlers.handleSubmitIncorrectEvidence
  const handleSubmitIncorrectEvidence = verificationHandlers.handleSubmitIncorrectEvidence;

  // REPLACED: handleEndComplaint ΓåÆ complaintHandlers.handleEndComplaint
