          Kß║┐t th├║c
        </Button>
      );
    }

    // Add Reopen button for resolved/rejected complaints
    if (canReopen) {
      actions.push(
        <Button
          key="reopen"
          variant="default"
          size="sm"
          className="h-9"
          onClick={handleReopenComplaint}
        >
          Mß╗ƒ lß║íi
        </Button>
      );
    }

    return actions;
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [
    complaint,
    isVerified,
    canEdit,
    canEnd,
    canReopen,
    systemId,
    router,
  ]);

  // Set page header: replaced by ComplaintHeaderSection component
  // (see ./components/complaint-header-section.tsx)

  if (!complaint) {
    return (
      <div className="flex items-center justify-center h-96">
        <div className="text-center">
          <h3 className="text-h4 font-semibold mb-2">Kh├┤ng t├¼m thß║Ñy khiß║┐u nß║íi</h3>
