          })),
          isEdited: c.isEdited,
        }))}
        onAddComment={(content) => {
          handleAddComment(content, content, [], []);
        }}
        onUpdateComment={(commentId, content) => {
          handleEditComment(commentId, content, content);
        }}
        onDeleteComment={(commentId) => {
          handleDeleteComment(commentId);
        }}
