      />

      {/* Timeline - Full Width */}
      <ComplaintTimelineSection
        complaint={complaint}
        employees={employees}
      />

      {/* Template Dialog */}
      <TemplateDialog 
        open={templateDialogOpen}
        onOpenChange={setTemplateDialogOpen}
