      />

      {/* Image Preview Dialog */}
      <ImagePreviewDialog
        images={previewImages}
        initialIndex={previewIndex}
        open={showImagePreview}
        onOpenChange={setShowImagePreview}
        title="H├¼nh ß║únh khiß║┐u nß║íi"
      />
      </div>
    </div>
  );
}

