    if (alert.slaType === 'follow-up') {
      update.mutate({
        systemId: customer.systemId,
        lastContactDate: now,
      } as any, {
        onSuccess: () => {
          toast.success('─É├ú x├íc nhß║¡n xß╗¡ l├╜ SLA', {
            description: 'Ng├áy li├¬n hß╗ç cuß╗æi ─æ├ú ─æ╞░ß╗úc cß║¡p nhß║¡t',
          });
          
          // 3. Trigger re-evaluation after a short delay
          setTimeout(() => triggerReevaluation(), 500);
        },
      });
    } else {
      toast.success('─É├ú x├íc nhß║¡n xß╗¡ l├╜ SLA', {
        description: `SLA "${alert.slaName}" ─æ├ú ─æ╞░ß╗úc ─æ├ính dß║Ñu xß╗¡ l├╜`,
