      update.mutate({ systemId: customer.systemId, status: newStatus }, {
        onSuccess: () => {
          toast.success(`─É├ú cß║¡p nhß║¡t trß║íng th├íi kh├ích h├áng`);
        },
      });
    },
    [update]
  );

  return {
    deleteConfirmId,
    handleView,
    handleEdit,
    handleDeleteRequest,
    handleDeleteConfirm,
    handleDeleteCancel,
    handleRestore,
    handleStatusChange,
  };
}

