  const handleImportV2 = React.useCallback(async (data: Partial<Employee>[], mode: 'insert-only' | 'update-only' | 'upsert', _branchId?: string) => { let inserted = 0, updated = 0, skipped = 0, failed = 0; const errors: Array<{ row: number; message: string }> = []; for (let i = 0; i < data.length; i++) { const item = data[i]; try { const existing = item.id ? activeEmployees.find(e => e.id === item.id) : null; if (existing) { if (mode === 'insert-only') { skipped++; continue; } await update.mutateAsync({ systemId: existing.systemId, ...item } as any); updated++; } else { if (mode === 'update-only') { errors.push({ row: i + 2, message: `Kh├┤ng t├¼m thß║Ñy nh├ón vi├¬n vß╗¢i m├ú ${item.id}` }); failed++; continue; } const { systemId: _s, ...newData } = item as Partial<Employee> & { systemId?: string }; await create.mutateAsync(newData as Omit<Employee, 'systemId'>); inserted++; } } catch (e) { errors.push({ row: i + 2, message: String(e) }); failed++; } } return { success: inserted + updated, failed, inserted, updated, skipped, errors }; }, [activeEmployees, update, create]);

  const currentUser = React.useMemo(() => ({ name: 'Admin', systemId: 'USR000001' as SystemId }), []);
  const bulkActions = [{ label: "Chuyß╗ân v├áo th├╣ng r├íc", onSelect: () => setIsBulkDeleteAlertOpen(true) }, { label: "─Éang l├ám viß╗çc", onSelect: (rows: Employee[]) => { Promise.all(rows.map(e => update.mutateAsync({ systemId: e.systemId, employmentStatus: "─Éang l├ám viß╗çc" } as any))).then(() => { toast.success("─É├ú cß║¡p nhß║¡t trß║íng th├íi", { description: `${rows.length} nh├ón vi├¬n ─æ├ú chuyß╗ân sang "─Éang l├ám viß╗çc"` }); setRowSelection({}); }).catch(() => toast.error("C├│ lß╗ùi khi cß║¡p nhß║¡t trß║íng th├íi")); } }, { label: "Nghß╗ë viß╗çc", onSelect: (rows: Employee[]) => { Promise.all(rows.map(e => update.mutateAsync({ systemId: e.systemId, employmentStatus: "─É├ú nghß╗ë viß╗çc" } as any))).then(() => { toast.success("─É├ú cß║¡p nhß║¡t trß║íng th├íi", { description: `${rows.length} nh├ón vi├¬n ─æ├ú chuyß╗ân sang "─É├ú nghß╗ë viß╗çc"` }); setRowSelection({}); }).catch(() => toast.error("C├│ lß╗ùi khi cß║¡p nhß║¡t trß║íng th├íi")); } }];
  const handleRowClick = (row: Employee) => router.push(ROUTES.HRM.EMPLOYEE_VIEW.replace(':systemId', row.systemId));

  const headerActions = React.useMemo(() => [<Button key="trash" variant="outline" size="sm" className="h-9" onClick={() => router.push('/employees/trash')}><Trash2 className="mr-2 h-4 w-4" />Th├╣ng r├íc ({deletedCount})</Button>, <Button key="add" size="sm" className="h-9" onClick={() => router.push('/employees/new')}><PlusCircle className="mr-2 h-4 w-4" />Th├¬m nh├ón vi├¬n</Button>], [router, deletedCount]);
  usePageHeader({ title: 'Danh s├ích nh├ón vi├¬n', breadcrumb: [{ label: 'Trang chß╗º', href: '/', isCurrent: false }, { label: 'Nh├ón vi├¬n', href: '/employees', isCurrent: true }], actions: headerActions, showBackButton: false });

  return (
    <div className="flex flex-col w-full h-full">
      {!isMobile && <PageToolbar leftActions={<><Button variant="outline" size="sm" className="h-9" onClick={() => setIsImportV2Open(true)}><Upload className="mr-2 h-4 w-4" />Nhß║¡p Excel</Button><Button variant="outline" size="sm" className="h-9" onClick={() => setIsExportV2Open(true)}><Download className="mr-2 h-4 w-4" />Xuß║Ñt Excel</Button></>} rightActions={<DataTableColumnCustomizer columns={columns} columnVisibility={columnVisibility} setColumnVisibility={setColumnVisibility} columnOrder={columnOrder} setColumnOrder={setColumnOrder} pinnedColumns={pinnedColumns} setPinnedColumns={setPinnedColumns} onResetToDefault={resetColumnLayout} />} />}
      <PageFilters searchValue={globalFilter} onSearchChange={setGlobalFilter} searchPlaceholder="T├¼m kiß║┐m nh├ón vi├¬n (t├¬n, m├ú, email, S─ÉT)..."><Select value={branchFilter} onValueChange={setBranchFilter}><SelectTrigger className="w-full sm:w-[180px] h-9"><SelectValue placeholder="Tß║Ñt cß║ú chi nh├ính" /></SelectTrigger><SelectContent><SelectItem value="all">Tß║Ñt cß║ú chi nh├ính</SelectItem>{branches.map(b => <SelectItem key={b.systemId} value={b.systemId}>{b.name}</SelectItem>)}</SelectContent></Select>{departmentOpts.length > 0 && <DataTableFacetedFilter title="Ph├▓ng ban" options={departmentOpts} selectedValues={departmentFilter} onSelectedValuesChange={setDepartmentFilter} />}{jobTitleOpts.length > 0 && <DataTableFacetedFilter title="Chß╗⌐c danh" options={jobTitleOpts} selectedValues={jobTitleFilter} onSelectedValuesChange={setJobTitleFilter} />}<DataTableFacetedFilter title="Trß║íng th├íi" options={statusOpts} selectedValues={statusFilter} onSelectedValuesChange={setStatusFilter} /></PageFilters>
      <div className="w-full py-4"><ResponsiveDataTable columns={columns} data={paginatedData} renderMobileCard={e => <MobileEmployeeCard employee={e} onDelete={handleDelete} />} pageCount={pageCount} pagination={pagination} setPagination={setPagination} rowCount={filteredData.length} rowSelection={rowSelection} setRowSelection={setRowSelection} onBulkDelete={() => setIsBulkDeleteAlertOpen(true)} bulkActions={bulkActions} allSelectedRows={allSelectedRows} expanded={expanded} setExpanded={setExpanded} sorting={sorting} setSorting={setSorting as React.Dispatch<React.SetStateAction<{ id: string; desc: boolean }>>} columnVisibility={columnVisibility} setColumnVisibility={setColumnVisibility} columnOrder={columnOrder} setColumnOrder={setColumnOrder} pinnedColumns={pinnedColumns} setPinnedColumns={setPinnedColumns} onRowClick={handleRowClick} /></div>
      <AlertDialog open={isAlertOpen} onOpenChange={setIsAlertOpen}><AlertDialogContent><AlertDialogHeader><AlertDialogTitle>X├íc nhß║¡n x├│a nh├ón vi├¬n</AlertDialogTitle><AlertDialogDescription>Nh├ón vi├¬n sß║╜ ─æ╞░ß╗úc chuyß╗ân v├áo th├╣ng r├íc.</AlertDialogDescription></AlertDialogHeader><AlertDialogFooter><AlertDialogCancel className="h-9">Hß╗ºy</AlertDialogCancel><AlertDialogAction className="h-9" onClick={confirmDelete}>Tiß║┐p tß╗Ñc</AlertDialogAction></AlertDialogFooter></AlertDialogContent></AlertDialog>
