export function InventoryCheckFormPage() {
  const router = useRouter();
  const { systemId } = useParams<{ systemId: string }>();
  const isEditMode = !!systemId;
  
  const { data: currentCheck } = useInventoryCheck(systemId);
  const { create: createMutation, update: updateMutation, balance: balanceMutation } = useInventoryCheckMutations({
    onCreateSuccess: (check) => {
      toast.success('─É├ú tß║ío phiß║┐u kiß╗âm k├¬');
      router.push(`/inventory-checks/${check.systemId}`);
    },
    onUpdateSuccess: () => {
      toast.success('─É├ú cß║¡p nhß║¡t phiß║┐u kiß╗âm k├¬');
    },
    onBalanceSuccess: (check) => {
      toast.success('─É├ú c├ón bß║▒ng phiß║┐u kiß╗âm k├¬');
      router.push(`/inventory-checks/${check.systemId}`);
    },
    onError: (err) => toast.error(err.message)
  });
  const { data: branches } = useAllBranches();
  const { data: allProducts } = useAllProducts();
  const { findById: findProductById } = useProductFinder();
  const { findById: findProductTypeById } = useProductTypeFinder();
  const { employee: authEmployee } = useAuth();
  const currentUserSystemId = authEmployee?.systemId ?? 'SYSTEM';
  
  const [previewImage, setPreviewImage] = React.useState<{ url: string; title: string } | null>(null);

  const getProductTypeName = React.useCallback((productTypeSystemId: string) => {
    const productType = findProductTypeById(productTypeSystemId as SystemId);
    return productType?.name || 'H├áng h├│a';
  }, [findProductTypeById]);
  
  // Get current user name
  const [currentUserName, setCurrentUserName] = React.useState(() =>
    authEmployee?.fullName || authEmployee?.id || ''
  );

  // Load current user name
  React.useEffect(() => {
    if (isEditMode) return;
    if (authEmployee) {
      setCurrentUserName(authEmployee.fullName || authEmployee.id || '');
      return;
    }
    setCurrentUserName('Hß╗ç thß╗æng');
  }, [authEmployee, isEditMode]);

  // Form state
  const [branchSystemId, setBranchSystemId] = React.useState('');
  const [customId, setCustomId] = React.useState('');
  const [note, setNote] = React.useState('');
  const [tags, setTags] = React.useState<string[]>([]);
  const [tagInput, setTagInput] = React.useState('');
  const [items, setItems] = React.useState<InventoryCheckItem[]>([]);
  const [activeTab, setActiveTab] = React.useState('all');
  const [subtasks, setSubtasks] = React.useState<Subtask[]>([]);
  
  // Dialog states
  const [showProductSelector, setShowProductSelector] = React.useState(false);
  const [showBalanceConfirm, setShowBalanceConfirm] = React.useState(false);
  const [isBalancing, setIsBalancing] = React.useState(false);

  // Load existing data in edit mode
  React.useEffect(() => {
    if (isEditMode && currentCheck) {
      // Load all fields from existing check
      setBranchSystemId(currentCheck.branchSystemId || '');
      setCustomId(currentCheck.id);
      setNote(currentCheck.note || '');
      setItems(currentCheck.items || []);
      
      // Load employee name for edit mode (ng╞░ß╗¥i tß║ío ban ─æß║ºu)
      if (currentCheck.createdBy) {
        import('../employees/store').then(({ useEmployeeStore }) => {
          const employeeList = useEmployeeStore.getState().data;
          const creator = employeeList.find(emp => emp.systemId === currentCheck.createdBy);
          if (creator) {
            setCurrentUserName(creator.fullName || creator.id);
          }
        }).catch(() => {
          // Ignore error, just won't show employee name
        });
      }
    } else if (!isEditMode) {
      // Auto-select default branch for new form
      const defaultBranch = branches.find(b => b.isDefault);
      if (defaultBranch) {
        setBranchSystemId(defaultBranch.systemId);
      }
    }
  }, [isEditMode, currentCheck, router, branches]);

  // Get branch name
  const selectedBranch = React.useMemo(() => 
    branches.find(b => b.systemId === branchSystemId),
    [branches, branchSystemId]
  );

  // Get system quantity from product inventory
  const getSystemQuantity = (productSystemId: string): number => {
    const product = allProducts.find(p => p.systemId === productSystemId);
    if (!product) return 0;
    
    if (branchSystemId) {
      // If branch selected, get branch-specific inventory using systemId
      return product.inventoryByBranch?.[branchSystemId] || 0;
    }
    
    // If no branch selected, get TOTAL inventory across all branches
    const inventoryByBranch = product.inventoryByBranch || {};
    return Object.values(inventoryByBranch).reduce((sum, qty) => sum + qty, 0);
  };

  // Add products from selector
  const handleAddProducts = (products: Product[]) => {
    const newItems: InventoryCheckItem[] = products.map(p => ({
      productSystemId: p.systemId,
      productId: p.id,
      productName: p.name,
      unit: p.unit || 'C├íi',
      systemQuantity: getSystemQuantity(p.systemId),
      actualQuantity: 0,
      difference: 0 - getSystemQuantity(p.systemId),
      reason: 'other', // Γ£à Default reason
    }));

    setItems(prev => [...prev, ...newItems]);
    toast.success(`─É├ú th├¬m ${products.length} sß║ún phß║⌐m`);
  };

  // Add single product from search
  const handleAddProduct = (product: Product) => {
    // Check if already added
    if (items.some(item => item.productSystemId === product.systemId)) {
      toast.error('Sß║ún phß║⌐m ─æ├ú ─æ╞░ß╗úc th├¬m v├áo danh s├ích');
      return;
    }

    const newItem: InventoryCheckItem = {
      productSystemId: product.systemId,
      productId: product.id,
      productName: product.name,
      unit: product.unit || 'C├íi',
      systemQuantity: getSystemQuantity(product.systemId),
      actualQuantity: 0,
      difference: 0 - getSystemQuantity(product.systemId),
      reason: 'other', // Γ£à Default reason
    };

    setItems(prev => [...prev, newItem]);
    toast.success(`─É├ú th├¬m ${product.name}`);
  };

  // Update actual quantity
  const handleUpdateActualQty = (index: number, value: string) => {
    const actualQty = parseInt(value) || 0;
    setItems(prev => {
      const updated = [...prev];
      const item = updated[index];
      item.actualQuantity = actualQty;
      item.difference = actualQty - item.systemQuantity;
      return updated;
    });
  };

  // Update reason
  const handleUpdateReason = (index: number, reason: DifferenceReason) => {
    setItems(prev => {
      const updated = [...prev];
      updated[index].reason = reason;
      return updated;
    });
  };

  // Update note
  const handleUpdateItemNote = (index: number, note: string) => {
    setItems(prev => {
      const updated = [...prev];
      updated[index].note = note;
      return updated;
    });
  };

  // Remove item
  const handleRemoveItem = (index: number) => {
    setItems(prev => prev.filter((_, i) => i !== index));
  };

  // Filter items by tab
  const filteredItems = React.useMemo(() => {
    // In edit mode, always show all items
    if (isEditMode) return items;
    
    switch (activeTab) {
      case 'unchecked':
        return items.filter(item => item.actualQuantity === 0);
      case 'matched':
        return items.filter(item => item.difference === 0);
      case 'different':
        return items.filter(item => item.difference !== 0);
      default:
        return items;
    }
  }, [items, activeTab, isEditMode]);

  // Add tag
  const handleAddTag = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter' && tagInput.trim()) {
      e.preventDefault();
      if (!tags.includes(tagInput.trim())) {
        setTags([...tags, tagInput.trim()]);
      }
      setTagInput('');
    }
  };

  // Remove tag
  const handleRemoveTag = (tag: string) => {
    setTags(tags.filter(t => t !== tag));
  };

  // Validation function
  const validateForm = React.useCallback(() => {
    const errors: string[] = [];
    
    if (!branchSystemId) {
      errors.push('Vui l├▓ng chß╗ìn chi nh├ính kiß╗âm');
    }
    
    if (items.length === 0) {
      errors.push('Vui l├▓ng th├¬m ├¡t nhß║Ñt 1 sß║ún phß║⌐m');
    }
    
    // Check items with difference but no reason
    const missingReason = items.filter(
      item => item.difference !== 0 && !item.reason
    );
    if (missingReason.length > 0) {
      errors.push(`C├│ ${missingReason.length} sß║ún phß║⌐m lß╗çch ch╞░a chß╗ìn l├╜ do`);
    }
    
    // Warning for large differences
    const largeDiff = items.filter(item => Math.abs(item.difference) > 100);
    if (largeDiff.length > 0) {
      toast.warning(`Cß║únh b├ío: C├│ ${largeDiff.length} sß║ún phß║⌐m lß╗çch qu├í 100 ─æ╞ín vß╗ï`, {
        description: largeDiff.slice(0, 3).map(item => 
          `${item.productName}: ${item.difference > 0 ? '+' : ''}${item.difference}`
        ).join(', ') + (largeDiff.length > 3 ? '...' : '')
      });
    }
    
    if (errors.length > 0) {
      toast.error('Vui l├▓ng kiß╗âm tra lß║íi', {
        description: errors.join('\n')
      });
      return false;
    }
    
    return true;
  }, [branchSystemId, items]);

  // Save draft
  const handleSaveDraft = React.useCallback(() => {
    
    if (!validateForm()) {
      return;
    }

    if (isEditMode && systemId) {
      if (currentCheck) {
        const updated: InventoryCheck = {
          ...currentCheck,
          branchSystemId: asSystemId(branchSystemId),
          branchName: selectedBranch?.name || '',
          note,
          items,
        };
        updateMutation.mutate({ systemId: asSystemId(systemId), data: updated as any });
        toast.success('─É├ú cß║¡p nhß║¡t phiß║┐u kiß╗âm h├áng');
      }
    } else {
      const data: Omit<InventoryCheck, 'systemId'> = {
        id: asBusinessId(customId || ''),
        branchSystemId: asSystemId(branchSystemId),
        branchName: selectedBranch?.name || '',
        status: 'draft',
        createdBy: asSystemId(currentUserSystemId || 'SYSTEM'),
        createdAt: new Date().toISOString(),
        note,
        items,
      };
      createMutation.mutate(data);
    }
  }, [isEditMode, systemId, currentCheck, selectedBranch, note, updateMutation, customId, currentUserSystemId, createMutation, router, validateForm, branchSystemId, items]);

  // Balance
  const handleBalance = React.useCallback(() => {
    
    if (!validateForm()) {
      return;
    }

    setShowBalanceConfirm(true);
  }, [validateForm]);

  const confirmBalance = async () => {
    setIsBalancing(true);
    
    let checkSystemId: string;
    
    if (isEditMode && systemId) {
      if (currentCheck) {
        const updated: Partial<InventoryCheck> = {
          branchSystemId: asSystemId(branchSystemId),
          branchName: selectedBranch?.name || '',
          note,
          items,
        };
        updateMutation.mutate({ systemId, data: updated });
        checkSystemId = systemId;
      } else {
        setIsBalancing(false);
        setShowBalanceConfirm(false);
        toast.error('Kh├┤ng t├¼m thß║Ñy phiß║┐u kiß╗âm h├áng');
        return;
      }
    } else {
      const data: Omit<InventoryCheck, 'systemId'> = {
        id: asBusinessId(customId || ''),
        branchSystemId: asSystemId(branchSystemId),
        branchName: selectedBranch?.name || '',
        status: 'draft',
        createdBy: asSystemId(currentUserSystemId || 'SYSTEM'),
        createdAt: new Date().toISOString(),
        note,
        items,
      };
      createMutation.mutate(data, {
        onSuccess: (newCheck) => {
          checkSystemId = newCheck.systemId;
          balanceMutation.mutate(checkSystemId, {
            onSettled: () => {
              setIsBalancing(false);
              setShowBalanceConfirm(false);
            }
          });
        },
        onError: () => {
          setIsBalancing(false);
          setShowBalanceConfirm(false);
        }
      });
      return;
    }

    balanceMutation.mutate(checkSystemId, {
      onSettled: () => {
        setIsBalancing(false);
        setShowBalanceConfirm(false);
      }
    });
  };

  // Store latest callbacks in refs to avoid stale closure
  const handleSaveDraftRef = React.useRef(handleSaveDraft);
  const handleBalanceRef = React.useRef(handleBalance);
  
  React.useEffect(() => {
    handleSaveDraftRef.current = handleSaveDraft;
    handleBalanceRef.current = handleBalance;
  }, [handleSaveDraft, handleBalance]);

  // Header actions - kh├íc nhau giß╗»a th├¬m v├á sß╗¡a
  const actions = React.useMemo(() => {
    if (isEditMode) {
      // Actions cho chß║┐ ─æß╗Ö sß╗¡a
      return [
        <Button key="cancel" variant="outline" onClick={() => router.push('/inventory-checks')} className="h-9">
          Hß╗ºy
        </Button>,
        <Button key="save" onClick={() => handleSaveDraftRef.current()} className="h-9">
          L╞░u thay ─æß╗òi
        </Button>
      ];
    } else {
      // Actions cho chß║┐ ─æß╗Ö th├¬m mß╗¢i
      return [
        <Button key="cancel" variant="outline" onClick={() => router.push('/inventory-checks')} className="h-9">
          Hß╗ºy
        </Button>,
        <Button key="save" variant="outline" onClick={() => handleSaveDraftRef.current()} className="h-9">
          Tß║ío phiß║┐u kiß╗âm
        </Button>,
        <Button key="balance" onClick={() => handleBalanceRef.current()} className="h-9">
          C├ón bß║▒ng kho
        </Button>
      ];
    }
  }, [isEditMode, router]);

  // Breadcrumb
  const breadcrumb = React.useMemo(() => [
    { label: 'Trang chß╗º', href: '/', isCurrent: false },
    { label: 'Kiß╗âm h├áng', href: '/inventory-checks', isCurrent: false },
    { label: isEditMode ? 'Chß╗ënh sß╗¡a' : 'Th├¬m mß╗¢i', href: '', isCurrent: true }
  ], [isEditMode]);

  // Custom title cho edit mode
  const pageTitle = React.useMemo(() => {
    if (isEditMode && currentCheck) {
      return `Chß╗ënh sß╗¡a ${currentCheck.id}`;
    }
    return undefined; // D├╣ng title auto tß╗½ route
  }, [isEditMode, currentCheck]);

  usePageHeader({ 
    title: pageTitle,
    actions,
    breadcrumb
  });

  // Count stats
  const stats = React.useMemo(() => {
    const unchecked = items.filter(item => item.actualQuantity === 0).length;
    const matched = items.filter(item => item.difference === 0).length;
    const different = items.filter(item => item.difference !== 0).length;
    const checked = items.filter(item => item.actualQuantity > 0).length;
    const progress = items.length > 0 ? Math.round((checked / items.length) * 100) : 0;
    return { unchecked, matched, different, checked, progress };
  }, [items]);

  return (
    <div className="space-y-4">
      {/* Progress Bar - Only in create mode */}
      {!isEditMode && items.length > 0 && (
        <Card>
          <CardContent className="pt-6">
            <div className="space-y-2">
              <div className="flex justify-between text-body-sm">
                <span className="font-medium">Tiß║┐n ─æß╗Ö kiß╗âm h├áng</span>
                <span className="font-bold text-primary">{stats.progress}%</span>
              </div>
              <div className="h-3 bg-muted rounded-full overflow-hidden">
                <div 
                  className="h-full bg-primary transition-all duration-300 ease-in-out"
                  style={{ width: `${stats.progress}%` }}
                />
              </div>
              <div className="flex justify-between text-body-xs text-muted-foreground">
                <span>─É├ú kiß╗âm: {stats.checked}/{items.length} sß║ún phß║⌐m</span>
                <span>Khß╗¢p: {stats.matched} ΓÇó Lß╗çch: {stats.different}</span>
              </div>
            </div>
          </CardContent>
        </Card>
      )}

      {/* Info Cards */}
      <div className="grid grid-cols-1 lg:grid-cols-10 gap-4">
        {/* Th├┤ng tin phiß║┐u */}
        <Card className="lg:col-span-4">
          <CardHeader>
            <CardTitle>Th├┤ng tin phiß║┐u</CardTitle>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              {/* M├ú phiß║┐u - Always show, disabled in edit mode */}
              <div className="space-y-2">
                <Label htmlFor="customId">M├ú phiß║┐u {!isEditMode && '(t├╣y chß╗ìn)'}</Label>
                <Input
                  id="customId"
                  placeholder={isEditMode ? '' : '─Éß╗â trß╗æng ─æß╗â tß╗▒ ─æß╗Öng tß║ío'}
                  value={customId}
                  onChange={(e) => setCustomId(e.target.value)}
                  disabled={isEditMode}
                  className={isEditMode ? 'bg-muted h-9' : 'h-9'}
                />
              </div>

              <div className="space-y-2">
                <Label htmlFor="branch">Chi nh├ính kiß╗âm *</Label>
                <Select 
                  value={branchSystemId} 
                  onValueChange={(value) => {
                    setBranchSystemId(value);
                  }}
                  disabled={isEditMode}
                >
                  <SelectTrigger id="branch" className={isEditMode ? 'bg-muted h-9' : 'h-9'}>
                    <SelectValue placeholder="Chß╗ìn chi nh├ính" />
                  </SelectTrigger>
                  <SelectContent>
                    {branches.map(branch => (
                      <SelectItem key={branch.systemId} value={branch.systemId}>
                        {branch.name}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              <div className="space-y-2 sm:col-span-2">
                <Label htmlFor="employee">Nh├ón vi├¬n kiß╗âm</Label>
                <Input
                  id="employee"
                  disabled
                  value={currentUserName || '─Éang tß║úi...'}
                  className="bg-muted h-9"
                />
              </div>
            </div>
          </CardContent>
        </Card>

        {/* Th├┤ng tin bß╗ò sung */}
        <Card className="lg:col-span-3">
          <CardHeader>
            <CardTitle>Th├┤ng tin bß╗ò sung</CardTitle>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="space-y-2">
              <Label htmlFor="note">Ghi ch├║</Label>
              <Textarea
                id="note"
                placeholder="VD: Kiß╗âm h├áng ng├áy 25/07/2022"
                value={note}
                onChange={(e) => setNote(e.target.value)}
                rows={3}
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="tags">Tags</Label>
              <Input
                id="tags"
                placeholder="Nhß║¡p k├╜ tß╗▒ v├á ß║Ñn Enter"
                value={tagInput}
                onChange={(e) => setTagInput(e.target.value)}
                onKeyDown={handleAddTag}
                className="h-9"
              />
              {tags.length > 0 && (
                <div className="flex flex-wrap gap-2 mt-2">
                  {tags.map(tag => (
                    <Badge key={tag} variant="secondary" className="cursor-pointer" onClick={() => handleRemoveTag(tag)}>
                      {tag} ├ù
                    </Badge>
                  ))}
                </div>
              )}
            </div>
          </CardContent>
        </Card>

        {/* Quy tr├¼nh xß╗¡ l├╜ */}
        <div className="lg:col-span-3">
          <InventoryCheckWorkflowCard
            subtasks={subtasks}
            onSubtasksChange={setSubtasks}
            readonly={true}
          />
        </div>
      </div>

      {/* Products Table */}
      <Card>
        <CardHeader>
          <CardTitle>Sß║ún phß║⌐m kiß╗âm h├áng</CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          {/* Search and Add Products - Only in create mode */}
          {!isEditMode && (
            <div className="flex gap-2">
              <div className="flex-1">
                <ProductSearchCombobox
                  onSelect={handleAddProduct}
                  placeholder="Th├¬m sß║ún phß║⌐m (F3)"
                  excludeProductIds={items.map(i => i.productSystemId)}
                  branchSystemId={branchSystemId}
                  showStock={true}
                  showPrice={false}
                />
              </div>
              <Button 
                onClick={() => setShowProductSelector(true)}
                variant="outline"
                className="h-9"
              >
                Chß╗ìn nhiß╗üu
              </Button>
            </div>
          )}

          {/* Edit mode message */}
          {isEditMode && (
            <div className="bg-muted/50 border rounded-lg p-4 text-body-sm text-muted-foreground">
              ß╗₧ chß║┐ ─æß╗Ö sß╗¡a, bß║ín chß╗ë c├│ thß╗â chß╗ënh sß╗¡a <strong>Ghi ch├║</strong> v├á <strong>Tags</strong>. Kh├┤ng thß╗â thay ─æß╗òi sß║ún phß║⌐m hoß║╖c sß╗æ l╞░ß╗úng.
            </div>
          )}

          {items.length === 0 ? (
            <div className="text-center py-12 text-muted-foreground border rounded-lg">
              <Package className="h-12 w-12 mx-auto mb-3 opacity-50" />
              <p>Ch╞░a c├│ sß║ún phß║⌐m n├áo</p>
              <p className="text-body-sm mt-1">T├¼m kiß║┐m hoß║╖c chß╗ìn sß║ún phß║⌐m ─æß╗â th├¬m</p>
            </div>
          ) : (
            <>
              {/* Tabs for filtering - Only in create mode */}
              {!isEditMode && (
                <div className="flex gap-2 mb-4 border-b">
                  <button
