                        <th className="px-3 py-2 text-right text-body-sm font-medium">Tß╗ôn thß╗▒c tß║┐</th>
                        <th className="px-3 py-2 text-right text-body-sm font-medium">Lß╗çch</th>
                        <th className="px-3 py-2 text-left text-body-sm font-medium">L├╜ do</th>
                        <th className="px-3 py-2 text-left text-body-sm font-medium">Ghi ch├║</th>
