      <div className="flex flex-col gap-2 md:flex-row md:items-center"><Input placeholder="T├¼m kiß║┐m theo m├ú, chi nh├ính, ng╞░ß╗¥i tß║ío..." value={searchQuery} onChange={e => setSearchQuery(e.target.value)} className="h-9 max-w-sm" /><DataTableFacetedFilter title="Trß║íng th├íi" selectedValues={new Set(statusFilter === 'all' ? [] : [statusFilter])} onSelectedValuesChange={v => setStatusFilter(v.size === 0 ? 'all' : Array.from(v)[0] as string)} options={[{ label: 'Nh├íp', value: 'draft' }, { label: '─É├ú c├ón bß║▒ng', value: 'balanced' }, { label: '─É├ú hß╗ºy', value: 'cancelled' }]} /></div>
