        if (!customer) return 0;

        const transactions: Array<{ date: string; change: number }> = [];

        deliveredCustomerOrders.forEach(o => {
            // Γ£à Use grandTotal (kh├┤ng trß╗½ paidAmount) v├¼ phiß║┐u thu ─æ├ú ─æ╞░ß╗úc t├¡nh ri├¬ng
