            const defaultTax = getDefaultSale();
            const taxRate = defaultTax?.rate || 0;
            const newItem = {
                id: `temp_${Date.now()}_${Math.random().toString(36).substr(2, 9)}_${idx}`,
                systemId: '',
                productSystemId: product.systemId,
                productId: product.id,
