            toast.info('─Éang tß║ío ─æ╞ín tr├¬n GHTK...', { duration: 2000 });
            const result = await ghtkService.createOrder(ghtkParams);
            
            if (result.success && result.order) {
                toast.success('─É├ú tß║ío ─æ╞ín GHTK th├ánh c├┤ng', { 
