                // ========================================
                // Hß╗ù trß╗ú nhiß╗üu ─æ╞ín vß╗ï: GHTK, GHN, J&T, VTP, SPX, v.v.
                // Logic tß╗òng qu├ít cho tß║Ñt cß║ú ─æ╞ín vß╗ï vß║¡n chuyß╗ân
                
                let partnerTrackingCode: string | null = null;
                const partnerId = partner?.id;
                
                // Kiß╗âm tra nß║┐u ─æ╞ín vß╗ï vß║¡n chuyß╗ân c├│ API integration
                if (partnerId && isSupportedShippingPartner(partnerId)) {
                    
                    // Γ£à Get preview params from window (stored by shipping-integration)
                    // Mß╗ùi ─æ╞ín vß╗ï vß║¡n chuyß╗ân sß║╜ c├│ params ri├¬ng
                    const previewParamsKey = getPreviewParamsKey(partnerId);
                    const configParamsKey = getConfigParamsKey(partnerId);
                    const partnerParams = (window as unknown as Record<string, unknown>)[previewParamsKey] || data.configuration?.[configParamsKey];
                    
                    if (!partnerParams) {
                        // ΓÜá∩╕Å CRITICAL: Kh├┤ng c├│ params = ch╞░a chß╗ìn ─æß║ºy ─æß╗º th├┤ng tin vß║¡n chuyß╗ân
                        console.error(`Γ¥î Missing ${partnerId} preview params (key: ${previewParamsKey}). Cannot create order.`);
                        toast.error(`Thiß║┐u th├┤ng tin vß║¡n chuyß╗ân ${partner.name}`, { 
                            description: `Vui l├▓ng cß║Ñu h├¼nh ─æß║ºy ─æß╗º th├┤ng tin vß║¡n chuyß╗ân (─æß╗ïa chß╗ë, dß╗ïch vß╗Ñ, ph├¡) trong tab "─Éß║⌐y qua h├úng vß║¡n chuyß╗ân" tr╞░ß╗¢c khi tß║ío ─æ╞ín.`,
                            duration: 5000
                        });
                        return; // Γ¥î STOP: Kh├┤ng cho tß║ío ─æ╞ín
                    }
                    
                    
                    try {
                        // Gß╗ìi API t╞░╞íng ß╗⌐ng vß╗¢i tß╗½ng ─æ╞ín vß╗ï
                        switch (partnerId) {
                            case 'GHTK':
                                partnerTrackingCode = await createGHTKOrder(partnerParams as GHTKCreateOrderParams);
                                break;
                            
                            case 'GHN':
                                // TODO: Implement GHN API call
                                // partnerTrackingCode = await createGHNOrder(partnerParams);
                                toast.info('GHN API ─æang ─æ╞░ß╗úc ph├ít triß╗ân', {
                                    description: 'Chß╗⌐c n─âng tß║ío ─æ╞ín tß╗▒ ─æß╗Öng vß╗¢i GHN sß║╜ sß╗¢m ─æ╞░ß╗úc cß║¡p nhß║¡t'
                                });
                                break;
                            
                            case 'JNT':
                                // TODO: Implement J&T API call
                                // partnerTrackingCode = await createJNTOrder(partnerParams);
                                toast.info('J&T Express API ─æang ─æ╞░ß╗úc ph├ít triß╗ân', {
                                    description: 'Chß╗⌐c n─âng tß║ío ─æ╞ín tß╗▒ ─æß╗Öng vß╗¢i J&T sß║╜ sß╗¢m ─æ╞░ß╗úc cß║¡p nhß║¡t'
                                });
                                break;
                            
                            case 'VTP':
                                // TODO: Implement ViettelPost API call
                                // partnerTrackingCode = await createVTPOrder(partnerParams);
                                toast.info('ViettelPost API ─æang ─æ╞░ß╗úc ph├ít triß╗ân', {
                                    description: 'Chß╗⌐c n─âng tß║ío ─æ╞ín tß╗▒ ─æß╗Öng vß╗¢i ViettelPost sß║╜ sß╗¢m ─æ╞░ß╗úc cß║¡p nhß║¡t'
                                });
                                break;
                            
                            case 'SPX':
                                // TODO: Implement Shopee Express API call
                                // partnerTrackingCode = await createSPXOrder(partnerParams);
                                toast.info('Shopee Express API ─æang ─æ╞░ß╗úc ph├ít triß╗ân', {
                                    description: 'Chß╗⌐c n─âng tß║ío ─æ╞ín tß╗▒ ─æß╗Öng vß╗¢i Shopee Express sß║╜ sß╗¢m ─æ╞░ß╗úc cß║¡p nhß║¡t'
                                });
                                break;
                            
                            default:
                                // ─É╞ín vß╗ï vß║¡n chuyß╗ân mß╗¢i ch╞░a implement
                                toast.warning(`${partner.name} ch╞░a ─æ╞░ß╗úc t├¡ch hß╗úp`, {
                                    description: 'Vui l├▓ng tß║ío vß║¡n ─æ╞ín thß╗º c├┤ng tr├¬n trang cß╗ºa ─æß╗æi t├íc'
                                });
                        }
                        
                        
                        if (!partnerTrackingCode) {
                            throw new Error(`${partner.name} API kh├┤ng trß║ú vß╗ü m├ú vß║¡n ─æ╞ín`);
                        }
                    } catch (error) {
                        const errorMessage = error instanceof Error ? error.message : 'Lß╗ùi kh├┤ng x├íc ─æß╗ïnh';
                        console.error(`Γ¥î ${partnerId} API Error:`, error);
                        
                        // Hß╗Åi user c├│ muß╗æn tiß║┐p tß╗Ñc kh├┤ng
                        const shouldContinue = confirm(
                            `Kh├┤ng tß║ío ─æ╞░ß╗úc ─æ╞ín tr├¬n ${partner.name}:\n${errorMessage}\n\n` +
                            `Bß║ín c├│ muß╗æn l╞░u ─æ╞ín h├áng vß╗¢i m├ú vß║¡n ─æ╞ín tß║ím thß╗¥i kh├┤ng?\n` +
                            `(Bß║ín c├│ thß╗â tß║ío vß║¡n ─æ╞ín ${partner.name} sau trong trang chi tiß║┐t ─æ╞ín h├áng)`
                        );
                        if (!shouldContinue) {
                            return; // Γ¥î STOP: User kh├┤ng muß╗æn tiß║┐p tß╗Ñc
                        }
                        // User chß╗ìn tiß║┐p tß╗Ñc ΓåÆ sß║╜ d├╣ng tracking code tß║ím
                    }
                }
                
                // Γ£à Only create new packaging if no existing packagings
                if (!hasExistingPackagings) {
                    const _allTrackingCodes = allOrders.flatMap(o => o.packagings).map(p => ({ id: p.trackingCode })).filter(p => p.id);
                    packagings.push({
                        systemId: asSystemId(getNextPackagingSystemId()), // Γ£à Use proper format PACKAGE000001
                        id: asBusinessId(''), // Γ£à Empty - auto-generate
                        requestDate: now, confirmDate: now,
                        requestingEmployeeId: salesperson.systemId, requestingEmployeeName: salesperson.fullName,
                        confirmingEmployeeId: salesperson.systemId, confirmingEmployeeName: salesperson.fullName,
                        assignedEmployeeId: packerSystemId,
                        assignedEmployeeName: packer?.fullName,
                        status: '─É├ú ─æ├│ng g├│i',
                        deliveryStatus: 'Chß╗¥ lß║Ñy h├áng',
                        printStatus: 'Ch╞░a in',
                        deliveryMethod: 'Dß╗ïch vß╗Ñ giao h├áng',
                        carrier: partner?.name, service: service?.name,
                        trackingCode: partnerTrackingCode || data.trackingCode || "", // Γ£à Empty tracking code
                        shippingFeeToPartner: data.shippingFee,
                        codAmount: data.codAmount, 
                        payer: data.payer, 
                        noteToShipper: sanitizeString(data.shippingNote || ''),
                        weight: data.weight, dimensions: (data.length && data.width && data.height) ? `${data.length}x${data.width}x${data.height}` : undefined,
                    });
                }
                break;
            }
            
            case 'deliver-later':
            default:
                // ├üp dß╗Ñng submitAction: draft = "─Éß║╖t h├áng", approve = "─Éang giao dß╗ïch"
                // Γ£à Preserve existing status when editing
                if (hasExistingPackagings) {
                    finalMainStatus = order!.status;
                    finalDeliveryStatus = order!.deliveryStatus;
                } else {
                    finalMainStatus = effectiveSubmitAction === 'approve' ? '─Éang giao dß╗ïch' : '─Éß║╖t h├áng';
                    finalDeliveryStatus = 'Chß╗¥ ─æ├│ng g├│i';
                }
                break;
        }

        const resolvedShippingAddress = data.shippingAddress || customer.addresses?.find((a) => a.isDefaultShipping) || null;
        const resolvedBillingAddress = data.billingAddress || customer.addresses?.find((a) => a.isDefaultBilling) || null;
        const shippingAddressSnapshot = cloneOrderAddress(resolvedShippingAddress);
        const billingAddressSnapshot = cloneOrderAddress(resolvedBillingAddress);

        const initialPayments = isEditing && order ? order.payments : [];
        const initialPaidAmount = isEditing && order ? order.paidAmount : 0;

        const finalOrderData = {
            id: finalOrderId,
            customerSystemId: customer.systemId, 
            customerName: sanitizeString(customer.name),
            
            // Γ£à Save selected addresses from form (snapshot to prevent future mutations)
            shippingAddress: shippingAddressSnapshot,
            billingAddress: billingAddressSnapshot,
            
            branchSystemId: branch.systemId,
            branchName: branch.name,
            salespersonSystemId: salesperson.systemId, 
            salesperson: salesperson.fullName,
            assignedPackerSystemId: packerSystemId,
            assignedPackerName: packer?.fullName,
            orderDate: toISODateTime(data.orderDate),
            expectedPaymentMethod: sanitizedExpectedPaymentMethod || undefined,
            lineItems: data.lineItems.map((li, index) => ({
                productSystemId: asSystemId(li.productSystemId), 
                productId: asBusinessId((li.productId || '').trim().toUpperCase() || `SKU${String(index + 1).padStart(6, '0')}`), 
                productName: sanitizeString(li.productName),
                quantity: Number(li.quantity), 
                unitPrice: Number(li.unitPrice), 
                discount: Number(li.discount), 
                discountType: li.discountType,
                tax: Number(li.tax) || 0,
                taxId: li.taxId || '',
                note: li.note?.trim() || undefined,
            })),
            subtotal: data.subtotal, 
            shippingFee: data.shippingFee, 
            tax: data.tax, 
            grandTotal: data.grandTotal,
            paidAmount: initialPaidAmount,
            payments: initialPayments,
            notes: sanitizedNotes, 
            tags: sanitizedTags,
            source: sanitizedSource,
            status: finalMainStatus,
            paymentStatus: paymentStatus,
            deliveryStatus: finalDeliveryStatus,
            printStatus: 'Ch╞░a in' as OrderPrintStatus,
            stockOutStatus: 'Ch╞░a xuß║Ñt kho' as OrderStockOutStatus,
            returnStatus: 'Ch╞░a trß║ú h├áng' as OrderReturnStatus,
            deliveryMethod: (data.deliveryMethod === 'pickup' ? 'Nhß║¡n tß║íi cß╗¡a h├áng' : 'Dß╗ïch vß╗Ñ giao h├áng') as OrderDeliveryMethod,
            codAmount: data.codAmount || 0,
            packagings: packagings,
            completedDate: finalCompletedDate,
            createdAt: toISODateTime(new Date()), // Thß╗¥i ─æiß╗âm tß║ío ─æ╞ín
        };

        if (isEditing && order) {
            const updatedOrder: Order = { ...order, ...finalOrderData };
            update.mutate({ id: order.systemId, data: updatedOrder }, {
                onSuccess: () => router.push(`/orders/${order.systemId}`)
            });
        } else {
            add.mutate(finalOrderData as Omit<Order, 'systemId'>, {
                onSuccess: (newItem) => {
                    if (!isEditing && formPayments.length > 0) {
                        formPayments.forEach(payment => {
                            const amount = Number(payment.amount) || 0;
                            if (amount <= 0) return;
                            addOrderPayment.mutate({ 
                                systemId: newItem.systemId, 
                                amount, 
                                paymentMethodId: payment.method 
                            });
                        });
                    }

                    // Γ£à C├┤ng nß╗ú sß║╜ ─æ╞░ß╗úc tß║ío khi ─æ╞ín h├áng giao th├ánh c├┤ng (completeDelivery)
                    // KH├öNG tß║ío c├┤ng nß╗ú ngay khi tß║ío ─æ╞ín

                    router.push(`/orders/${newItem.systemId}`);
                }
            });
        }
    };

    // Page header actions
    const actions = [
        <Button 
            key="exit" 
            type="button" 
            variant="outline" 
            onClick={() => router.push('/orders')} 
            size="sm" 
            className="h-9"
        >
            Tho├ít
        </Button>,
        <Button 
            key="save" 
            type="submit" 
            form="order-form"
            variant="outline"
            disabled={isFullyReadOnly}
            onClick={(_e) => {
                setSubmitAction('draft');
                // Don't preventDefault - let form submit naturally
            }}
            size="sm" 
            className="h-9"
        >
            {isEditing ? 'L╞░u thay ─æß╗òi' : 'Tß║ío ─æ╞ín h├áng (F1)'}
        </Button>,
        ...(!isEditing ? [
            <Button 
                key="save-approve" 
                type="submit"
                form="order-form"
                disabled={isFullyReadOnly}
                onClick={(_e) => {
                    setSubmitAction('approve');
                    // Don't preventDefault - let form submit naturally
                }}
                size="sm" 
                className="h-9"
            >
                Tß║ío ─æ╞ín v├á duyß╗çt
            </Button>
        ] : [])
    ];

    usePageHeader({ 
        actions,
        breadcrumb: order ? [
            { label: 'Trang chß╗º', href: '/', isCurrent: false },
            { label: '─É╞ín h├áng', href: '/orders', isCurrent: false },
            { label: order.id, href: `/orders/${order.systemId}`, isCurrent: false },
            { label: isEditing ? 'Chß╗ënh sß╗¡a' : 'Chi tiß║┐t', href: '', isCurrent: true }
        ] : [
            { label: 'Trang chß╗º', href: '/', isCurrent: false },
            { label: '─É╞ín h├áng', href: '/orders', isCurrent: false },
            { label: 'Tß║ío mß╗¢i', href: '', isCurrent: true }
        ],
        // Γ£à FIX: Pass order context so title shows businessId (DH000007) instead of systemId (ORDER000002)
        context: order ? { id: order.id } : undefined
    });
    
    // Loading state for edit mode
    if (isEditing && isOrderLoading) {
        return (
            <div className="space-y-4">
                <div className="animate-pulse bg-muted h-32 rounded-lg" />
                <div className="animate-pulse bg-muted h-64 rounded-lg" />
                <div className="animate-pulse bg-muted h-48 rounded-lg" />
            </div>
        );
    }
    
    return (
        <FormProvider {...form}>
            <form id="order-form" onSubmit={handleSubmit(processSubmit)} className="h-full flex flex-col">
                <OrderCalculations />
                <ScrollArea className="flex-grow">
                    <div className="pr-4 space-y-4">
                        {/* Γ£à Th├┤ng b├ío khi chß╗ë sß╗¡a metadata */}
                        {isMetadataOnlyMode && (
                            <Card className="border-amber-200 bg-amber-50">
                                <CardContent className="pt-6">
                                    <p className="text-body-sm text-amber-800">
                                        <strong>L╞░u ├╜:</strong> ─É╞ín h├áng ─æ├ú ─æ├│ng g├│i/xuß║Ñt kho. Chß╗ë c├│ thß╗â chß╗ënh sß╗¡a: Tags, Ghi ch├║, ─É╞░ß╗¥ng dß║½n ─æ╞ín h├áng, Tham chiß║┐u.
                                    </p>
                                </CardContent>
                            </Card>
                        )}
                        
                        <div className="flex flex-col md:flex-row gap-4 items-start">
                            <div className="flex-grow-[7] w-full md:w-0"><CustomerSelector disabled={isFormDisabled || isMetadataOnlyMode} /></div>
                            <div className="flex-grow-[3] w-full md:w-0"><OrderInfoCard disabled={isFormDisabled} isBranchLocked={isBranchLocked} isMetadataOnlyMode={isMetadataOnlyMode} /></div>
                        </div>
                        <Card className="flex flex-col">
                            <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-4">
                                <CardTitle className="text-h4">Th├┤ng tin sß║ún phß║⌐m</CardTitle>
                                <ProductTableToolbar 
                                    disabled={isFormDisabled || isMetadataOnlyMode} 
                                    enableSplitLine={enableSplitLine}
                                    onSplitLineChange={setEnableSplitLine}
                                    settings={tableSettings}
                                    onSettingsChange={setTableSettings}
                                />
                            </CardHeader>
                            <CardContent>
                                <div className="mb-4">
                                    <div className="flex items-center gap-2">
                                        <OrderProductSearch 
                                            onSelectProduct={(p) => handleSelectProducts([p])}
