                                            allowCreateNew={true}
                                            placeholder="Th├¬m sß║ún phß║⌐m (F3)"
                                            searchPlaceholder="T├¼m kiß║┐m theo t├¬n, m├ú SKU, barcode..."
                                            {...(selectedBranchSystemId ? { branchSystemId: selectedBranchSystemId } : {})}
                                        />
                                        <Button type="button" variant="outline" className="h-9 flex-shrink-0" onClick={() => setIsProductSelectionOpen(true)} disabled={isFormDisabled || isMetadataOnlyMode}>Chß╗ìn nhanh</Button>
                                        <Select value={selectedPolicyId} onValueChange={setSelectedPolicyId} disabled={isFormDisabled || isMetadataOnlyMode}>
                                            <SelectTrigger className="h-9 w-[180px] flex-shrink-0"><SelectValue /></SelectTrigger>
                                            <SelectContent>{salesPolicies.map(p => <SelectItem key={p.systemId} value={p.systemId}>{p.name}</SelectItem>)}</SelectContent>
                                        </Select>
                                    </div>
                                </div>
                                {fields.length === 0 ? (
                                    <>
                                        <div className="text-center text-muted-foreground p-12 border border-dashed rounded-md">
                                            <PackageOpen className="mx-auto h-12 w-12 text-gray-300" />
                                            <p className="mt-4 text-body-sm">Ch╞░a c├│ sß║ún phß║⌐m n├áo trong ─æ╞ín h├áng</p>
                                            <Button type="button" variant="link" className="mt-2" onClick={() => setIsProductSelectionOpen(true)} disabled={isMetadataOnlyMode}>Th├¬m sß║ún phß║⌐m</Button>
