                                            onApplyPromotion={() => setIsApplyPromotionDialogOpen(true)}
                                        />
                                    </>
                                ) : ( 
                                    <LineItemsTable 
                                        disabled={isFormDisabled || isMetadataOnlyMode} 
                                        onAddService={() => setIsAddServiceDialogOpen(true)}
