                <ApplyPromotionDialog open={isApplyPromotionDialogOpen} onOpenChange={setIsApplyPromotionDialogOpen} onApply={handleApplyPromotion} disabled={isFormDisabled} />
            </form>
        </FormProvider>
    );
}

import * as React from 'react';
import { useFormContext } from 'react-hook-form';
import { useAllEmployees } from '../../employees/hooks/use-all-employees';
import { useAllBranches } from '../../settings/branches/hooks/use-all-branches';
import { Card, CardContent, CardHeader, CardTitle } from '../../../components/ui/card';
import { FormField, FormItem, FormLabel, FormControl, FormMessage } from '../../../components/ui/form';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '../../../components/ui/select';
import { Combobox } from '../../../components/ui/combobox';
import { DatePicker } from '../../../components/ui/date-picker';
import { Input } from '../../../components/ui/input';
import { Separator } from '../../../components/ui/separator';
import { useSalesChannels } from '../../settings/sales-channels/hooks/use-sales-channels';
import { usePaymentMethods } from '../../settings/payments/hooks/use-payment-methods';

export function OrderInfoCard({ disabled, isBranchLocked = false, isMetadataOnlyMode = false }: { disabled: boolean; isBranchLocked?: boolean; isMetadataOnlyMode?: boolean }) {
    const { control } = useFormContext();
    const { data: employees } = useAllEmployees();
    const { data: branches } = useAllBranches();
    
    // React Query for payment methods and sales channels
    const { data: pmData } = usePaymentMethods({ limit: 1000 });
    const paymentMethods = pmData?.data ?? [];
    const { data: scData } = useSalesChannels({ limit: 1000 });
    const salesChannels = scData?.data ?? [];
    
    const employeeOptions = React.useMemo(() => employees.map(e => ({ value: e.systemId, label: e.fullName })), [employees]);
    const branchOptions = React.useMemo(() => branches.map(b => ({ value: b.systemId, label: b.name })), [branches]);
    const channelOptions = React.useMemo(() => {
      return salesChannels
        .filter(channel => channel.isApplied)
        .sort((a, b) => Number(b.isDefault) - Number(a.isDefault));
    }, [salesChannels]);
    const hasChannelOptions = channelOptions.length > 0;
    const paymentMethodOptions = React.useMemo(() => {
      return paymentMethods
        .filter(method => method.isActive)
        .sort((a, b) => Number(b.isDefault) - Number(a.isDefault));
    }, [paymentMethods]);
    const hasPaymentMethodOptions = paymentMethodOptions.length > 0;

    return (
        <Card className="flex flex-col h-[385px]">
            <CardHeader className="flex-shrink-0"><CardTitle className="text-base font-semibold">Th├┤ng tin bß╗ò sung</CardTitle></CardHeader>
            <CardContent className="flex-1 overflow-y-auto space-y-4">
                <FormField control={control} name="branchSystemId" render={({ field }) => (
                  <FormItem><FormLabel>B├ín tß║íi</FormLabel><Select onValueChange={field.onChange} value={field.value} disabled={disabled || isBranchLocked || isMetadataOnlyMode}><FormControl><SelectTrigger><SelectValue placeholder="Chß╗ìn chi nh├ính" /></SelectTrigger></FormControl><SelectContent>{branchOptions.map(opt => <SelectItem key={opt.value} value={opt.value}>{opt.label}</SelectItem>)}</SelectContent></Select>
                  {isBranchLocked && <p className="text-xs text-muted-foreground mt-1">≡ƒöÆ Chi nh├ính bß╗ï kh├│a sau khi duyß╗çt ─æ╞ín</p>}
                  </FormItem>
                )}/>
                <FormField control={control} name="salespersonSystemId" render={({ field }) => (
                  <FormItem><FormLabel>B├ín bß╗ƒi</FormLabel><Combobox options={employeeOptions} value={employeeOptions.find(opt => opt.value === field.value) || null} onChange={option => field.onChange(option ? option.value : '')} placeholder="Chß╗ìn nh├ón vi├¬n" disabled={disabled || isMetadataOnlyMode} /></FormItem>
                )}/>
                <FormField control={control} name="packerId" render={({ field }) => (
                  <FormItem><FormLabel>Nh├ón vi├¬n ─æ├│ng g├│i</FormLabel><Combobox options={employeeOptions} value={employeeOptions.find(opt => opt.value === field.value) || null} onChange={option => field.onChange(option ? option.value : '')} placeholder="Chß╗ìn nh├ón vi├¬n ─æ├│ng g├│i" disabled={disabled || isMetadataOnlyMode} /><FormMessage /></FormItem>
