const currencyFormatter = new Intl.NumberFormat('vi-VN', {
  style: 'currency',
  currency: 'VND',
  maximumFractionDigits: 0,
});

const formatCurrency = (value?: number) => (typeof value === 'number' ? currencyFormatter.format(value) : 'ΓÇö');
const formatDate = (value?: string) => (value ? formatDateForDisplay(value) : 'ΓÇö');
const _formatDateTime = (value?: string) => (value ? formatDateTimeForDisplay(value) : 'ΓÇö');

const formatMonthKey = (monthKey?: string) => {
  if (!monthKey) return 'ΓÇö';
  const [year, month] = monthKey.split('-');
  return `Th├íng ${month}/${year}`;
};

const formatPeriod = (period?: PayrollPeriod) => {
  if (!period) return 'ΓÇö';
  return `${formatDate(period.startDate)} ΓÇô ${formatDate(period.endDate)}`;
};

