        { label: 'Trang chß╗º', href: ROUTES.DASHBOARD },
        { label: 'Bß║úng l╞░╞íng', href: ROUTES.PAYROLL.LIST },
        { label: batch?.id ?? 'Chi tiß║┐t', href: '' },
      ],
      actions: headerActions,
      badge: batch ? <PayrollStatusBadge status={batch.status} /> : undefined,
      showBackButton: true,
    });
    return () => clearPageHeader();
  }, [setPageHeader, clearPageHeader, batch, headerSubtitle, headerActions]);

  const closeApprovalDialog = React.useCallback(() => {
    setIsApprovalDialogOpen(false);
    setApprovalAction(null);
    setApprovalNote('');
  }, []);

  const handleStatusChange = React.useCallback((status: PayrollBatch['status'], note?: string) => {
    if (!batch) return;
    updateStatus.mutate(
      { systemId: batch.systemId, data: { status, note } },
      {
        onSuccess: () => {
          toast.success('Cß║¡p nhß║¡t trß║íng th├íi th├ánh c├┤ng', {
            description: `Bß║úng l╞░╞íng ─æ├ú chuyß╗ân sang trß║íng th├íi ${STATUS_LABEL[status]}.`,
          });
        },
      }
    );
  }, [batch, updateStatus]);

  const handleConfirmApproval = React.useCallback(() => {
    if (!approvalAction || !batch) return;
    const status = approvalAction === 'review' ? 'reviewed' : 'locked';
    const note = approvalNote.trim() || undefined;
    handleStatusChange(status, note);
    closeApprovalDialog();
  }, [approvalAction, batch, approvalNote, handleStatusChange, closeApprovalDialog]);

  const _handleUnlock = React.useCallback(() => {
    if (!batch) return;
    handleStatusChange('reviewed', 'Mß╗ƒ kh├│a bß║úng l╞░╞íng');
  }, [batch, handleStatusChange]);

  const _handleOpenEmployee = React.useCallback((row: PayslipRow) => {
    if (!row.employeeSystemId) return;
    router.push(ROUTES.HRM.EMPLOYEE_VIEW.replace(':systemId', row.employeeSystemId));
  }, [router]);

  // Payslip action handlers
  const handleEditPayslip = React.useCallback((row: PayslipRow) => {
    if (isLocked) {
      toast.error('Kh├┤ng thß╗â sß╗¡a', { description: 'Bß║úng l╞░╞íng ─æ├ú kh├│a.' });
      return;
    }
    setEditingPayslipId(row.systemId);
  }, [isLocked]);

  const handleSavePayslip = React.useCallback((payload: PayslipUpdatePayload) => {
    if (!editingPayslipId) return;
    updateWithAudit.mutate(
      {
        systemId: editingPayslipId,
        data: payload,
      },
      {
        onSuccess: () => {
          toast.success('─É├ú cß║¡p nhß║¡t phiß║┐u l╞░╞íng');
          setEditingPayslipId(null);
        },
        onError: (err) => {
          toast.error('Kh├┤ng thß╗â cß║¡p nhß║¡t', { description: err.message });
        },
      }
    );
  }, [editingPayslipId, updateWithAudit]);

  const handlePrintPayslip = React.useCallback((row: PayslipRow) => {
    const payslip = payslips.find((p) => p.systemId === row.systemId);
    if (!payslip || !batch) return;

    // Get employee info
    const employee = employeeLookup[payslip.employeeSystemId as SystemId];
    const departmentName = payslip.departmentSystemId
      ? departmentLookup[payslip.departmentSystemId as SystemId]?.name
      : undefined;

    const storeSettings = createStoreSettings(storeInfo);
    
    // Convert to PayslipForPrint for individual payslip printing
    const payslipForPrint = convertPayslipForPrint(
      payslip,
      batch,
      {
        employee: employee ? {
          id: employee.id,
          fullName: employee.fullName,
          department: departmentName,
          position: employee.positionName,
        } : undefined,
        departmentName,
      }
    );

    // Debug: log components

    // Use payslip template (not payroll)
    print('payslip', {
      data: mapPayslipToPrintData(payslipForPrint, storeSettings),
      lineItems: mapPayslipComponentLineItems(payslipForPrint.components),
    });
  }, [batch, payslips, employeeLookup, departmentLookup, storeInfo, print]);

  const handleRemovePayslip = React.useCallback((row: PayslipRow) => {
    if (isLocked) {
      toast.error('Kh├┤ng thß╗â x├│a', { description: 'Bß║úng l╞░╞íng ─æ├ú kh├│a.' });
      return;
    }
    removeFromBatch.mutate(row.systemId, {
      onSuccess: () => {
        toast.success('─É├ú x├│a phiß║┐u l╞░╞íng khß╗Åi bß║úng l╞░╞íng');
      },
      onError: (err) => {
        toast.error('Kh├┤ng thß╗â x├│a', { description: err.message });
      },
    });
  }, [isLocked, removeFromBatch]);

  // Print payment voucher for a payslip (In phiß║┐u chi)
  const handlePrintPayment = React.useCallback((row: PayslipRow) => {
    if (!batch) return;
    
    // Find payment linked to this payslip (by payslipSystemId)
    const payslip = payslips.find((p) => p.systemId === row.systemId);
    if (!payslip) {
      toast.error('Kh├┤ng t├¼m thß║Ñy phiß║┐u l╞░╞íng');
      return;
    }
    
    // Find payment voucher that matches this payslip
    const payment = linkedPayments.find(
      (p) => p.linkedPayslipSystemId === payslip.systemId
    );
    
    if (!payment) {
      toast.error('Ch╞░a tß║ío phiß║┐u chi', {
        description: 'Nh├ón vi├¬n n├áy ch╞░a c├│ phiß║┐u chi. H├úy tß║ío phiß║┐u chi tr╞░ß╗¢c.',
      });
      return;
    }

    // Convert payment to print format
    const storeSettings = createStoreSettings(storeInfo);
    const employee = employeeLookup[payslip.employeeSystemId as SystemId];

    const paymentForPrint: PaymentForPrint = {
      code: payment.id,
      createdAt: payment.createdAt,
      amount: payment.amount,
      paymentMethod: payment.paymentMethodName,
      recipientName: employee?.fullName ?? payslip.employeeId,
      recipientType: 'Nh├ón vi├¬n',
      description: payment.description,
      groupName: payment.paymentReceiptTypeName,
      location: {
        name: payment.branchName,
      },
    };

    print('payment', {
      data: mapPaymentToPrintData(paymentForPrint, storeSettings),
      lineItems: [],
    });
    
    toast.success('─É├ú gß╗¡i in phiß║┐u chi');
  }, [batch, payslips, linkedPayments, employeeLookup, storeInfo, print]);

  // Print penalties for a payslip (In phiß║┐u phß║ít)
  const handlePrintPenalties = React.useCallback((row: PayslipRow) => {
    if (!batch) return;
    
    // Find payslip to get deducted penalty IDs
    const payslip = payslips.find((p) => p.systemId === row.systemId);
    if (!payslip) {
      toast.error('Kh├┤ng t├¼m thß║Ñy phiß║┐u l╞░╞íng');
      return;
    }
    
    // Get deducted penalties
    const penaltyIds = payslip.deductedPenaltySystemIds || [];
    if (penaltyIds.length === 0) {
      toast.info('Kh├┤ng c├│ phiß║┐u phß║ít', {
        description: 'Nh├ón vi├¬n n├áy kh├┤ng c├│ phiß║┐u phß║ít n├áo trong kß╗│ l╞░╞íng.',
      });
      return;
    }
    
    // Get penalties from store
    const penalties = penaltyIds
      .map((id) => allPenalties.find((p) => p.systemId === id))
      .filter(Boolean);
    
    if (penalties.length === 0) {
      toast.error('Kh├┤ng t├¼m thß║Ñy phiß║┐u phß║ít');
      return;
    }
    
    // Build print jobs for all penalties
    const storeSettings = createStoreSettings(storeInfo);
    const employee = employeeLookup[payslip.employeeSystemId as SystemId];
    
    const printJobs = penalties
      .filter((penalty): penalty is NonNullable<typeof penalty> => penalty != null)
      .map((penalty) => {
        const penaltyForPrint = convertPenaltyForPrint(penalty, {
          employee: employee || null,
        });
        
        return {
          data: mapPenaltyToPrintData(penaltyForPrint, storeSettings),
          lineItems: [] as never[],
        };
      });
    
    // Print all penalties at once (single popup)
    printMultiple('penalty', printJobs);
    
    toast.success(`─É├ú in ${penalties.length} phiß║┐u phß║ít`);
  }, [batch, payslips, allPenalties, employeeLookup, storeInfo, printMultiple]);

  // Print dialog state
  const [isPrintDialogOpen, setIsPrintDialogOpen] = React.useState(false);
  const [pendingPrintRows, setPendingPrintRows] = React.useState<PayslipRow[]>([]);
  const [printMode, setPrintMode] = React.useState<'payslips' | 'penalties'>('payslips');

  // Bulk print penalties - open dialog
  const handleBulkPrintPenalties = React.useCallback((rows: PayslipRow[]) => {
    if (!batch || rows.length === 0) return;
    setPendingPrintRows(rows);
    setPrintMode('penalties');
    setIsPrintDialogOpen(true);
  }, [batch]);

  // Bulk print payslips - open dialog
  const handleBulkPrintPayslips = React.useCallback((rows: PayslipRow[]) => {
    if (!batch || rows.length === 0) return;
    setPendingPrintRows(rows);
    setPrintMode('payslips');
    setIsPrintDialogOpen(true);
  }, [batch]);

  // Handle print confirm from dialog
  const handlePrintConfirm = React.useCallback((options: SimplePrintOptionsResult) => {
    if (!batch) return;
    
    const { paperSize } = options;
    const storeSettings = createStoreSettings(storeInfo);
    
    if (printMode === 'penalties') {
      // Print penalties
      const printOptionsList: Array<{
        data: ReturnType<typeof mapPenaltyToPrintData>;
        lineItems: never[];
        paperSize: PaperSize;
      }> = [];
      
      pendingPrintRows.forEach((row) => {
        const payslip = payslips.find((p) => p.systemId === row.systemId);
        if (!payslip) return;
        
        const penaltyIds = payslip.deductedPenaltySystemIds || [];
        if (penaltyIds.length === 0) return;
        
        const penalties = penaltyIds
          .map((id) => allPenalties.find((p) => p.systemId === id))
          .filter(Boolean);
        
        const employee = employeeLookup[payslip.employeeSystemId as SystemId];
        
        penalties.forEach((penalty) => {
          if (!penalty) return;
          
          const penaltyForPrint = convertPenaltyForPrint(penalty, {
            employee: employee || null,
          });
          
          printOptionsList.push({
            data: mapPenaltyToPrintData(penaltyForPrint, storeSettings),
            lineItems: [],
            paperSize,
          });
        });
      });
      
      if (printOptionsList.length > 0) {
        printMultiple('penalty', printOptionsList);
        toast.success(`─É├ú gß╗¡i lß╗çnh in ${printOptionsList.length} phiß║┐u phß║ít`);
      } else {
        toast.info('Kh├┤ng c├│ phiß║┐u phß║ít', {
          description: 'C├íc nh├ón vi├¬n ─æ╞░ß╗úc chß╗ìn kh├┤ng c├│ phiß║┐u phß║ít n├áo.',
        });
      }
    } else {
      // Print payslips
      const printOptionsList: Array<{
        data: ReturnType<typeof mapPayslipToPrintData>;
        lineItems: ReturnType<typeof mapPayslipComponentLineItems>;
        paperSize: PaperSize;
      }> = [];
      
      pendingPrintRows.forEach((row) => {
        const payslip = payslips.find((p) => p.systemId === row.systemId);
        if (!payslip) return;

        const employee = employeeLookup[payslip.employeeSystemId as SystemId];
        const departmentName = payslip.departmentSystemId
          ? departmentLookup[payslip.departmentSystemId as SystemId]?.name
          : undefined;

        const payslipForPrint = convertPayslipForPrint(
          payslip,
          batch,
          {
            employee: employee ? {
              id: employee.id,
              fullName: employee.fullName,
              department: departmentName,
              position: employee.positionName,
            } : undefined,
            departmentName,
          }
        );

        printOptionsList.push({
          data: mapPayslipToPrintData(payslipForPrint, storeSettings),
          lineItems: mapPayslipComponentLineItems(payslipForPrint.components),
          paperSize,
        });
      });
      
      if (printOptionsList.length > 0) {
        printMultiple('payslip', printOptionsList);
        toast.success(`─É├ú gß╗¡i lß╗çnh in ${printOptionsList.length} phiß║┐u l╞░╞íng`);
      }
    }
    
    setPendingPrintRows([]);
  }, [batch, printMode, pendingPrintRows, payslips, allPenalties, employeeLookup, departmentLookup, storeInfo, printMultiple]);

  // Bulk delete
  const handleBulkDeletePayslips = React.useCallback((rows: PayslipRow[]) => {
    if (isLocked) {
      toast.error('Kh├┤ng thß╗â x├│a', { description: 'Bß║úng l╞░╞íng ─æ├ú kh├│a.' });
      return;
    }
    
    let successCount = 0;
    let errorCount = 0;
    
    rows.forEach((row) => {
      try {
        (removeFromBatch as any)(row.systemId);
        successCount++;
      } catch (e) {
        errorCount++;
      }
    });
    
    if (successCount > 0) {
      toast.success(`─É├ú x├│a ${successCount} phiß║┐u l╞░╞íng`);
    }
    if (errorCount > 0) {
      toast.error(`Kh├┤ng thß╗â x├│a ${errorCount} phiß║┐u l╞░╞íng`);
    }
  }, [isLocked, removeFromBatch]);

  // Payslip table actions
  const payslipActions = React.useMemo<PayslipActions>(() => ({
    onEdit: handleEditPayslip,
    onPrint: handlePrintPayslip,
    onPrintPayment: handlePrintPayment,
    onPrintPenalties: handlePrintPenalties,
    onRemove: handleRemovePayslip,
  }), [handleEditPayslip, handlePrintPayslip, handlePrintPayment, handlePrintPenalties, handleRemovePayslip]);

  // Not found state
  if (!batch) {
    return (
      <div className="flex h-72 flex-col items-center justify-center text-center">
        <p className="text-lg font-semibold">Kh├┤ng t├¼m thß║Ñy bß║úng l╞░╞íng.</p>
        <p className="text-body-sm text-muted-foreground">Vui l├▓ng kiß╗âm tra lß║íi ─æ╞░ß╗¥ng dß║½n hoß║╖c quay vß╗ü danh s├ích.</p>
        <Button className="mt-4 h-9" onClick={handleBack}>
          Vß╗ü danh s├ích
        </Button>
      </div>
    );
  }

  const _statusHint = STATUS_HINTS[batch.status];

  return (
    <div className="space-y-6">
      {/* Info Card - 2 cß╗Öt */}
      <Card>
        <CardHeader>
          <CardTitle>Th├┤ng tin chung</CardTitle>
        </CardHeader>
        <CardContent className="grid gap-4 md:grid-cols-2">
          {/* Cß╗Öt tr├íi */}
          <div className="space-y-3 text-body-sm">
            <div className="flex items-center justify-between">
              <span className="text-muted-foreground">M├ú</span>
              <span>{batch.id}</span>
            </div>
            <div className="flex items-center justify-between">
              <span className="text-muted-foreground">Ti├¬u ─æß╗ü</span>
              <span className="font-medium text-right">{batch.title}</span>
            </div>
            <div className="flex items-center justify-between">
              <span className="text-muted-foreground">Kß╗│ l╞░╞íng</span>
              <span className="text-right">{payPeriodLabel}</span>
            </div>
            <div className="flex items-center justify-between">
              <span className="text-muted-foreground">Th├íng chß║Ñm c├┤ng</span>
              <span className="text-right">{referenceMonthsLabel || 'ΓÇö'}</span>
            </div>
          </div>
          
          {/* Cß╗Öt phß║úi */}
          <div className="space-y-3 text-body-sm">
            <div className="flex items-center justify-between">
              <span className="text-muted-foreground">Ng├áy chi trß║ú</span>
              <span>{formatDate(batch.payrollDate)}</span>
            </div>
            <div className="flex items-center justify-between">
              <span className="text-muted-foreground">Tß╗òng thß╗▒c l─⌐nh</span>
              <span className="font-semibold text-primary">{formatCurrency(batch.totalNet)}</span>
            </div>
            <div className="flex items-center justify-between">
              <span className="text-muted-foreground">Sß╗æ phiß║┐u l╞░╞íng</span>
              <span>{batchPayslips.length} nh├ón vi├¬n</span>
            </div>
            <div className="flex items-center justify-between">
              <span className="text-muted-foreground">Trß║íng th├íi</span>
              <PayrollStatusBadge status={batch.status} />
            </div>
          </div>
          
          {/* Phiß║┐u chi l╞░╞íng - full width */}
          <div className="md:col-span-2 pt-3 border-t">
            <div className="flex items-center justify-between text-body-sm">
              <span className="text-muted-foreground">Phiß║┐u chi l╞░╞íng</span>
              <span>{linkedPayments.length > 0 ? `${linkedPayments.length} phiß║┐u chi` : 'Ch╞░a tß║ío'}</span>
            </div>
          </div>
        </CardContent>
      </Card>

      {/* Totals & Notes */}
      <div className="grid gap-4 lg:grid-cols-2">
        <Card>
          <CardHeader>
            <CardTitle>Tß╗òng quan chi trß║ú</CardTitle>
          </CardHeader>
          <CardContent className="grid gap-4 sm:grid-cols-2">
            <div className="rounded-lg border p-3 text-body-sm">
              <p className="text-muted-foreground">Tß╗òng thu nhß║¡p</p>
              <p className="text-xl font-semibold text-emerald-600">{formatCurrency(totals.earnings)}</p>
            </div>
            <div className="rounded-lg border p-3 text-body-sm">
              <p className="text-muted-foreground">Tß╗òng khß║Ñu trß╗½</p>
              <p className="text-xl font-semibold text-red-500">{formatCurrency(totals.deductions)}</p>
            </div>
            <div className="rounded-lg border p-3 text-body-sm">
              <p className="text-muted-foreground">─É├│ng g├│p DN</p>
              <p className="text-xl font-semibold text-blue-500">{formatCurrency(totals.contributions)}</p>
            </div>
            <div className="rounded-lg border p-3 text-body-sm">
              <p className="text-muted-foreground">Tß╗òng thß╗▒c l─⌐nh</p>
              <p className="text-xl font-semibold">{formatCurrency(totals.net)}</p>
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle>Ghi ch├║</CardTitle>
          </CardHeader>
          <CardContent>
            <Textarea
              className="min-h-[120px]"
              placeholder="Ghi ch├║ nß╗Öi bß╗Ö sß║╜ ─æ╞░ß╗úc hß╗ù trß╗ú ß╗ƒ b╞░ß╗¢c tiß║┐p theo."
              readOnly
              value={batch.notes ?? ''}
            />
            {!batch.notes && (
              <p className="mt-2 text-body-xs text-muted-foreground">
                Bß║ín c├│ thß╗â cß║¡p nhß║¡t ghi ch├║ sau khi ho├án thiß╗çn t├¡nh n─âng chß╗ënh sß╗¡a batch.
              </p>
            )}
          </CardContent>
        </Card>
      </div>

      {/* Payslip Table */}
      <PayslipDataTable
        data={batchPayslips}
        isLocked={isLocked}
        actions={payslipActions}
        onBulkPrintBatch={handlePrint}
        onBulkPrint={handleBulkPrintPayslips}
        onBulkPrintPenalties={handleBulkPrintPenalties}
        onBulkDelete={handleBulkDeletePayslips}
      />

      {/* Edit Payslip Dialog */}
      <PayslipEditDialog
        open={!!editingPayslipId}
        onOpenChange={(open) => { if (!open) setEditingPayslipId(null); }}
        payslip={editingPayslip}
        employeeName={editingPayslip ? (employeeLookup[editingPayslip.employeeSystemId]?.fullName ?? `Nh├ón vi├¬n ${editingPayslip.employeeId}`) : ''}
        isLocked={isLocked}
        onSave={handleSavePayslip}
      />

      {/* Create Payment Dialog */}
      <CreatePaymentDialog
        open={isCreatePaymentOpen}
        onOpenChange={setIsCreatePaymentOpen}
        batch={batch}
        payslips={payslips}
        employeeLookup={employeeLookup as Record<SystemId, import('../employees/types').Employee | undefined>}
      />

      {/* Audit Logs - ActivityHistory */}
      <ActivityHistory
        history={historyEntries}
        title="Nhß║¡t k├╜ thao t├íc"
        emptyMessage="Ch╞░a c├│ nhß║¡t k├╜ n├áo."
        showFilters={false}
        groupByDate={false}
        maxHeight="400px"
      />

      {/* Approval Dialog */}
      <AlertDialog
        open={isApprovalDialogOpen}
        onOpenChange={(open) => {
          if (!open) closeApprovalDialog();
        }}
      >
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>
              {approvalAction ? APPROVAL_DIALOG_CONFIG[approvalAction].title : 'X├íc nhß║¡n'}
            </AlertDialogTitle>
            <AlertDialogDescription>
              {approvalAction
                ? APPROVAL_DIALOG_CONFIG[approvalAction].description
                : 'Thao t├íc sß║╜ ─æ╞░ß╗úc ├íp dß╗Ñng cho bß║úng l╞░╞íng hiß╗çn tß║íi.'}
            </AlertDialogDescription>
          </AlertDialogHeader>
          <div className="space-y-2">
            <Label htmlFor="approval-note" className="text-body-sm font-medium">
              Ghi ch├║ nß╗Öi bß╗Ö (kh├┤ng bß║»t buß╗Öc)
            </Label>
            <Textarea
              id="approval-note"
              placeholder="Nhß║¡p l├╜ do duyß╗çt/kh├│a ─æß╗â l╞░u v├áo nhß║¡t k├╜."
              className="min-h-[80px]"
              value={approvalNote}
              onChange={(event) => setApprovalNote(event.target.value)}
            />
          </div>
          <AlertDialogFooter>
            <AlertDialogCancel className="h-9" onClick={closeApprovalDialog}>
              Hß╗ºy
            </AlertDialogCancel>
            <AlertDialogAction className="h-9" onClick={handleConfirmApproval} disabled={!approvalAction}>
              {approvalAction ? APPROVAL_DIALOG_CONFIG[approvalAction].confirmLabel : 'X├íc nhß║¡n'}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      {/* Print Options Dialog */}
      <SimplePrintOptionsDialog
        open={isPrintDialogOpen}
        onOpenChange={setIsPrintDialogOpen}
        onConfirm={handlePrintConfirm}
        selectedCount={pendingPrintRows.length}
        title={printMode === 'payslips' ? 'In phiß║┐u l╞░╞íng' : 'In phiß║┐u phß║ít'}
      />
    </div>
  );
}

/**
 * Payroll List Page Handlers Hook
 * Extracted to reduce list-page.tsx size
 */
import * as React from 'react';
import { toast } from 'sonner';
import { useAllPayrollBatches, useAllPayslips, usePayrollBatchMutations } from '../hooks/use-payroll';
import { useAllPayments } from '@/features/payments/hooks/use-all-payments';
