                    </AlertDescription>
                  </Alert>
                )}
              </>
            ) : (
              <Alert>
                <AlertTitle>Ch╞░a c├│ dß╗» liß╗çu preview</AlertTitle>
                <AlertDescription>
                  Vui l├▓ng quay lß║íi b╞░ß╗¢c tr╞░ß╗¢c ─æß╗â chß╗ìn nh├ón vi├¬n, sau ─æ├│ quay lß║íi ─æ├óy ─æß╗â xem kß║┐t quß║ú.
                </AlertDescription>
              </Alert>
            )}
          </CardContent>
        </Card>
      )}

      <div className="flex items-center justify-between">
        <Button variant="outline" className="h-9" disabled={currentStep === 0} onClick={goPrev}>
          Quay lß║íi
        </Button>
        {currentStep < 2 ? (
          <Button className="h-9" onClick={goNext} disabled={(currentStep === 0 && !canProceedStep1) || (currentStep === 1 && !canProceedStep2)}>
            Tiß║┐p tß╗Ñc
          </Button>
        ) : (
          <Button className="h-9" disabled={!canCreateBatch} onClick={handleCreateBatch}>
            Tß║ío bß║úng l╞░╞íng
          </Button>
        )}
      </div>
    </div>
  );
}

import * as React from 'react';
import { useFuseFilter } from '../../hooks/use-fuse-search';
import { Plus, CheckCircle2, RotateCcw, Trash2, Search, X } from 'lucide-react';
import { Button } from '../../components/ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '../../components/ui/card';
