import { Textarea } from '../../components/ui/textarea';
import { Checkbox } from '../../components/ui/checkbox';
import { Label } from '../../components/ui/label';
import { Badge } from '../../components/ui/badge';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from '../../components/ui/alert-dialog';
import { ResponsiveDataTable } from '../../components/data-table/responsive-data-table';
import { DataTableFacetedFilter } from '../../components/data-table/data-table-faceted-filter';
import { usePageHeader } from '../../contexts/page-header-context';
import { useBreakpoint } from '../../contexts/breakpoint-context';
import { useAllPayrollTemplates, usePayrollTemplateMutations, usePayrollTemplateExtended, usePayrollTemplateFinder } from './hooks/use-payroll';
import { useEmployeeSettings } from '../settings/employees/hooks/use-employee-settings';
import { getTemplateColumns } from './template-columns';
import { TemplateCard } from './template-card';
import { toast } from 'sonner';
import { asSystemId, type SystemId } from '../../lib/id-types';
import type { PayrollTemplate } from '../../lib/payroll-types';

export function PayrollTemplatePage() {
  const templates = useAllPayrollTemplates();
  const { findById } = usePayrollTemplateFinder();
  const { create, update, remove } = usePayrollTemplateMutations({
    onSuccess: () => {},
    onError: (err) => toast.error('Lß╗ùi', { description: err.message }),
  });
  const { setDefault } = usePayrollTemplateExtended({
    onSuccess: () => {},
    onError: (err) => toast.error('Lß╗ùi', { description: err.message }),
  });
  const { data: employeeSettings } = useEmployeeSettings();
  const salaryComponents = React.useMemo(
    () => employeeSettings?.salaryComponents ?? [],
    [employeeSettings?.salaryComponents]
  );
  const { isMobile } = useBreakpoint();

  // Search & Filter states
  const [searchQuery, setSearchQuery] = React.useState('');
  const [isDefaultFilter, setIsDefaultFilter] = React.useState<Set<string>>(new Set());

  // Dialog states
  const [isDialogOpen, setIsDialogOpen] = React.useState(false);
  const [isResetDialogOpen, setIsResetDialogOpen] = React.useState(false);
  const [editingTemplateId, setEditingTemplateId] = React.useState<SystemId | null>(null);
  const [deleteConfirmId, setDeleteConfirmId] = React.useState<SystemId | null>(null);

  // Form state
  const [formState, setFormState] = React.useState({
    name: '',
    description: '',
    componentSystemIds: salaryComponents.map((component) => asSystemId(component.systemId)),
    isDefault: false,
  });

  // Table states
  const [rowSelection, setRowSelection] = React.useState<Record<string, boolean>>({});
  const [columnVisibility, setColumnVisibility] = React.useState<Record<string, boolean>>({});
  const [columnOrder, setColumnOrder] = React.useState<string[]>([]);
  const [pinnedColumns, setPinnedColumns] = React.useState<string[]>(['select', 'id']);
  const [pagination, setPagination] = React.useState({ pageIndex: 0, pageSize: 20 });
  const [sorting, setSorting] = React.useState<{ id: string; desc: boolean }>({ id: 'createdAt', desc: true });

  // Mobile infinite scroll
  const [mobileLoadedCount, setMobileLoadedCount] = React.useState(20);

  // Fuse.js for search (lazy-loaded)
  const fuseOptions = React.useMemo(
    () => ({
      keys: ['id', 'name', 'description'],
      threshold: 0.3,
      includeScore: true,
    }),
    []
  );
  const searchedData = useFuseFilter(templates, searchQuery.trim(), fuseOptions);

  // Filtered data
  const filteredData = React.useMemo(() => {
    let result = searchQuery.trim() ? searchedData : templates;

    // Default filter
    if (isDefaultFilter.size > 0) {
      result = result.filter((t) => {
        if (isDefaultFilter.has('default') && t.isDefault) return true;
        if (isDefaultFilter.has('normal') && !t.isDefault) return true;
        return false;
      });
    }

    return result;
  }, [templates, searchQuery, isDefaultFilter, searchedData]);

  // Reset mobile count when filters change
  React.useEffect(() => {
    setMobileLoadedCount(20);
    setPagination((prev) => ({ ...prev, pageIndex: 0 }));
  }, [searchQuery, isDefaultFilter.size]);

  // Handlers
  const handleOpenCreateDialog = React.useCallback(() => {
    setEditingTemplateId(null);
    setFormState({
      name: '',
      description: '',
      componentSystemIds: salaryComponents.map((component) => asSystemId(component.systemId)),
      isDefault: false,
    });
    setIsDialogOpen(true);
  }, [salaryComponents]);

  const handleEdit = React.useCallback((systemId: SystemId) => {
    const template = findById(systemId);
    if (!template) return;
    setEditingTemplateId(systemId);
    setFormState({
      name: template.name,
      description: template.description ?? '',
      componentSystemIds: template.componentSystemIds as any,
      isDefault: template.isDefault,
    });
    setIsDialogOpen(true);
  }, [findById]);

  const handleDelete = React.useCallback((systemId: SystemId) => {
    setDeleteConfirmId(systemId);
  }, []);

  const handleConfirmDelete = React.useCallback(() => {
    if (deleteConfirmId) {
      remove.mutate(deleteConfirmId, {
        onSuccess: () => {
          toast.success('─É├ú x├│a mß║½u', { description: 'Mß║½u bß║úng l╞░╞íng ─æ├ú ─æ╞░ß╗úc gß╗í bß╗Å.' });
          setDeleteConfirmId(null);
        },
      });
    }
  }, [remove, deleteConfirmId]);

  const handleSetDefault = React.useCallback((systemId: SystemId) => {
    setDefault.mutate(systemId, {
      onSuccess: () => {
        toast.success('─É├ú ─æß║╖t mß║╖c ─æß╗ïnh', { description: 'Mß║½u n├áy sß║╜ ─æ╞░ß╗úc chß╗ìn sß║╡n khi chß║íy l╞░╞íng.' });
      },
    });
  }, [setDefault]);

  const handleToggleDefault = React.useCallback((template: PayrollTemplate, isDefault: boolean) => {
    if (isDefault) {
      // ─Éß║╖t l├ám mß║╖c ─æß╗ïnh
      setDefault.mutate(template.systemId, {
        onSuccess: () => {
          toast.success('─É├ú ─æß║╖t mß║╖c ─æß╗ïnh', { description: `"${template.name}" sß║╜ ─æ╞░ß╗úc chß╗ìn sß║╡n khi chß║íy l╞░╞íng.` });
        },
      });
    } else {
      // Bß╗Å mß║╖c ─æß╗ïnh - server will auto-assign new default
      update.mutate(
        { systemId: template.systemId, data: { isDefault: false } },
        {
          onSuccess: () => {
            toast.success('─É├ú bß╗Å mß║╖c ─æß╗ïnh', { description: 'Hß╗ç thß╗æng ─æ├ú chß╗ìn mß║½u mß║╖c ─æß╗ïnh mß╗¢i.' });
          },
        }
      );
    }
  }, [setDefault, update]);

  const handleResetToDefault = React.useCallback(() => {
    toast.info('Chß╗⌐c n─âng n├áy ─æ├ú ─æ╞░ß╗úc gß╗í bß╗Å', { description: 'Vui l├▓ng tß║ío mß║½u mß╗¢i tß╗½ ─æß║ºu.' });
    setIsResetDialogOpen(false);
  }, []);

  const resetDialog = () => {
    setIsDialogOpen(false);
    setEditingTemplateId(null);
    setFormState({
      name: '',
      description: '',
      componentSystemIds: salaryComponents.map((component) => asSystemId(component.systemId)),
      isDefault: false,
    });
  };

  const handleSubmit = (event: React.FormEvent<HTMLFormElement>) => {
    event.preventDefault();
    if (!formState.name.trim()) {
      toast.error('Vui l├▓ng nhß║¡p t├¬n mß║½u', { description: 'T├¬n mß║½u bß║úng l╞░╞íng l├á bß║»t buß╗Öc.' });
      return;
    }

    if (editingTemplateId) {
      update.mutate(
        {
          systemId: editingTemplateId,
          data: {
            name: formState.name.trim(),
            description: formState.description.trim(),
            componentSystemIds: formState.componentSystemIds,
            isDefault: formState.isDefault,
          },
        },
        {
          onSuccess: () => {
            toast.success('─É├ú cß║¡p nhß║¡t mß║½u', { description: 'Th├┤ng tin mß║½u bß║úng l╞░╞íng ─æ├ú ─æ╞░ß╗úc l╞░u.' });
            resetDialog();
          },
        }
      );
    } else {
      create.mutate(
        {
          name: formState.name.trim(),
          description: formState.description.trim(),
          componentSystemIds: formState.componentSystemIds,
          isDefault: formState.isDefault,
          id: '', // Will be generated by server
          isActive: true,
        },
        {
          onSuccess: () => {
            toast.success('─É├ú tß║ío mß║½u mß╗¢i', { description: 'Bß║ín c├│ thß╗â d├╣ng mß║½u n├áy trong wizard chß║íy l╞░╞íng.' });
            resetDialog();
          },
        }
      );
    }
  };

  const toggleComponentSelection = (componentId: SystemId) => {
    setFormState((prev) => {
      const exists = prev.componentSystemIds.includes(componentId);
      return {
        ...prev,
        componentSystemIds: exists
          ? prev.componentSystemIds.filter((id) => id !== componentId)
          : [...prev.componentSystemIds, componentId],
      };
    });
  };

  // Columns
  const columns = React.useMemo(
    () => getTemplateColumns(handleEdit, handleDelete, handleToggleDefault),
    [handleEdit, handleDelete, handleToggleDefault]
  );

  // Set default column visibility
  React.useEffect(() => {
    const defaultVisibleColumns = ['select', 'id', 'name', 'componentCount', 'isDefault', 'createdAt', 'actions'];
    setColumnVisibility(
      Object.fromEntries(columns.map((col) => [col.id, defaultVisibleColumns.includes(col.id!)]))
    );
    setColumnOrder(columns.map((c) => c.id).filter(Boolean) as string[]);
  }, [columns]);

  // Mobile scroll listener
  React.useEffect(() => {
    if (!isMobile) return;

    const handleScroll = () => {
      const scrollPosition = window.innerHeight + window.scrollY;
      const threshold = document.body.offsetHeight * 0.8;
      if (scrollPosition >= threshold && mobileLoadedCount < filteredData.length) {
        setMobileLoadedCount((prev) => Math.min(prev + 20, filteredData.length));
      }
    };

    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, [isMobile, mobileLoadedCount, filteredData.length]);

  // Pagination
  const pageCount = Math.ceil(filteredData.length / pagination.pageSize);
  const paginatedData = React.useMemo(() => {
    const start = pagination.pageIndex * pagination.pageSize;
    const end = start + pagination.pageSize;
    return filteredData.slice(start, end);
  }, [filteredData, pagination.pageIndex, pagination.pageSize]);

  const displayData = isMobile ? filteredData.slice(0, mobileLoadedCount) : paginatedData;

  // Selected rows count
  const selectedCount = Object.values(rowSelection).filter(Boolean).length;

  // Header actions
  const headerActions = React.useMemo(
