import * as React from 'react';
import { useQueryClient } from '@tanstack/react-query';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '../../../components/ui/card';
import { Button } from '../../../components/ui/button';
import { Badge } from '../../../components/ui/badge';
import { Separator } from '../../../components/ui/separator';
import { Alert, AlertDescription, AlertTitle } from '../../../components/ui/alert';
import { 
  Globe, 
  Unlink, 
  Upload, 
  ExternalLink, 
  CheckCircle2, 
  AlertCircle, 
  Loader2,
  DollarSign,
  Package,
  FileText,
  Search,
  Star
} from 'lucide-react';
import { toast } from 'sonner';
import type { Product } from '../types';
import { usePkgxSettingsStore } from '../../settings/pkgx/store';
import { useProductMutations } from '../hooks/use-products';
import * as pkgxApi from '../../../lib/pkgx/api-service';
import { 
  mapHrmToPkgxPayload, 
  createPriceUpdatePayload, 
  createSeoUpdatePayload,
  createDescriptionUpdatePayload,
  createFlagsUpdatePayload,
  getTotalInventory 
} from '../../../lib/pkgx/mapping-service';

interface EcommerceTabProps {
  product: Product;
}

export function EcommerceTab({ product }: EcommerceTabProps) {
  const [isPushingPkgx, setIsPushingPkgx] = React.useState(false);
  const [isSyncingPrice, setIsSyncingPrice] = React.useState(false);
  const [isSyncingStock, setIsSyncingStock] = React.useState(false);
  const [isSyncingSeo, setIsSyncingSeo] = React.useState(false);
  const [isSyncingDesc, setIsSyncingDesc] = React.useState(false);
  const [isSyncingFlags, setIsSyncingFlags] = React.useState(false);
  const [isUnlinking, setIsUnlinking] = React.useState(false);
  
  const queryClient = useQueryClient();
  const pkgxSettings = usePkgxSettingsStore();
  const { update: updateMutation } = useProductMutations();
  const updateProduct = (systemId: string, data: Partial<Product>) => 
    updateMutation.mutate({ systemId, ...data });
  
  const isPkgxLinked = !!product.pkgxId;
  const isTrendtechLinked = !!product.trendtechId;
  
  // Get category mapping for this product
  const pkgxCategoryMapping = React.useMemo(() => {
    if (!product.categorySystemId) return null;
    return null; // getCategoryMappingByHrmId not available
  }, [product.categorySystemId]);
  
  // Get brand mapping for this product
  const pkgxBrandMapping = React.useMemo(() => {
    if (!product.brandSystemId) return null;
    return null; // getBrandMappingByHrmId not available
  }, [product.brandSystemId]);
  
  // Check if product can be pushed to PKGX
  const canPushToPkgx = React.useMemo(() => {
    if (!(pkgxSettings as any)?.apiUrl || !(pkgxSettings as any)?.apiKey) return false;
    if (!(pkgxSettings as any)?.enabled) return false;
    // Must have category mapping
    if (!pkgxCategoryMapping) return false;
    return true;
  }, [pkgxSettings, pkgxCategoryMapping]);
  
  // Push product to PKGX
  const handlePushToPkgx = async () => {
    if (!canPushToPkgx) {
      toast.error('Ch╞░a cß║Ñu h├¼nh ─æß╗º th├┤ng tin ─æß╗â ─æß║⌐y l├¬n PKGX');
      return;
    }
    
    setIsPushingPkgx(true);
    try {
      const payload = mapHrmToPkgxPayload(product);
      
      let response;
      if (isPkgxLinked) {
        // Update existing
        response = await pkgxApi.updateProduct(product.pkgxId!, payload, pkgxSettings as any);
      } else {
        // Create new
        response = await pkgxApi.createProduct(payload, pkgxSettings as any);
      }
      
      if (response.success && response.data) {
        // Update product with PKGX ID if newly created
        if (!isPkgxLinked && response.data.goods_id) {
          updateProduct(product.systemId, { 
            pkgxId: response.data.goods_id,
            updatedAt: new Date().toISOString(),
          });
          
          // Invalidate React Query cache so list page refreshes immediately
          queryClient.invalidateQueries({ queryKey: ['products'] });
        }
        
        pkgxSettings.addLog({
          action: isPkgxLinked ? 'update_product' : 'create_product',
          status: 'success',
          message: `${isPkgxLinked ? 'Cß║¡p nhß║¡t' : 'Tß║ío mß╗¢i'} sß║ún phß║⌐m tr├¬n PKGX: ${product.name}`,
          details: { productId: product.systemId, pkgxId: response.data.goods_id || product.pkgxId },
        });
        
        toast.success(isPkgxLinked ? '─É├ú cß║¡p nhß║¡t sß║ún phß║⌐m tr├¬n PKGX' : '─É├ú ─æß║⌐y sß║ún phß║⌐m l├¬n PKGX');
      } else {
        throw new Error(response.error || 'Lß╗ùi kh├┤ng x├íc ─æß╗ïnh');
      }
    } catch (error) {
      pkgxSettings.addLog({
        action: isPkgxLinked ? 'update_product' : 'create_product',
        status: 'error',
        message: `Lß╗ùi ${isPkgxLinked ? 'cß║¡p nhß║¡t' : 'tß║ío'} sß║ún phß║⌐m: ${product.name}`,
        details: { error: error instanceof Error ? error.message : String(error) },
      });
      toast.error(error instanceof Error ? error.message : 'Lß╗ùi khi ─æß║⌐y sß║ún phß║⌐m l├¬n PKGX');
    } finally {
      setIsPushingPkgx(false);
    }
  };
  
  // Sync price to PKGX
  const handleSyncPrice = async () => {
    if (!isPkgxLinked) {
      toast.error('Sß║ún phß║⌐m ch╞░a li├¬n kß║┐t vß╗¢i PKGX');
      return;
    }
    
    setIsSyncingPrice(true);
    try {
      const pricePayload = createPriceUpdatePayload(product);
      
      const response = await pkgxApi.updateProduct(product.pkgxId!, pricePayload, pkgxSettings as any);
      
      if (response.success) {
        pkgxSettings.addLog({
          action: 'sync_price',
          status: 'success',
          message: `─Éß╗ông bß╗Ö gi├í th├ánh c├┤ng: ${product.name}`,
          details: { productId: product.systemId, pkgxId: product.pkgxId },
        });
        toast.success('─É├ú ─æß╗ông bß╗Ö gi├í l├¬n PKGX');
      } else {
        throw new Error(response.error || 'Lß╗ùi kh├┤ng x├íc ─æß╗ïnh');
      }
    } catch (error) {
      pkgxSettings.addLog({
        action: 'sync_price',
        status: 'error',
        message: `Lß╗ùi ─æß╗ông bß╗Ö gi├í: ${product.name}`,
        details: { error: error instanceof Error ? error.message : String(error) },
      });
      toast.error(error instanceof Error ? error.message : 'Lß╗ùi khi ─æß╗ông bß╗Ö gi├í');
    } finally {
      setIsSyncingPrice(false);
    }
  };
  
  // Sync stock to PKGX
  const handleSyncStock = async () => {
    if (!isPkgxLinked) {
      toast.error('Sß║ún phß║⌐m ch╞░a li├¬n kß║┐t vß╗¢i PKGX');
      return;
    }
    
    setIsSyncingStock(true);
    try {
      const totalStock = getTotalInventory(product);
      
      const response = await pkgxApi.updateProductStock(product.pkgxId!, totalStock);
      
      if (response.success) {
        pkgxSettings.addLog({
          action: 'sync_inventory',
          status: 'success',
          message: `─Éß╗ông bß╗Ö tß╗ôn kho th├ánh c├┤ng: ${product.name} (${totalStock})`,
          details: { productId: product.systemId, pkgxId: product.pkgxId, inventory: totalStock },
        });
        toast.success(`─É├ú ─æß╗ông bß╗Ö tß╗ôn kho: ${totalStock} ${product.unit}`);
      } else {
        throw new Error(response.error || 'Lß╗ùi kh├┤ng x├íc ─æß╗ïnh');
      }
    } catch (error) {
      pkgxSettings.addLog({
        action: 'sync_inventory',
        status: 'error',
        message: `Lß╗ùi ─æß╗ông bß╗Ö tß╗ôn kho: ${product.name}`,
        details: { error: error instanceof Error ? error.message : String(error) },
      });
      toast.error(error instanceof Error ? error.message : 'Lß╗ùi khi ─æß╗ông bß╗Ö tß╗ôn kho');
    } finally {
      setIsSyncingStock(false);
    }
  };
  
  // Sync SEO to PKGX
  const handleSyncSeo = async () => {
    if (!isPkgxLinked) {
      toast.error('Sß║ún phß║⌐m ch╞░a li├¬n kß║┐t vß╗¢i PKGX');
      return;
    }
    
    setIsSyncingSeo(true);
    try {
      const seoPayload = createSeoUpdatePayload(product);
      const response = await pkgxApi.updateProduct(product.pkgxId!, seoPayload);
      
      if (response.success) {
        pkgxSettings.addLog({
          action: 'sync_seo',
          status: 'success',
          message: `─Éß╗ông bß╗Ö SEO th├ánh c├┤ng: ${product.name}`,
          details: { productId: product.systemId, pkgxId: product.pkgxId },
        });
        toast.success('─É├ú ─æß╗ông bß╗Ö SEO l├¬n PKGX');
      } else {
        throw new Error(response.error || 'Lß╗ùi kh├┤ng x├íc ─æß╗ïnh');
      }
    } catch (error) {
      pkgxSettings.addLog({
        action: 'sync_seo',
        status: 'error',
        message: `Lß╗ùi ─æß╗ông bß╗Ö SEO: ${product.name}`,
