import * as React from 'react';
import { Link2 } from 'lucide-react';
import { toast } from 'sonner';
import { Button } from '@/components/ui/button';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { VirtualizedCombobox, type ComboboxOption } from '@/components/ui/virtualized-combobox';
import { useAllProducts } from '../hooks/use-all-products';
import { useProductMutations } from '../hooks/use-products';
import type { Product } from '../types';
import type { PkgxProduct } from '@/features/settings/pkgx/types';
import { usePkgxSettings, usePkgxProductsMutations } from '@/features/settings/pkgx/hooks/use-pkgx-settings';

interface PkgxLinkDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  product: Product | null;
  onSuccess?: (pkgxId: number) => void;
}

export function PkgxLinkDialog({
  open,
  onOpenChange,
  product,
  onSuccess,
}: PkgxLinkDialogProps) {
  const { update: updateMutation } = useProductMutations();
  const { data: pkgxSettings } = usePkgxSettings();
  const { setPkgxProducts: setProducts } = usePkgxProductsMutations();
  const cachedPkgxProducts = pkgxSettings?.pkgxProducts ?? [];
  
  const [selectedPkgxProduct, setSelectedPkgxProduct] = React.useState<ComboboxOption | null>(null);
  const [pkgxProducts, setPkgxProductsLocal] = React.useState<PkgxProduct[]>([]);
  const [isLoading, setIsLoading] = React.useState(false);
  const [isSyncing, setIsSyncing] = React.useState(false);
  const [hasFetched, setHasFetched] = React.useState(false);

  const loadPkgxProducts = React.useCallback(async () => {
    setIsLoading(true);
    try {
      // fetchPkgxProducts not available - use placeholder
      const response: any = { success: false, data: null };
      if (response.success && response.data && response.data.data) {
        // API trß║ú vß╗ü { data: PkgxProduct[], pagination: {...} }
        const productsArray = Array.isArray(response.data.data) ? response.data.data : [];
        setPkgxProductsLocal(productsArray);
        setProducts.mutate(productsArray); // L╞░u v├áo store ─æß╗â d├╣ng chung
        setHasFetched(true);
      }
    } catch (error) {
      console.error('Failed to load PKGX products:', error);
      toast.error('Kh├┤ng thß╗â tß║úi danh s├ích sß║ún phß║⌐m PKGX');
    } finally {
      setIsLoading(false);
    }
  }, [setProducts]);

  // Load PKGX products khi mß╗ƒ dialog - chß╗ë chß║íy 1 lß║ºn
  React.useEffect(() => {
    if (open && !hasFetched) {
      if (cachedPkgxProducts && cachedPkgxProducts.length > 0) {
        setPkgxProductsLocal(cachedPkgxProducts);
        setHasFetched(true);
      } else {
        loadPkgxProducts();
      }
    }
  }, [open, hasFetched, cachedPkgxProducts, loadPkgxProducts]);

  // Reset state khi ─æ├│ng dialog
  React.useEffect(() => {
    if (!open) {
      setSelectedPkgxProduct(null);
    }
  }, [open]);

  // Filter out products that are already linked
  const { data: hrmProducts } = useAllProducts();
  const linkedPkgxIds = React.useMemo(() => {
    return new Set(hrmProducts.filter(p => p.pkgxId).map(p => p.pkgxId));
  }, [hrmProducts]);

  // Convert PKGX products to combobox options
  const pkgxOptions: ComboboxOption[] = React.useMemo(() => {
    return pkgxProducts
      .filter(p => !linkedPkgxIds.has(p.goods_id)) // Exclude already linked
      .map(p => ({
        value: String(p.goods_id),
        label: p.goods_name,
        subtitle: `ID: ${p.goods_id} | M├ú: ${p.goods_sn || '-'}`,
        metadata: p,
      }));
  }, [pkgxProducts, linkedPkgxIds]);

  const handleConfirmLink = async () => {
    if (!product || !selectedPkgxProduct) {
      toast.error('Vui l├▓ng chß╗ìn sß║ún phß║⌐m PKGX ─æß╗â li├¬n kß║┐t');
      return;
    }

    setIsSyncing(true);
    try {
      const pkgxId = Number(selectedPkgxProduct.value);
      
      // Update HRM product with pkgxId
      updateMutation.mutate({ systemId: product.systemId, pkgxId });
      
      // Log to console

      toast.success(`─É├ú li├¬n kß║┐t vß╗¢i sß║ún phß║⌐m PKGX: ${selectedPkgxProduct.label}`);
      onSuccess?.(pkgxId);
      onOpenChange(false);
    } catch (error) {
      console.error('[PKGX Link Error]', error);
      toast.error('Lß╗ùi khi li├¬n kß║┐t sß║ún phß║⌐m');
    } finally {
      setIsSyncing(false);
    }
  };

  if (!product) return null;

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-[500px]">
        <DialogHeader>
          <DialogTitle>Li├¬n kß║┐t vß╗¢i sß║ún phß║⌐m PKGX</DialogTitle>
          <DialogDescription>
            Chß╗ìn sß║ún phß║⌐m PKGX ─æß╗â li├¬n kß║┐t vß╗¢i sß║ún phß║⌐m HRM n├áy
          </DialogDescription>
        </DialogHeader>

        <div className="space-y-4 py-4">
          {/* HRM Product Info */}
          <div className="rounded-lg bg-muted p-3">
            <p className="text-sm font-medium">Sß║ún phß║⌐m HRM:</p>
            <p className="text-sm">{product.name}</p>
            <p className="text-xs text-muted-foreground">
              M├ú: {product.id} | SystemID: {product.systemId}
            </p>
          </div>

          {/* PKGX Product Selector */}
          <div className="space-y-2">
            <label className="text-sm font-medium">Chß╗ìn sß║ún phß║⌐m PKGX</label>
            <VirtualizedCombobox
              value={selectedPkgxProduct}
              onChange={setSelectedPkgxProduct}
              options={pkgxOptions}
              placeholder="T├¼m v├á chß╗ìn sß║ún phß║⌐m PKGX..."
              searchPlaceholder="T├¼m theo t├¬n hoß║╖c m├ú..."
              emptyPlaceholder={isLoading ? '─Éang tß║úi...' : 'Kh├┤ng t├¼m thß║Ñy sß║ún phß║⌐m PKGX'}
              isLoading={isLoading}
              disabled={isLoading}
            />
            {pkgxOptions.length === 0 && !isLoading && (
              <p className="text-xs text-muted-foreground">
                Tß║Ñt cß║ú sß║ún phß║⌐m PKGX ─æ├ú ─æ╞░ß╗úc li├¬n kß║┐t. H├úy ─æß╗ông bß╗Ö danh s├ích mß╗¢i tß╗½ PKGX.
              </p>
            )}
          </div>
        </div>

        <DialogFooter>
          <Button
            variant="outline"
            onClick={() => onOpenChange(false)}
            disabled={isSyncing}
          >
            Hß╗ºy
          </Button>
          <Button
            onClick={handleConfirmLink}
            disabled={!selectedPkgxProduct || isSyncing}
          >
            <Link2 className="h-4 w-4 mr-2" />
            {isSyncing ? '─Éang li├¬n kß║┐t...' : 'Li├¬n kß║┐t'}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

import * as React from "react";
import { asBusinessId } from "@/lib/id-types";
import { useProductMutations } from "../hooks/use-products";
import { toast } from 'sonner';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "../../../components/ui/dialog";
import { Button } from "../../../components/ui/button";
import { Input } from "../../../components/ui/input";
import { Label } from "../../../components/ui/label";
import { CurrencyInput } from "../../../components/ui/currency-input";

interface QuickAddProductDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onSuccess?: (productId: string) => void;
}

export function QuickAddProductDialog({
  open,
  onOpenChange,
  onSuccess,
}: QuickAddProductDialogProps) {
  const { create: createMutation } = useProductMutations({
    onCreateSuccess: (data) => {
      toast.success(`─É├ú th├¬m sß║ún phß║⌐m`);
      onOpenChange(false);
      if (onSuccess && data && typeof data === 'object' && 'systemId' in data) {
        onSuccess((data as { systemId: string }).systemId);
      }
    },
    onError: () => {
      toast.error('Kh├┤ng thß╗â th├¬m sß║ún phß║⌐m. Vui l├▓ng thß╗¡ lß║íi.');
    }
  });
  const [isSubmitting, setIsSubmitting] = React.useState(false);

  // Form state
  const [formData, setFormData] = React.useState({
    name: "",
    sku: "",
    costPrice: "",
    basePrice: "",
    importQuantity: "",
    category: "",
    unit: "C├íi",
    productType: "regular" as "regular" | "serial-imei",
  });

  // Validation errors
  const [errors, setErrors] = React.useState<Record<string, string>>({});

  // Auto-focus first input when dialog opens
  const nameInputRef = React.useRef<HTMLInputElement>(null);
  React.useEffect(() => {
    if (open) {
      setTimeout(() => nameInputRef.current?.focus(), 100);
    }
  }, [open]);

  // Reset form when dialog closes
  React.useEffect(() => {
    if (!open) {
      setFormData({
        name: "",
        sku: "",
        costPrice: "",
        basePrice: "",
        importQuantity: "",
        category: "",
        unit: "C├íi",
        productType: "regular",
      });
      setErrors({});
      setIsSubmitting(false);
    }
  }, [open]);

  const validateForm = (): boolean => {
    const newErrors: Record<string, string> = {};

    if (!formData.name.trim()) {
      newErrors.name = "T├¬n sß║ún phß║⌐m l├á bß║»t buß╗Öc";
    }

    if (formData.costPrice && isNaN(Number(formData.costPrice))) {
      newErrors.costPrice = "Gi├í nhß║¡p phß║úi l├á sß╗æ";
    }

    if (formData.costPrice && Number(formData.costPrice) < 0) {
      newErrors.costPrice = "Gi├í nhß║¡p kh├┤ng thß╗â ├óm";
    }

    if (formData.basePrice && isNaN(Number(formData.basePrice))) {
      newErrors.basePrice = "Gi├í b├ín lß║╗ phß║úi l├á sß╗æ";
    }

    if (formData.basePrice && Number(formData.basePrice) < 0) {
      newErrors.basePrice = "Gi├í b├ín lß║╗ kh├┤ng thß╗â ├óm";
    }

    if (formData.importQuantity && isNaN(Number(formData.importQuantity))) {
      newErrors.importQuantity = "Sß╗æ l╞░ß╗úng nhß║¡p phß║úi l├á sß╗æ";
    }

    if (formData.importQuantity && Number(formData.importQuantity) < 0) {
      newErrors.importQuantity = "Sß╗æ l╞░ß╗úng nhß║¡p kh├┤ng thß╗â ├óm";
