        type: "physical" as const,
        status: "active" as const,
        isStockTracked: formData.productType === "regular",
        inventoryByBranch: {},
        committedByBranch: {},
        inTransitByBranch: {},
      };

      (createMutation.mutate as any)(newProduct);
    } catch (_error) {
      toast.error('Kh├┤ng thß╗â th├¬m sß║ún phß║⌐m. Vui l├▓ng thß╗¡ lß║íi.');
