        <form onSubmit={handleSubmit} className="space-y-4">
          {/* T├¬n sß║ún phß║⌐m */}
          <div className="space-y-2">
            <Label htmlFor="product-name">
              T├¬n sß║ún phß║⌐m <span className="text-destructive">*</span>
            </Label>
            <Input
              id="product-name"
              ref={nameInputRef}
              placeholder="Nhß║¡p t├¬n sß║ún phß║⌐m"
              value={formData.name}
              onChange={(e) =>
                setFormData((prev) => ({ ...prev, name: e.target.value }))
              }
              className={errors.name ? "border-destructive" : ""}
            />
            {errors.name && (
              <p className="text-body-sm text-destructive">{errors.name}</p>
            )}
          </div>

          {/* M├ú sß║ún phß║⌐m/SKU */}
          <div className="space-y-2">
            <Label htmlFor="product-sku">M├ú sß║ún phß║⌐m/SKU</Label>
            <Input
              id="product-sku"
              placeholder="Nhß║¡p tay hoß║╖c ─æß╗â trß╗æng ─æß╗â tß╗▒ ─æß╗Öng"
              value={formData.sku}
              onChange={(e) =>
                setFormData((prev) => ({ ...prev, sku: e.target.value }))
              }
            />
          </div>

          {/* Row 1: Gi├í nhß║¡p + Gi├í b├ín lß║╗ */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="product-cost">Gi├í nhß║¡p</Label>
              <CurrencyInput
                id="product-cost"
                value={formData.costPrice ? Number(formData.costPrice) : 0}
                onChange={(value) =>
                  setFormData((prev) => ({ ...prev, costPrice: value.toString() }))
                }
                placeholder="0"
                className={errors.costPrice ? "border-destructive" : ""}
              />
              {errors.costPrice && (
                <p className="text-body-sm text-destructive">{errors.costPrice}</p>
              )}
            </div>

            <div className="space-y-2">
              <Label htmlFor="product-base-price">Gi├í b├ín lß║╗</Label>
              <CurrencyInput
                id="product-base-price"
                value={formData.basePrice ? Number(formData.basePrice) : 0}
                onChange={(value) =>
                  setFormData((prev) => ({ ...prev, basePrice: value.toString() }))
                }
                placeholder="0"
                className={errors.basePrice ? "border-destructive" : ""}
              />
              {errors.basePrice && (
                <p className="text-body-sm text-destructive">{errors.basePrice}</p>
              )}
            </div>
          </div>

          {/* Row 2: Sß╗æ l╞░ß╗úng nhß║¡p + Loß║íi sß║ún phß║⌐m */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="product-quantity">Sß╗æ l╞░ß╗úng nhß║¡p</Label>
              <Input
                id="product-quantity"
                type="number"
                min="0"
                step="1"
                placeholder="0"
                value={formData.importQuantity}
                onChange={(e) =>
                  setFormData((prev) => ({
                    ...prev,
                    importQuantity: e.target.value,
                  }))
                }
                className={errors.importQuantity ? "border-destructive" : ""}
              />
              {errors.importQuantity && (
                <p className="text-body-sm text-destructive">{errors.importQuantity}</p>
              )}
            </div>

            <div className="space-y-2">
              <Label htmlFor="product-category">Loß║íi sß║ún phß║⌐m</Label>
              <Input
                id="product-category"
                placeholder="Nhß║¡p loß║íi sß║ún phß║⌐m"
                value={formData.category}
                onChange={(e) =>
                  setFormData((prev) => ({ ...prev, category: e.target.value }))
                }
              />
            </div>
          </div>

          {/* ─É╞ín vß╗ï t├¡nh */}
          <div className="space-y-2">
            <Label htmlFor="product-unit">─É╞ín vß╗ï t├¡nh</Label>
            <Input
              id="product-unit"
              placeholder="C├íi, Hß╗Öp, Th├╣ng..."
              value={formData.unit}
