    }
  }, [addPkgxLog]);

  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  // 6. SYNC TH├öNG TIN C╞á Bß║óN (t├¬n, SKU, category, brand, seller_note)
  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  const handlePkgxSyncBasicInfo = React.useCallback(async (product: Product) => {
    if (!product.pkgxId) {
      toast.error('Sß║ún phß║⌐m ch╞░a ─æ╞░ß╗úc li├¬n kß║┐t vß╗¢i PKGX');
      return;
    }
    
    toast.loading(`─Éang ─æß╗ông bß╗Ö th├┤ng tin c╞í bß║ún...`, { id: 'pkgx-sync-basic' });
    
    try {
      const payload: Record<string, unknown> = {
        goods_name: product.name,
        goods_sn: product.id,
        seller_note: product.sellerNote || '',
      };

      // Map category nß║┐u c├│
      const catId = getMappedCategoryId(product);
      if (catId) payload.cat_id = catId;

      // Map brand nß║┐u c├│  
      const brandId = getMappedBrandId(product);
      if (brandId) payload.brand_id = brandId;

      const response = await updateProduct(product.pkgxId, payload);
      
      if (response.success) {
        toast.success(`─É├ú ─æß╗ông bß╗Ö th├┤ng tin c╞í bß║ún`, { id: 'pkgx-sync-basic' });
        addPkgxLog({
          action: 'sync_basic_info',
          status: 'success',
          message: `─É├ú ─æß╗ông bß╗Ö th├┤ng tin c╞í bß║ún: ${product.name}`,
          details: { productId: product.systemId, pkgxId: product.pkgxId, payload },
        });
      } else {
        throw new Error(response.error);
      }
    } catch (error) {
      toast.error(`Lß╗ùi ─æß╗ông bß╗Ö th├┤ng tin c╞í bß║ún: ${error instanceof Error ? error.message : 'Unknown error'}`, { id: 'pkgx-sync-basic' });
      addPkgxLog({
        action: 'sync_basic_info',
        status: 'error',
        message: `Lß╗ùi ─æß╗ông bß╗Ö th├┤ng tin c╞í bß║ún: ${product.name}`,
        details: { productId: product.systemId, error: error instanceof Error ? error.message : String(error) },
      });
    }
  }, [getMappedCategoryId, getMappedBrandId, addPkgxLog]);

  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  // 7. SYNC H├îNH ß║óNH (ß║únh ─æß║íi diß╗çn + album gallery)
  // Logic: Fetch ß║únh tß╗½ HRM server tr╞░ß╗¢c, upload l├¬n PKGX, rß╗ôi sync ─æ╞░ß╗¥ng dß║½n
  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  const handlePkgxSyncImages = React.useCallback(async (product: Product) => {
    if (!product.pkgxId) {
      toast.error('Sß║ún phß║⌐m ch╞░a ─æ╞░ß╗úc li├¬n kß║┐t vß╗¢i PKGX');
      return;
    }

    toast.loading('─Éang lß║Ñy th├┤ng tin h├¼nh ß║únh...', { id: 'pkgx-sync-images' });

    // ===== STEP 1: Fetch ß║únh tß╗½ HRM server =====
    const thumbnailUrls: string[] = [];
    const galleryUrls: string[] = [];

    // Helper: Kiß╗âm tra URL c├│ thß╗â truy cß║¡p tß╗½ internet kh├┤ng
    const isPublicUrl = (url: string): boolean => {
      if (!url) return false;
      // Bß╗Å qua localhost, 127.0.0.1, hoß║╖c internal IP
      if (url.includes('localhost') || url.includes('127.0.0.1') || url.includes('192.168.')) {
        return false;
      }
      return true;
    };

    try {
      // Import ─æß╗Öng ─æß╗â tr├ính circular dependency
      const { FileUploadAPI } = await import('@/lib/file-upload-api');
      const files = await FileUploadAPI.getProductFiles(product.systemId);
      
      
      // Ph├ón loß║íi ß║únh theo documentName - CHß╗ê lß║Ñy URL public
      for (const file of files) {
        if (file.documentName === 'thumbnail' && file.url && isPublicUrl(file.url)) {
          thumbnailUrls.push(file.url);
        } else if (file.documentName === 'gallery' && file.url && isPublicUrl(file.url)) {
          galleryUrls.push(file.url);
        }
      }
    } catch (_fetchError) {
      // Silently fail - fallback to product object
    }

    // ===== STEP 2: Fallback vß╗ü product object nß║┐u server kh├┤ng c├│ ß║únh =====

    // Nß║┐u server kh├┤ng c├│, d├╣ng tß╗½ product object - CHß╗ê lß║Ñy URL public
    if (thumbnailUrls.length === 0 && product.thumbnailImage && isPublicUrl(product.thumbnailImage)) {
      thumbnailUrls.push(product.thumbnailImage);
    }
    if (galleryUrls.length === 0 && product.galleryImages?.length) {
      galleryUrls.push(...product.galleryImages.filter(isPublicUrl));
    }
    // Legacy fallback
    if (thumbnailUrls.length === 0 && galleryUrls.length === 0 && product.images?.length) {
      const publicImages = product.images.filter(isPublicUrl);
      if (publicImages.length > 0) {
        thumbnailUrls.push(publicImages[0]);
        if (publicImages.length > 1) {
          galleryUrls.push(...publicImages.slice(1));
        }
      }
    }

    // C┼⌐ng check image-store (ß║únh ─æ├ú upload v├áo HRM nh╞░ng ch╞░a fetch tß╗½ server)
    const imageStoreState = useImageStore.getState();
    const permanentThumbnails = imageStoreState.getPermanentImages(product.systemId, 'thumbnail');
    const permanentGallery = imageStoreState.getPermanentImages(product.systemId, 'gallery');

    // Merge vß╗¢i image-store nß║┐u c├│ - CHß╗ê lß║Ñy URL public
    if (permanentThumbnails.length > 0 && thumbnailUrls.length === 0) {
      thumbnailUrls.push(...permanentThumbnails.map(f => f.url).filter(url => url && isPublicUrl(url)));
    }
    if (permanentGallery.length > 0 && galleryUrls.length === 0) {
      galleryUrls.push(...permanentGallery.map(f => f.url).filter(url => url && isPublicUrl(url)));
    }


    // Final main image v├á gallery
    const mainImage = thumbnailUrls[0] || null;
    const galleryImages = galleryUrls;


    if (!mainImage && galleryImages.length === 0) {
      toast.error('Sß║ún phß║⌐m ch╞░a c├│ h├¼nh ß║únh', { id: 'pkgx-sync-images' });
      return;
    }
    
    const totalImages = (mainImage ? 1 : 0) + galleryImages.length;
    toast.loading(`─Éang ─æß╗ông bß╗Ö ${totalImages} h├¼nh ß║únh...`, { id: 'pkgx-sync-images' });
    
    try {
      // Tß║ío slug tß╗½ t├¬n sß║ún phß║⌐m cho filename
      const baseSlug = (product.name || 'product')
        .toLowerCase()
        .normalize('NFD')
        .replace(/[\u0300-\u036f]/g, '')
        .replace(/─æ/g, 'd')
        .replace(/[^a-z0-9]+/g, '-')
        .replace(/^-|-$/g, '')
        .substring(0, 50);

      let uploadedMainImg: string | null = null;
      const uploadedGalleryPaths: string[] = [];
      let errorCount = 0;

      // Helper function: Upload ß║únh tß╗½ URL qua server PKGX (tr├ính CORS)
      const uploadFromUrl = async (imageUrl: string, slugSuffix: string): Promise<string | null> => {
        try {
          // Kiß╗âm tra nß║┐u l├á ─æ╞░ß╗¥ng dß║½n local tr├¬n PKGX (─æ├ú upload tr╞░ß╗¢c ─æ├│)
          if (imageUrl.startsWith('images/') || imageUrl.includes('/cdn/images/')) {
            // ─É├ú l├á path tr├¬n PKGX, kh├┤ng cß║ºn upload lß║íi
            const cleanPath = imageUrl.replace(/.*\/cdn\//, '').replace(/^cdn\//, '');
            return cleanPath;
          }

          // Gß╗ìi API server-to-server ─æß╗â tr├ính CORS
          const uploadResult = await uploadImageFromUrl(imageUrl, {
            filenameSlug: `${baseSlug}-${slugSuffix}`,
          });

          if (!uploadResult.success || !uploadResult.data) {
            throw new Error(uploadResult.error || 'Upload thß║Ñt bß║íi');
          }

          // Trß║ú vß╗ü ─æ╞░ß╗¥ng dß║½n original_img
          return uploadResult.data.data?.original_img || null;
        } catch (err) {
          console.error(`Lß╗ùi upload ß║únh ${imageUrl}:`, err);
          return null;
        }
      };

      // Upload ß║únh ─æß║íi diß╗çn
      if (mainImage) {
        toast.loading(`─Éang upload ß║únh ─æß║íi diß╗çn...`, { id: 'pkgx-sync-images' });
        uploadedMainImg = await uploadFromUrl(mainImage, 'main');
        if (!uploadedMainImg) {
          errorCount++;
        }
      }

      // Upload gallery images
      if (galleryImages.length > 0) {
        for (let i = 0; i < galleryImages.length; i++) {
          toast.loading(`─Éang upload ß║únh ${i + 1}/${galleryImages.length}...`, { id: 'pkgx-sync-images' });
          const galleryPath = await uploadFromUrl(galleryImages[i], `gallery-${i + 1}`);
          if (galleryPath) {
            uploadedGalleryPaths.push(galleryPath);
          } else {
            errorCount++;
          }
        }
      }

      // Kiß╗âm tra c├│ g├¼ ─æß╗â sync kh├┤ng
      if (!uploadedMainImg && uploadedGalleryPaths.length === 0) {
        throw new Error('Kh├┤ng thß╗â upload bß║Ñt kß╗│ ß║únh n├áo');
      }

      // Build payload ─æß╗â sync v├áo sß║ún phß║⌐m
      const payload: Record<string, unknown> = {};
      
      if (uploadedMainImg) {
        payload.original_img = uploadedMainImg;
      }
      
      if (uploadedGalleryPaths.length > 0) {
        payload.gallery_images = uploadedGalleryPaths;
      }

      // Sync ─æ╞░ß╗¥ng dß║½n v├áo sß║ún phß║⌐m
      toast.loading(`─Éang cß║¡p nhß║¡t sß║ún phß║⌐m...`, { id: 'pkgx-sync-images' });
      const response = await updateProduct(product.pkgxId, payload);
      
      if (response.success) {
        const syncedCount = (uploadedMainImg ? 1 : 0) + uploadedGalleryPaths.length;
        const message = errorCount > 0 
          ? `─É├ú ─æß╗ông bß╗Ö ${syncedCount} h├¼nh ß║únh (${errorCount} lß╗ùi)`
          : `─É├ú ─æß╗ông bß╗Ö ${syncedCount} h├¼nh ß║únh`;
        
        toast.success(message, { id: 'pkgx-sync-images' });
        addPkgxLog({
          action: 'sync_images',
          status: errorCount > 0 ? 'partial' : 'success',
          message: `${message}: ${product.name}`,
          details: { 
            productId: product.systemId, 
            pkgxId: product.pkgxId, 
            uploadedMainImg,
            galleryCount: uploadedGalleryPaths.length,
            uploadedGalleryPaths,
            errorCount,
          },
        });
      } else {
        throw new Error(response.error);
      }
    } catch (error) {
      toast.error(`Lß╗ùi ─æß╗ông bß╗Ö h├¼nh ß║únh: ${error instanceof Error ? error.message : 'Unknown error'}`, { id: 'pkgx-sync-images' });
      addPkgxLog({
        action: 'sync_images',
        status: 'error',
        message: `Lß╗ùi ─æß╗ông bß╗Ö h├¼nh ß║únh: ${product.name}`,
        details: { productId: product.systemId, error: error instanceof Error ? error.message : String(error) },
      });
    }
  }, [addPkgxLog]);

  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  // 8. SYNC Tß║ñT Cß║ó (Full sync, bao gß╗ôm xß╗¡ l├╜ ß║únh trong m├┤ tß║ú)
  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  const handlePkgxSyncAll = React.useCallback(async (product: Product) => {
    if (!product.pkgxId) {
      toast.error('Sß║ún phß║⌐m ch╞░a ─æ╞░ß╗úc li├¬n kß║┐t vß╗¢i PKGX');
      return;
    }
    
    toast.loading(`─Éang ─æß╗ông bß╗Ö tß║Ñt cß║ú th├┤ng tin...`, { id: 'pkgx-sync-all' });
    
    try {
      const pkgxSeo = product.seoPkgx;
      
      // Get raw descriptions
      const rawLongDesc = pkgxSeo?.longDescription || product.description || '';
      const rawShortDesc = pkgxSeo?.shortDescription || product.shortDescription || '';
      
      // Process images in long description
      let processedLongDesc = rawLongDesc;
      let imageStats = { uploadedCount: 0, skippedCount: 0, errors: [] as string[] };
      
      if (rawLongDesc.includes('<img')) {
        toast.loading(`─Éang xß╗¡ l├╜ ß║únh trong m├┤ tß║ú...`, { id: 'pkgx-sync-all' });
        
        const filenamePrefix = product.sku || product.id || `product-${product.pkgxId}`;
        const result = await processHtmlImagesForPkgx(rawLongDesc, filenamePrefix);
        
        processedLongDesc = result.processedHtml;
        imageStats = result;
      }
      
      // Build full payload
      const payload: Record<string, unknown> = {
        // Th├┤ng tin c╞í bß║ún
        goods_name: product.name,
        goods_sn: product.id,
        
        // Tß╗ôn kho
        goods_number: product.inventoryByBranch
          ? Object.values(product.inventoryByBranch).reduce((sum, qty) => sum + (qty || 0), 0)
          : 0,
        
        // SEO
        keywords: pkgxSeo?.seoKeywords || product.tags?.join(', ') || product.name,
        meta_title: pkgxSeo?.seoTitle || product.ktitle || product.name,
        meta_desc: pkgxSeo?.metaDescription || product.seoDescription || '',
        
        // M├┤ tß║ú (─æ├ú xß╗¡ l├╜ ß║únh)
        goods_desc: processedLongDesc,
        goods_brief: rawShortDesc,
        
        // Flags
        best: product.isFeatured || false,
        hot: product.isBestSeller || false,
        new: product.isNewArrival || false,
        ishome: product.isFeatured || false,
        is_on_sale: product.isPublished ?? (product.status === 'active'),
        
        // Image - ß║únh ─æß║íi diß╗çn
        ...(product.thumbnailImage && { original_img: product.thumbnailImage }),
      };

      // Gallery images (album ß║únh) - update to├án bß╗Ö
      const galleryImages = product.galleryImages || product.images || [];
      if (galleryImages.length > 0) {
        payload.gallery_images = galleryImages;
      }

      // Map category
      const catId = getMappedCategoryId(product);
      if (catId) payload.cat_id = catId;

      // Map brand
      const brandId = getMappedBrandId(product);
      if (brandId) payload.brand_id = brandId;

      // Map prices
      const shopPrice = getPriceByMapping(product, 'shopPrice');
      if (shopPrice !== undefined) payload.shop_price = shopPrice;
      
      const marketPrice = getPriceByMapping(product, 'marketPrice');
      if (marketPrice !== undefined) payload.market_price = marketPrice;
      
      const partnerPrice = getPriceByMapping(product, 'partnerPrice');
      if (partnerPrice !== undefined) payload.partner_price = partnerPrice;
      
      const acePrice = getPriceByMapping(product, 'acePrice');
      if (acePrice !== undefined) payload.ace_price = acePrice;
      
      const dealPrice = getPriceByMapping(product, 'dealPrice');
      if (dealPrice !== undefined) payload.deal_price = dealPrice;

      const response = await updateProduct(product.pkgxId, payload);
      
      if (response.success) {
        const message = imageStats.uploadedCount > 0
          ? `─É├ú ─æß╗ông bß╗Ö tß║Ñt cß║ú (${imageStats.uploadedCount} ß║únh trong m├┤ tß║ú ─æ├ú upload)`
          : `─É├ú ─æß╗ông bß╗Ö tß║Ñt cß║ú th├┤ng tin`;
          
        toast.success(message, { id: 'pkgx-sync-all' });
        addPkgxLog({
          action: 'sync_all',
          status: imageStats.errors.length > 0 ? 'partial' : 'success',
          message: `${message}: ${product.name}`,
          details: { 
            productId: product.systemId, 
            pkgxId: product.pkgxId,
            imagesUploaded: imageStats.uploadedCount,
            imagesSkipped: imageStats.skippedCount,
            imageErrors: imageStats.errors,
          },
        });
      } else {
        throw new Error(response.error);
      }
    } catch (error) {
      toast.error(`Lß╗ùi ─æß╗ông bß╗Ö: ${error instanceof Error ? error.message : 'Unknown error'}`, { id: 'pkgx-sync-all' });
      addPkgxLog({
        action: 'sync_all',
        status: 'error',
        message: `Lß╗ùi ─æß╗ông bß╗Ö tß║Ñt cß║ú: ${product.name}`,
        details: { productId: product.systemId, error: error instanceof Error ? error.message : String(error) },
      });
    }
  }, [getMappedCategoryId, getMappedBrandId, getPriceByMapping, addPkgxLog]);

  return {
    // Sync handlers
    handlePkgxUpdatePrice,
    handlePkgxSyncInventory,
    handlePkgxUpdateSeo,
    handlePkgxSyncDescription,
    handlePkgxSyncFlags,
    handlePkgxSyncBasicInfo,
    handlePkgxSyncImages,
    handlePkgxSyncAll,
    // Helpers
    hasPriceMapping,
  };
}

'use client';

import * as React from 'react';
import { Card, CardContent } from '@/components/ui/card';
import { usePurchaseOrders } from '../hooks/use-purchase-orders';
import { useAllInventoryReceipts } from '@/features/inventory-receipts/hooks/use-all-inventory-receipts';
import { usePurchaseReturns } from '@/features/purchase-returns/hooks/use-purchase-returns';

interface POStats {
  totalOrdered: number;
  totalReceived: number;
  totalReturned: number;
  netInStock: number;
  receivedRate: string;
  returnedRate: string;
}

export function usePOStats(): POStats {
  const { data: queryData } = usePurchaseOrders({ limit: 1000 });
  const purchaseOrders = queryData?.data ?? [];
  const { data: allReceipts } = useAllInventoryReceipts();
  const { data: prQueryData } = usePurchaseReturns({ limit: 1000 });
  const allPurchaseReturns = prQueryData?.data ?? [];

  return React.useMemo(() => {
    const stats = new Map<string, { 
      totalOrdered: number; 
      totalReceived: number; 
      totalReturned: number;
      variance: number;
    }>();

    // Collect all PO IDs
    purchaseOrders.forEach(po => {
      const totalOrdered = po.lineItems.reduce((sum, item) => sum + item.quantity, 0);
      stats.set(po.id, { totalOrdered, totalReceived: 0, totalReturned: 0, variance: totalOrdered });
    });

    // Add received quantities
    allReceipts.forEach(receipt => {
      if (receipt.purchaseOrderId && stats.has(receipt.purchaseOrderId)) {
        const totalReceived = receipt.items.reduce((sum, item) => sum + item.receivedQuantity, 0);
        const current = stats.get(receipt.purchaseOrderId)!;
        current.totalReceived += totalReceived;
        current.variance = current.totalOrdered - current.totalReceived + current.totalReturned;
      }
    });

    // Add returned quantities
    allPurchaseReturns.forEach(ret => {
      if (ret.purchaseOrderId && stats.has(ret.purchaseOrderId)) {
        const totalReturned = ret.items.reduce((sum, item) => sum + item.returnQuantity, 0);
        const current = stats.get(ret.purchaseOrderId)!;
        current.totalReturned += totalReturned;
        current.variance = current.totalOrdered - current.totalReceived + current.totalReturned;
      }
    });

    // Calculate totals
    let totalOrdered = 0;
    let totalReceived = 0;
    let totalReturned = 0;
    stats.forEach(stat => {
      totalOrdered += stat.totalOrdered;
      totalReceived += stat.totalReceived;
      totalReturned += stat.totalReturned;
    });

    return { 
      totalOrdered, 
      totalReceived, 
      totalReturned,
      netInStock: totalReceived - totalReturned,
      receivedRate: totalOrdered > 0 ? ((totalReceived / totalOrdered) * 100).toFixed(1) : '0',
      returnedRate: totalReceived > 0 ? ((totalReturned / totalReceived) * 100).toFixed(1) : '0'
    };
  }, [purchaseOrders, allReceipts, allPurchaseReturns]);
}

export function POStatisticsCards() {
