            <span className="text-body-sm text-muted-foreground ml-2">({stats.receivedRate}%)</span>
          </p>
        </CardContent>
      </Card>
      <Card>
        <CardContent className="p-4">
          <p className="text-body-sm text-muted-foreground">─É├ú trß║ú lß║íi</p>
