        // 3. Cß║¡p nhß║¡t delivery status trong store
        processInventoryReceipt(createdOrder.systemId); // Γ£à Fixed: Use systemId

        // 4. Xß╗¡ l├╜ thanh to├ín nß║┐u c├│ payment records
        if (currentPayments.length > 0) {
          const totalPayments = currentPayments.reduce((sum, p) => sum + p.amount, 0);
          
          currentPayments.forEach((payment, _index) => {
            const paymentCategory = paymentTypes.find(pt => pt.name === 'Thanh to├ín cho ─æ╞ín nhß║¡p h├áng');

            const timestamp = formatDateCustom(getCurrentDate(), 'yyyy-MM-dd HH:mm');
            const newPayment = {
