            createPayment.mutate(newPayment);
          });

          // Cß║¡p nhß║¡t payment status
          const updatedPaymentStatus = totalPayments >= grandTotal ? '─É├ú thanh to├ín' : 'Thanh to├ín mß╗Öt phß║ºn';
          (update as any).mutate({
            systemId: createdOrder.systemId,
