    </Button>,
  ];

  const headerTitle = isEditMode
    ? `Chß╗ënh sß╗¡a ─æ╞ín nhß║¡p h├áng ${existingOrder?.id ?? ''}`.trim()
    : 'Tß║ío ─æ╞ín nhß║¡p h├áng mß╗¢i';

  usePageHeader({ 
    title: headerTitle,
    breadcrumb: [
      { label: 'Trang chß╗º', href: '/', isCurrent: false },
