/**
 * Hook cho cancel workflow cß╗ºa PurchaseOrder
 * T├ích tß╗½ page.tsx ─æß╗â giß║úm k├¡ch th╞░ß╗¢c file
 */
import React from 'react';
import { toast } from 'sonner';
import { toISODate, getCurrentDate } from '@/lib/date-utils';
import { asBusinessId, asSystemId } from '@/lib/id-types';
import type { PurchaseOrder } from '@/lib/types/prisma-extended';
import { usePurchaseOrderStore } from '../store';
import { sumPaymentsForPurchaseOrder } from '../payment-utils';
import { useAllPayments } from '@/features/payments/hooks/use-all-payments';
import { useInventoryReceipts } from '@/features/inventory-receipts/hooks/use-inventory-receipts';
import { usePurchaseReturns, usePurchaseReturnMutations } from '@/features/purchase-returns/hooks/use-purchase-returns';
import type { PurchaseReturnLineItem } from '@/features/purchase-returns/types';
import { useAuth } from '@/contexts/auth-context';

export interface CancelPODialogState {
  isOpen: boolean;
  po: PurchaseOrder | null;
  willCreateReturn?: boolean;
  totalPaid?: number;
}

const initialCancelState: CancelPODialogState = {
  isOpen: false,
  po: null,
};

export function usePurchaseOrderCancelWorkflow() {
  const { cancelOrder, bulkCancel } = usePurchaseOrderStore();
  const { data: allPayments } = useAllPayments();
  const { data: irQueryData } = useInventoryReceipts({ limit: 1000 });
  const allReceipts = irQueryData?.data ?? [];
  const { data: prQueryData } = usePurchaseReturns({ limit: 1000 });
  const allPurchaseReturns = prQueryData?.data ?? [];
  const { create: createPurchaseReturn } = usePurchaseReturnMutations({
    onCreateSuccess: () => {},
    onError: (err) => toast.error(err.message)
  });
  const { employee: loggedInUser } = useAuth();
  
  const currentUserSystemId = loggedInUser?.systemId ?? 'SYSTEM';
  const currentUserName = loggedInUser?.fullName ?? 'Hß╗ç thß╗æng';

  const [cancelDialogState, setCancelDialogState] = React.useState<CancelPODialogState>(initialCancelState);

  const handleCancelRequest = React.useCallback((po: PurchaseOrder) => {
    const totalPaid = sumPaymentsForPurchaseOrder(allPayments, po);
    const hasBeenDelivered = po.deliveryStatus !== 'Ch╞░a nhß║¡p';

    setCancelDialogState({ 
      isOpen: true, 
      po: po, 
      totalPaid: totalPaid,
      willCreateReturn: hasBeenDelivered 
    });
  }, [allPayments]);

  const closeCancelDialog = React.useCallback(() => {
    setCancelDialogState(initialCancelState);
  }, []);

  const confirmCancel = React.useCallback(() => {
    if (!cancelDialogState.po) return;
    const po = cancelDialogState.po;

    if (cancelDialogState.willCreateReturn) {
      const poSystemId = asSystemId(po.systemId);
      const receiptsForPO = allReceipts.filter(r => r.purchaseOrderSystemId === poSystemId);
      const returnsForPO = allPurchaseReturns.filter(pr => pr.purchaseOrderSystemId === poSystemId);

      const returnItems = po.lineItems
        .map<PurchaseReturnLineItem | null>(item => {
          const totalReceived = receiptsForPO.reduce((sum, receipt) => {
            const receiptItem = receipt.items.find(i => i.productSystemId === item.productSystemId);
            return sum + (receiptItem ? Number(receiptItem.receivedQuantity) : 0);
          }, 0);
          const totalReturned = returnsForPO.reduce((sum, pr) => {
            const returnItem = pr.items.find(i => i.productSystemId === item.productSystemId);
            return sum + (returnItem ? returnItem.returnQuantity : 0);
          }, 0);
          const returnableQuantity = totalReceived - totalReturned;

          if (returnableQuantity <= 0) {
            return null;
          }

          return {
            productSystemId: asSystemId(item.productSystemId),
            productId: asBusinessId(item.productId),
            productName: item.productName,
            orderedQuantity: item.quantity,
            returnQuantity: returnableQuantity,
            unitPrice: item.unitPrice,
          } satisfies PurchaseReturnLineItem;
        })
        .filter((item): item is PurchaseReturnLineItem => Boolean(item));

      if (returnItems.length > 0) {
        const totalReturnValue = returnItems.reduce((sum, item) => sum + (item.returnQuantity * item.unitPrice), 0);

        createPurchaseReturn.mutate({
          id: asBusinessId(''),
          purchaseOrderSystemId: asSystemId(po.systemId),
          purchaseOrderId: asBusinessId(po.id),
          supplierSystemId: asSystemId(po.supplierSystemId),
          supplierName: po.supplierName,
          branchSystemId: asSystemId(po.branchSystemId),
          branchName: po.branchName,
          returnDate: toISODate(getCurrentDate()),
          reason: `Tß╗▒ ─æß╗Öng tß║ío khi hß╗ºy ─æ╞ín nhß║¡p h├áng ${po.id}`,
          items: returnItems,
          totalReturnValue,
          refundAmount: 0,
          refundMethod: '',
          creatorName: currentUserName,
        });
      }
    }

    cancelOrder(po.systemId, currentUserSystemId, currentUserName);
    setCancelDialogState(initialCancelState);
    toast.success('─É├ú hß╗ºy ─æ╞ín nhß║¡p h├áng', {
      description: `─É╞ín ${po.id} ─æ├ú ─æ╞░ß╗úc hß╗ºy`,
    });
  }, [cancelDialogState, allReceipts, allPurchaseReturns, createPurchaseReturn, cancelOrder, currentUserSystemId, currentUserName]);

  const handleBulkCancel = React.useCallback((selectedIds: string[]) => {
    if (selectedIds.length === 0) {
      toast.error('Ch╞░a chß╗ìn ─æ╞ín h├áng', {
        description: 'Vui l├▓ng chß╗ìn ├¡t nhß║Ñt mß╗Öt ─æ╞ín h├áng',
      });
      return;
    }
    bulkCancel(selectedIds, currentUserSystemId, currentUserName);
    toast.success('─É├ú hß╗ºy', {
      description: `─É├ú hß╗ºy ${selectedIds.length} ─æ╞ín nhß║¡p h├áng`,
    });
  }, [bulkCancel, currentUserSystemId, currentUserName]);

  return {
    cancelDialogState,
    handleCancelRequest,
    closeCancelDialog,
    confirmCancel,
    handleBulkCancel,
  };
}

/**
 * Hook tß╗òng hß╗úp handlers cho PurchaseOrders page
 * Kß║┐t hß╗úp receive workflow, cancel workflow, v├á print handlers
 * Sß╗¡ dß╗Ñng ─æß╗â giß║úm k├¡ch th╞░ß╗¢c page.tsx < 300 lines
 */
import * as React from 'react';
import { useRouter } from 'next/navigation';
import { toast } from 'sonner';
import { formatDateCustom, getCurrentDate } from '@/lib/date-utils';
import { asBusinessId, asSystemId } from '@/lib/id-types';
import type { PurchaseOrder } from '@/lib/types/prisma-extended';
import { usePurchaseOrders, usePurchaseOrderMutations } from '../hooks/use-purchase-orders';
import { useAllPayments } from '@/features/payments/hooks/use-all-payments';
import { usePaymentStore } from '@/features/payments/store';
import { useAllCashAccounts } from '@/features/cashbook/hooks/use-all-cash-accounts';
import { useAllPaymentTypes } from '@/features/settings/payments/types/hooks/use-all-payment-types';
import { usePurchaseReturns } from '@/features/purchase-returns/hooks/use-purchase-returns';
import { useAuth } from '@/contexts/auth-context';
import { sumPaymentsForPurchaseOrder } from '../payment-utils';
import type { Payment } from '@/features/payments/types';

// Import sub-workflows
import { usePurchaseOrderReceiveWorkflow, type ReceiveDialogState, type ReceiveLineItemForm } from './use-po-receive-workflow';
import { usePurchaseOrderCancelWorkflow, type CancelPODialogState } from './use-po-cancel-workflow';
import { usePurchaseOrderPrintHandlers } from './use-po-print-handlers';

export type { ReceiveDialogState, ReceiveLineItemForm, CancelPODialogState };

/**
 * Main hook combining all PurchaseOrders page handlers
 */
export function usePurchaseOrdersPageHandlers() {
  const router = useRouter();
  const { data: queryData } = usePurchaseOrders({ limit: 1000 });
  const purchaseOrders = queryData?.data ?? [];
  const { update: updatePO } = usePurchaseOrderMutations({});
  const { data: allPayments } = useAllPayments();
  const { accounts } = useAllCashAccounts();
  const { data: paymentTypes } = useAllPaymentTypes();
  const { data: prQueryData } = usePurchaseReturns({ limit: 1000 });
  const allPurchaseReturns = prQueryData?.data ?? [];
  const { employee: loggedInUser } = useAuth();
  
  const currentUserSystemId = loggedInUser?.systemId ?? 'SYSTEM';
  const currentUserName = loggedInUser?.fullName ?? 'Hß╗ç thß╗æng';
  
  // Helper functions
  const bulkCancel = React.useCallback((systemIds: string[], userId: string, userName: string) => {
    systemIds.forEach(id => (updatePO as any).mutate({ systemId: id, status: 'cancelled', cancelledBy: userId, cancelledAt: new Date().toISOString() }));
  }, [updatePO]);
  
  const syncAllPurchaseOrderStatuses = React.useCallback(() => {
    // Note: This is handled by React Query invalidation
  }, []);

  // Sub-workflows
  const receiveWorkflow = usePurchaseOrderReceiveWorkflow();
  const cancelWorkflow = usePurchaseOrderCancelWorkflow();
  const printHandlers = usePurchaseOrderPrintHandlers();

  // Row selection state
  const [rowSelection, setRowSelection] = React.useState<Record<string, boolean>>({});
  const [isBulkPayAlertOpen, setIsBulkPayAlertOpen] = React.useState(false);

  // Computed values
  const selectedOrders = React.useMemo(() => {
    return purchaseOrders.filter(o => rowSelection[o.systemId]);
  }, [purchaseOrders, rowSelection]);

  const numSelected = Object.keys(rowSelection).filter(k => rowSelection[k]).length;

  // Handler: Start cancel request
  const handleCancelRequest = React.useCallback((po: PurchaseOrder) => {
    cancelWorkflow.handleCancelRequest(po);
  }, [cancelWorkflow]);

  // Handler: Start receive goods
  const handleReceiveGoods = React.useCallback((po: PurchaseOrder) => {
    receiveWorkflow.beginReceiveFlow([po]);
  }, [receiveWorkflow]);

  // Handler: View payment details
  const handlePayment = React.useCallback((po: PurchaseOrder) => {
    router.push(`/purchase-orders/${po.systemId}`);
    toast(`Mß╗ƒ trang thanh to├ín cho ─æ╞ín ${po.id}`);
  }, [router]);

  // Handler: Print single
  const handlePrint = React.useCallback((po: PurchaseOrder) => {
    printHandlers.handlePrint(po);
  }, [printHandlers]);

  // Bulk actions
  const handleBulkPrint = React.useCallback(() => {
    if (numSelected === 0) {
      toast.error('Ch╞░a chß╗ìn ─æ╞ín h├áng', {
        description: 'Vui l├▓ng chß╗ìn ├¡t nhß║Ñt mß╗Öt ─æ╞ín h├áng',
      });
      return;
    }
    printHandlers.openBulkPrintDialog(selectedOrders);
  }, [numSelected, selectedOrders, printHandlers]);

  const handleBulkCancel = React.useCallback(() => {
    const selectedIds = Object.keys(rowSelection).filter(id => rowSelection[id]);
    if (selectedIds.length === 0) {
      toast.error('Ch╞░a chß╗ìn ─æ╞ín h├áng', {
        description: 'Vui l├▓ng chß╗ìn ├¡t nhß║Ñt mß╗Öt ─æ╞ín h├áng',
      });
      return;
    }
    bulkCancel(selectedIds, currentUserSystemId, currentUserName);
    toast.success('─É├ú hß╗ºy', {
      description: `─É├ú hß╗ºy ${selectedIds.length} ─æ╞ín nhß║¡p h├áng`,
    });
    setRowSelection({});
  }, [rowSelection, bulkCancel, currentUserSystemId, currentUserName]);

  const handleBulkReceive = React.useCallback(() => {
    if (numSelected === 0) {
      toast.error('Ch╞░a chß╗ìn ─æ╞ín h├áng', {
        description: 'Vui l├▓ng chß╗ìn ├¡t nhß║Ñt mß╗Öt ─æ╞ín h├áng',
      });
      return;
    }
    receiveWorkflow.beginReceiveFlow(selectedOrders);
  }, [numSelected, selectedOrders, receiveWorkflow]);

  const confirmBulkPay = React.useCallback(() => {
    const paymentCategory = paymentTypes.find(pt => pt.name === 'Thanh to├ín cho ─æ╞ín nhß║¡p h├áng');
    const { add: addPayment } = usePaymentStore.getState();
    const paymentMethodName = 'Chuyß╗ân khoß║ún';
    const paymentMethodSystemId = 'BANK_TRANSFER';
    let totalPaymentsCreated = 0;
    
    selectedOrders.forEach(po => {
      const totalPaid = sumPaymentsForPurchaseOrder(allPayments, po);
      const totalReturnValue = allPurchaseReturns
        .filter(r => r.purchaseOrderSystemId === asSystemId(po.systemId))
        .reduce((sum, r) => sum + r.totalReturnValue, 0);
      const actualDebt = Math.max(po.grandTotal - totalReturnValue, 0);
      const amountRemaining = actualDebt - totalPaid;

      if (amountRemaining > 0) {
        const account = accounts.find(acc => acc.type === 'bank' && acc.branchSystemId === po.branchSystemId) 
          || accounts.find(acc => acc.type === 'bank');
        if (!account) {
          console.error(`Kh├┤ng t├¼m thß║Ñy t├ái khoß║ún ng├ón h├áng cho chi nh├ính ${po.branchName}`);
          return;
        }

        const now = formatDateCustom(getCurrentDate(), 'yyyy-MM-dd HH:mm');
        const newPayment = {
          id: '' as Payment['id'],
          date: now,
          amount: amountRemaining,
          recipientTypeSystemId: asSystemId('NHACUNGCAP'),
          recipientTypeName: 'Nh├á cung cß║Ñp',
          recipientName: po.supplierName,
          recipientSystemId: asSystemId(po.supplierSystemId),
          description: `Thanh to├ín to├án bß╗Ö cho ─æ╞ín nhß║¡p h├áng ${po.id}`,
          paymentMethodSystemId: asSystemId(paymentMethodSystemId),
          paymentMethodName,
          accountSystemId: asSystemId(account.systemId),
          paymentReceiptTypeSystemId: asSystemId(paymentCategory?.systemId || ''),
          paymentReceiptTypeName: paymentCategory?.name || 'Thanh to├ín cho ─æ╞ín nhß║¡p h├áng',
          branchSystemId: asSystemId(po.branchSystemId),
          branchName: po.branchName,
          createdBy: asSystemId(currentUserSystemId),
          createdAt: now,
          status: 'completed' as const,
          category: 'supplier_payment' as const,
          affectsDebt: true,
          purchaseOrderSystemId: asSystemId(po.systemId),
          purchaseOrderId: asBusinessId(po.id),
          originalDocumentId: po.id,
        } satisfies Omit<Payment, 'systemId'>;
        addPayment(newPayment);
        totalPaymentsCreated += 1;
      }
    });

    if (totalPaymentsCreated > 0) {
      syncAllPurchaseOrderStatuses();
      toast.success('─É├ú tß║ío phiß║┐u chi', {
        description: `Ho├án tß║Ñt ${totalPaymentsCreated} phiß║┐u chi cho ─æ╞ín nhß║¡p h├áng ─æ├ú chß╗ìn.`,
      });
    }

    setRowSelection({});
    setIsBulkPayAlertOpen(false);
  }, [selectedOrders, allPayments, allPurchaseReturns, accounts, paymentTypes, currentUserSystemId, syncAllPurchaseOrderStatuses]);

  // Print dialog handlers
  const handlePrintConfirm = React.useCallback((options: Parameters<typeof printHandlers.handlePrintConfirm>[0]) => {
    printHandlers.handlePrintConfirm(options);
    setRowSelection({});
  }, [printHandlers]);

  // Cancel dialog handlers
  const handleConfirmCancel = React.useCallback(() => {
    cancelWorkflow.confirmCancel();
    setRowSelection({});
  }, [cancelWorkflow]);

  return {
    // State
    rowSelection,
    setRowSelection,
    isBulkPayAlertOpen,
    setIsBulkPayAlertOpen,
    numSelected,
    selectedOrders,
    
    // Individual actions
    handleCancelRequest,
    handleReceiveGoods,
    handlePayment,
    handlePrint,
    
    // Bulk actions  
    handleBulkPrint,
    handleBulkCancel,
    handleBulkReceive,
    confirmBulkPay,
    
    // Receive workflow state & handlers
    receiveDialogState: receiveWorkflow.receiveDialogState,
    isSubmittingReceive: receiveWorkflow.isSubmittingReceive,
    handleReceiveQuantityChange: receiveWorkflow.handleReceiveQuantityChange,
    handleReceiveFieldChange: receiveWorkflow.handleReceiveFieldChange,
    handleReceiveBranchChange: receiveWorkflow.handleReceiveBranchChange,
    handleSubmitReceiveDialog: receiveWorkflow.handleSubmitReceiveDialog,
    closeReceiveDialog: receiveWorkflow.closeReceiveDialog,
    
    // Cancel workflow state & handlers
    cancelDialogState: cancelWorkflow.cancelDialogState,
    closeCancelDialog: cancelWorkflow.closeCancelDialog,
    handleConfirmCancel,
    
    // Print workflow state & handlers
    isPrintDialogOpen: printHandlers.isPrintDialogOpen,
    pendingPrintPOs: printHandlers.pendingPrintPOs,
    handlePrintConfirm,
    closePrintDialog: printHandlers.closePrintDialog,
  };
}

