  // Search & filter
  const fuseOptions = React.useMemo(() => ({ keys: ['id', 'supplierName', 'status'] }), []);
  const searchedData = useFuseFilter(purchaseOrders, filters.globalFilter, fuseOptions);

  const filteredData = React.useMemo(() => {
