            <SelectItem value="Ho├án th├ánh">Ho├án th├ánh</SelectItem>
            <SelectItem value="─É├ú hß╗ºy">─É├ú hß╗ºy</SelectItem>
            <SelectItem value="Kß║┐t th├║c">Kß║┐t th├║c</SelectItem>
          </SelectContent>
        </Select>
        <Select value={filters.paymentStatusFilter} onValueChange={filters.setPaymentStatusFilter}>
          <SelectTrigger className="h-9 w-full sm:w-[180px]"><SelectValue placeholder="Thanh to├ín" /></SelectTrigger>
          <SelectContent>
            <SelectItem value="all">Tß║Ñt cß║ú</SelectItem>
            <SelectItem value="Ch╞░a thanh to├ín">Ch╞░a thanh to├ín</SelectItem>
            <SelectItem value="Thanh to├ín mß╗Öt phß║ºn">Thanh to├ín mß╗Öt phß║ºn</SelectItem>
