      <POReceiveDialog state={handlers.receiveDialogState} branches={branches} pendingQueueLength={0} isSubmitting={handlers.isSubmittingReceive} hasValidQuantity={hasValidReceiveQty} onClose={handlers.closeReceiveDialog} onFieldChange={handlers.handleReceiveFieldChange} onBranchChange={handlers.handleReceiveBranchChange} onQuantityChange={handlers.handleReceiveQuantityChange} onSubmit={handlers.handleSubmitReceiveDialog} />
      <SimplePrintOptionsDialog open={handlers.isPrintDialogOpen} onOpenChange={handlers.closePrintDialog} onConfirm={handlers.handlePrintConfirm} selectedCount={handlers.pendingPrintPOs.length} title="In ─æ╞ín nhß║¡p h├áng" />
      <PurchaseOrderImportDialog open={importExport.showImportDialog} onOpenChange={importExport.setShowImportDialog} branches={branches.map(b => ({ systemId: b.systemId, name: b.name }))} existingData={purchaseOrders} onImport={handleImport} currentUser={{ name: loggedInUser?.fullName || 'Hß╗ç thß╗æng', systemId: loggedInUser?.systemId || asSystemId('SYSTEM') }} />
      <PurchaseOrderExportDialog open={importExport.showExportDialog} onOpenChange={importExport.setShowExportDialog} allData={purchaseOrders} filteredData={sortedData} currentPageData={paginatedData} selectedData={handlers.selectedOrders} currentUser={{ name: loggedInUser?.fullName || 'Hß╗ç thß╗æng', systemId: loggedInUser?.systemId || asSystemId('SYSTEM') }} />
    </div>
  );
