            <PageFilters searchValue={globalFilter} onSearchChange={setGlobalFilter} searchPlaceholder='T├¼m kiß║┐m phiß║┐u trß║ú h├áng (m├ú phiß║┐u, m├ú ─æ╞ín, kh├ích h├áng)...'>
                <Select value={branchFilter} onValueChange={setBranchFilter}>
