                    <SelectContent><SelectItem value='all'>Tß║Ñt cß║ú chi nh├ính</SelectItem>{branches.map(b => <SelectItem key={b.systemId} value={b.systemId}>{b.name}</SelectItem>)}</SelectContent>
                </Select>
                <DataTableFacetedFilter title='Trß║íng th├íi' options={statusOptions} selectedValues={statusFilter} onSelectedValuesChange={setStatusFilter} />
            </PageFilters>
            {isMobile ? (
