                    ) : (<>
                        {sortedData.slice(0, mobileLoadedCount).map(salesReturn => <MobileSalesReturnCard key={salesReturn.systemId} salesReturn={salesReturn} />)}
                        {mobileLoadedCount < sortedData.length && <Card className='border-dashed'><CardContent className='py-6 text-center'><div className='flex items-center justify-center gap-2'><div className='h-4 w-4 animate-spin rounded-full border-2 border-primary border-t-transparent' /><span className='text-body-sm text-muted-foreground'>─Éang tß║úi th├¬m...</span></div></CardContent></Card>}
                        {mobileLoadedCount >= sortedData.length && sortedData.length > 20 && <Card className='border-dashed'><CardContent className='py-4 text-center'><span className='text-body-sm text-muted-foreground'>─É├ú hiß╗ân thß╗ï tß║Ñt cß║ú {sortedData.length} phiß║┐u trß║ú h├áng</span></CardContent></Card>}
                    </>)}
                </div>
            ) : (
                <div className='w-full py-4'>
                    <ResponsiveDataTable columns={columns} data={paginatedData} renderMobileCard={(salesReturn) => <MobileSalesReturnCard salesReturn={salesReturn} />} pageCount={pageCount} pagination={pagination} setPagination={setPagination} rowCount={filteredData.length} rowSelection={rowSelection} setRowSelection={setRowSelection} allSelectedRows={allSelectedRows} bulkActions={bulkActions} expanded={expanded} setExpanded={setExpanded} sorting={sorting} setSorting={setSorting as React.Dispatch<React.SetStateAction<{ id: string; desc: boolean; }>>} columnVisibility={columnVisibility} setColumnVisibility={setColumnVisibility} columnOrder={columnOrder} setColumnOrder={setColumnOrder} pinnedColumns={pinnedColumns} setPinnedColumns={setPinnedColumns} onRowClick={handleRowClick} />
                </div>
            )}
            <SimplePrintOptionsDialog open={printDialogOpen} onOpenChange={setPrintDialogOpen} selectedCount={itemsToPrint.length} onConfirm={handlePrintConfirm} title="In phiß║┐u trß║ú h├áng" />
            <SalesReturnExportDialog open={exportDialogOpen} onOpenChange={setExportDialogOpen} allData={activeReturns} filteredData={sortedData} currentPageData={paginatedData} selectedData={allSelectedRows} currentUser={{ name: currentUser?.fullName || 'Hß╗ç thß╗æng', systemId: currentUser?.systemId || asSystemId('SYSTEM') }} />
