    );
}

import * as React from "react";
import { Plus, MoreHorizontal } from "lucide-react";
import { useCashAccounts, useCashAccountMutations } from "../../cashbook/hooks/use-cashbook";
import { useAllReceipts } from "../../receipts/hooks/use-all-receipts";
import { useAllPayments } from "../../payments/hooks/use-all-payments";
import { useAllBranches } from "../branches/hooks/use-all-branches";
import type { CashAccount } from "../../cashbook/types";
import { CashAccountForm, type CashAccountFormValues } from "./form";
import { Button } from "../../../components/ui/button";
import { Switch } from "../../../components/ui/switch";
import { Dialog, DialogContent, DialogFooter, DialogHeader, DialogTitle } from "../../../components/ui/dialog";
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle } from "../../../components/ui/alert-dialog";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "../../../components/ui/table";
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuLabel, DropdownMenuSeparator, DropdownMenuTrigger } from "../../../components/ui/dropdown-menu";
import { Badge } from "../../../components/ui/badge";
import { toast } from "sonner";
import { asBusinessId, asSystemId, type SystemId } from "../../../lib/id-types";
import { SettingsActionButton } from "../../../components/settings/SettingsActionButton";
import type { RegisterTabActions } from "../use-tab-action-registry";

const formatCurrency = (value: number) => new Intl.NumberFormat('vi-VN').format(value);

type CashAccountsPageContentProps = {
  isActive: boolean;
  onRegisterActions: RegisterTabActions;
};

export function CashAccountsPageContent({ isActive, onRegisterActions }: CashAccountsPageContentProps) {
  const { data: queryData } = useCashAccounts({ limit: 500 });
  const data = queryData?.data ?? [];
  const { create, update, remove, setDefault } = useCashAccountMutations({
    onSuccess: () => {},
    onError: (error) => toast.error(error.message),
  });
  const { data: receipts } = useAllReceipts();
  const { data: payments } = useAllPayments();
  const { data: branches } = useAllBranches();
  
  // T├¡nh sß╗æ d╞░ hiß╗çn tß║íi cho mß╗ùi t├ái khoß║ún
  const accountsWithBalance = React.useMemo(() => {
    return data.map(account => {
      const accountReceipts = receipts.filter(r => r.accountSystemId === account.systemId);
      const accountPayments = payments.filter(p => p.accountSystemId === account.systemId);
      
      const totalIn = accountReceipts.reduce((sum, r) => sum + r.amount, 0);
      const totalOut = accountPayments.reduce((sum, p) => sum + p.amount, 0);
      const currentBalance = account.initialBalance + totalIn - totalOut;
      
      // Kiß╗âm tra cß║únh b├ío
      const isLowBalance = account.minBalance && currentBalance < account.minBalance;
      const isHighBalance = account.maxBalance && currentBalance > account.maxBalance;
      
      return { ...account, currentBalance, isLowBalance, isHighBalance };
    });
  }, [data, receipts, payments]);
  
  const [isFormOpen, setIsFormOpen] = React.useState(false);
  const [editingItem, setEditingItem] = React.useState<CashAccount | null>(null);
  const [isAlertOpen, setIsAlertOpen] = React.useState(false);
  const [idToDelete, setIdToDelete] = React.useState<SystemId | null>(null);
  
  const handleAddNew = React.useCallback(() => {
    setEditingItem(null);
    setIsFormOpen(true);
  }, []);

  const handleEdit = React.useCallback((item: CashAccount) => { setEditingItem(item); setIsFormOpen(true); }, []);
  const handleDeleteRequest = (systemId: SystemId) => { 
    setIdToDelete(systemId);
    setIsAlertOpen(true);
  };
  
  const handleToggleStatus = async (item: CashAccount, isActive: boolean) => {
    await update.mutateAsync({ systemId: item.systemId, data: { ...item, isActive } });
    toast.success(isActive ? `─É├ú k├¡ch hoß║ít "${item.name}"` : `─É├ú tß║»t "${item.name}"`);
  };
  
  const handleToggleDefault = React.useCallback(async (item: CashAccount, checked: boolean) => {
    if (checked) {
      await setDefault.mutateAsync(item.systemId);
      toast.success(`─É├ú ─æß║╖t "${item.name}" l├ám mß║╖c ─æß╗ïnh`);
    } else {
      const otherAccounts = data.filter(a => a.systemId !== item.systemId);
      if (otherAccounts.length > 0) {
        await setDefault.mutateAsync(otherAccounts[0].systemId);
        toast.success(`─É├ú ─æß║╖t "${otherAccounts[0].name}" l├ám mß║╖c ─æß╗ïnh`);
      } else {
        toast.error('Phß║úi c├│ ├¡t nhß║Ñt mß╗Öt t├ái khoß║ún mß║╖c ─æß╗ïnh');
      }
    }
  }, [data, setDefault]);
  
  const handleSetDefault = async (item: CashAccount) => {
    await setDefault.mutateAsync(item.systemId);
    toast.success(`─É├ú ─æß║╖t "${item.name}" l├ám mß║╖c ─æß╗ïnh`);
  };
  
  const confirmDelete = async () => {
    if (idToDelete) {
      const item = data.find(a => a.systemId === idToDelete);
      await remove.mutateAsync(idToDelete);
      toast.success(`─É├ú x├│a "${item?.name}"`);
    }
    setIsAlertOpen(false);
    setIdToDelete(null);
  };
  
  const normalizeFormValues = (values: CashAccountFormValues): Omit<CashAccount, 'systemId'> => {
    const sanitizedId = values.id.trim().toUpperCase();
    const sanitizedName = values.name.trim();
    const branchId = values.branchSystemId ? asSystemId(values.branchSystemId) : undefined;
    const managerId = values.managedBy ? asSystemId(values.managedBy) : undefined;

    const trimmed = (input?: string) => {
      if (!input) return undefined;
      const next = input.trim();
      return next.length > 0 ? next : undefined;
    };

    const bankAccountNumber = trimmed(values.bankAccountNumber);
    const bankBranch = trimmed(values.bankBranch);
    const bankName = trimmed(values.bankName);
    const bankCode = trimmed(values.bankCode);
    const accountHolder = trimmed(values.accountHolder);

    return {
      id: asBusinessId(sanitizedId),
      name: sanitizedName,
      initialBalance: values.initialBalance,
      type: values.type,
      isActive: values.isActive,
      ...(values.isDefault !== undefined ? { isDefault: values.isDefault } : {}),
      ...(bankAccountNumber ? { bankAccountNumber } : {}),
      ...(bankBranch ? { bankBranch } : {}),
      ...(bankName ? { bankName } : {}),
      ...(bankCode ? { bankCode } : {}),
      ...(accountHolder ? { accountHolder } : {}),
      ...(values.minBalance !== undefined ? { minBalance: values.minBalance } : {}),
      ...(values.maxBalance !== undefined ? { maxBalance: values.maxBalance } : {}),
      ...(branchId ? { branchSystemId: branchId } : {}),
      ...(managerId ? { managedBy: managerId } : {}),
    };
  };

  const handleFormSubmit = async (values: CashAccountFormValues) => {
    try {
      const payload = normalizeFormValues(values);
      if (editingItem) {
        await update.mutateAsync({ systemId: editingItem.systemId, data: { ...editingItem, ...payload } });
        toast.success("Cß║¡p nhß║¡t th├ánh c├┤ng");
      } else {
        await create.mutateAsync(payload);
        toast.success("Th├¬m mß╗¢i th├ánh c├┤ng");
      }
      setIsFormOpen(false);
    } catch (error) {
      toast.error("C├│ lß╗ùi xß║úy ra", {
        description: error instanceof Error ? error.message : "Lß╗ùi kh├┤ng x├íc ─æß╗ïnh",
      });
    }
  };

  React.useEffect(() => {
    if (!isActive) {
      return;
    }

    onRegisterActions([
      <SettingsActionButton key="add-cash-account" onClick={handleAddNew}>
        <Plus className="mr-2 h-4 w-4" /> Th├¬m t├ái khoß║ún quß╗╣
      </SettingsActionButton>,
    ]);
  }, [handleAddNew, isActive, onRegisterActions]);

  return (
    <div className="space-y-4">
      <div className="rounded-md border">
        <Table>
          <TableHeader>
            <TableRow>
              <TableHead>M├ú t├ái khoß║ún</TableHead>
              <TableHead>T├¬n t├ái khoß║ún</TableHead>
              <TableHead>Loß║íi</TableHead>
              <TableHead>Ng├ón h├áng</TableHead>
              <TableHead>Chi nh├ính</TableHead>
              <TableHead className="text-right">Sß╗æ d╞░ hiß╗çn tß║íi</TableHead>
              <TableHead>Mß║╖c ─æß╗ïnh</TableHead>
              <TableHead>Trß║íng th├íi</TableHead>
              <TableHead className="text-right">Thao t├íc</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {accountsWithBalance.length === 0 ? (
              <TableRow>
                <TableCell colSpan={9} className="h-24 text-center">
                  Ch╞░a c├│ dß╗» liß╗çu
                </TableCell>
              </TableRow>
            ) : (
              accountsWithBalance.map((item) => {
                const branch = branches.find(b => b.systemId === item.branchSystemId);
                return (
                  <TableRow key={item.systemId}>
                    <TableCell className="font-medium">{item.id}</TableCell>
                    <TableCell className="font-medium">{item.name}</TableCell>
                    <TableCell>
                      <Badge variant={item.type === 'cash' ? 'default' : 'secondary'}>
                        {item.type === 'cash' ? 'Tiß╗ün mß║╖t' : 'Ng├ón h├áng'}
                      </Badge>
                    </TableCell>
                    <TableCell className="text-sm">
                      {item.type === 'bank' && item.bankName ? (
                        <div>
                          <div className="font-medium">{item.bankName}</div>
                          {item.bankAccountNumber && (
                            <div className="text-xs text-muted-foreground">
                              {item.bankAccountNumber}
                            </div>
                          )}
                        </div>
                      ) : 'ΓÇö'}
                    </TableCell>
                    <TableCell className="text-sm text-muted-foreground">
                      {branch?.name || 'ΓÇö'}
                    </TableCell>
                    <TableCell className="text-right">
                      <div className="font-medium">
                        {formatCurrency(item.currentBalance)}
                      </div>
                      {(item.isLowBalance || item.isHighBalance) && (
                        <div className="text-xs text-orange-600">
                          {item.isLowBalance && 'ΓÜá D╞░ß╗¢i mß╗⌐c tß╗æi thiß╗âu'}
                          {item.isHighBalance && 'ΓÜá V╞░ß╗út mß╗⌐c tß╗æi ─æa'}
                        </div>
                      )}
                    </TableCell>
                    <TableCell>
                      <Switch 
                        checked={item.isDefault} 
                        onCheckedChange={(checked) => handleToggleDefault(item, checked)}
                      />
                    </TableCell>
                    <TableCell>
                      <Switch 
                        checked={item.isActive} 
                        onCheckedChange={(checked) => handleToggleStatus(item, checked)}
                      />
                    </TableCell>
                    <TableCell className="text-right">
                      <DropdownMenu>
                        <DropdownMenuTrigger asChild>
                          <Button variant="ghost" className="h-8 w-8 p-0">
                            <span className="sr-only">Mß╗ƒ menu</span>
                            <MoreHorizontal className="h-4 w-4" />
                          </Button>
                        </DropdownMenuTrigger>
                        <DropdownMenuContent align="end">
                          <DropdownMenuLabel>Thao t├íc</DropdownMenuLabel>
                          <DropdownMenuSeparator />
                          <DropdownMenuItem onClick={() => handleEdit(item)}>
                            Chß╗ënh sß╗¡a
                          </DropdownMenuItem>
                          {!item.isDefault && (
                            <DropdownMenuItem onClick={() => handleSetDefault(item)}>
                              ─Éß║╖t l├ám mß║╖c ─æß╗ïnh
                            </DropdownMenuItem>
                          )}
                          <DropdownMenuItem
                            onClick={() => handleDeleteRequest(item.systemId)}
                            className="text-destructive"
                          >
                            X├│a
                          </DropdownMenuItem>
                        </DropdownMenuContent>
                      </DropdownMenu>
                    </TableCell>
                  </TableRow>
                );
              })
            )}
          </TableBody>
        </Table>
      </div>
      
      <Dialog open={isFormOpen} onOpenChange={setIsFormOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>{editingItem ? 'Cß║¡p nhß║¡t t├ái khoß║ún quß╗╣' : 'Th├¬m t├ái khoß║ún quß╗╣'}</DialogTitle>
          </DialogHeader>
          <CashAccountForm initialData={editingItem} onSubmit={handleFormSubmit} />
          <DialogFooter>
            <Button type="button" variant="outline" onClick={() => setIsFormOpen(false)}>Hß╗ºy</Button>
            <Button type="submit" form="cash-account-form">L╞░u</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      <AlertDialog open={isAlertOpen} onOpenChange={setIsAlertOpen}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>X├íc nhß║¡n x├│a?</AlertDialogTitle>
            <AlertDialogDescription>
              H├ánh ─æß╗Öng n├áy kh├┤ng thß╗â ho├án t├íc. T├ái khoß║ún quß╗╣ sß║╜ bß╗ï x├│a v─⌐nh viß╗àn.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Hß╗ºy</AlertDialogCancel>
            <AlertDialogAction onClick={confirmDelete}>X├│a</AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

