'use client'

import * as React from 'react';
import { useRouter, useParams } from 'next/navigation';
import { DepartmentForm, DepartmentFormValues } from './department-form';
import { useDepartment, useDepartmentMutations } from './hooks/use-departments';
import { useSettingsPageHeader } from '../use-settings-page-header';
import { Card, CardContent, CardHeader, CardTitle } from '../../../components/ui/card';
import { SettingsActionButton } from '../../../components/settings/SettingsActionButton';
import { ROUTES, generatePath } from '../../../lib/router';
import { toast } from 'sonner';

export function DepartmentFormPage() {
  const router = useRouter();
  const { id } = useParams<{ id: string }>();
  const { data: department } = useDepartment(id);
  const { create, update } = useDepartmentMutations({
    onCreateSuccess: () => {
      toast.success('Tß║ío mß╗¢i th├ánh c├┤ng');
      router.push(backPath);
    },
    onUpdateSuccess: () => {
      toast.success('Cß║¡p nhß║¡t th├ánh c├┤ng');
      router.push(backPath);
    },
    onError: (err) => toast.error(err.message)
  });
  
  const isEditMode = !!id;

  const backPath = ROUTES.HRM.DEPARTMENTS;
  const headerActions = React.useMemo(() => [
    <SettingsActionButton
      key="cancel"
      variant="outline"
      onClick={() => router.push(backPath)}
    >
      Hß╗ºy
    </SettingsActionButton>,
    <SettingsActionButton
      key="save"
      type="submit"
      form="department-form"
    >
      {isEditMode ? 'Cß║¡p nhß║¡t' : 'Tß║ío mß╗¢i'}
    </SettingsActionButton>,
  ], [backPath, router, isEditMode]);

  useSettingsPageHeader({
    title: isEditMode ? `Chß╗ënh sß╗¡a ph├▓ng ban${department?.name ? ` ΓÇó ${department.name}` : ''}` : 'Th├¬m ph├▓ng ban mß╗¢i',
    breadcrumb: [
      { label: 'Ph├▓ng ban', href: ROUTES.HRM.DEPARTMENTS, isCurrent: false },
      {
        label: isEditMode ? 'Chß╗ënh sß╗¡a' : 'Th├¬m mß╗¢i',
        href: isEditMode && id
          ? generatePath(ROUTES.HRM.DEPARTMENT_EDIT, { systemId: id })
          : ROUTES.HRM.DEPARTMENT_NEW,
        isCurrent: true,
      },
    ],
    showBackButton: true,
    backPath,
    actions: headerActions,
  });

  const handleSubmit = (values: DepartmentFormValues) => {
    if (isEditMode && department) {
      update.mutate({
        systemId: department.systemId,
        data: {
          id: values.id,
          name: values.name,
        }
      });
    } else {
      (create as any).mutate({
        id: values.id,
        name: values.name,
      });
    }
  };

  return (
    <div className="container mx-auto py-6 max-w-2xl">
      <Card>
        <CardHeader>
          <CardTitle>
            {isEditMode ? 'Chß╗ënh sß╗¡a ph├▓ng ban' : 'Th├¬m ph├▓ng ban mß╗¢i'}
          </CardTitle>
        </CardHeader>
        <CardContent>
          <DepartmentForm
            initialData={department ?? null}
            onSubmit={handleSubmit}
          />
        </CardContent>
      </Card>
    </div>
  );
}

