        </AlertDialogContent>
      </AlertDialog>
      
      <Dialog open={isFormOpen} onOpenChange={setIsFormOpen}>
          <DialogContent>
            <DialogHeader>
              <DialogTitle>{editingDepartment ? 'Chß╗ënh sß╗¡a ph├▓ng ban' : 'Th├¬m ph├▓ng ban mß╗¢i'}</DialogTitle>
              <DialogDescription>{editingDepartment ? 'Cß║¡p nhß║¡t th├┤ng tin cho ph├▓ng ban.' : '─Éiß╗ün th├┤ng tin ─æß╗â tß║ío mß╗¢i.'}</DialogDescription>
            </DialogHeader>
            <DepartmentForm 
