  const [isAlertOpen, setIsAlertOpen] = React.useState(false);
  const [idToDelete, setIdToDelete] = React.useState<SystemId | null>(null);

  const activeImporters = React.useMemo(() => data.filter(b => !b.isDeleted), [data]);
  const existingIds = React.useMemo(() => activeImporters.map(b => b.id), [activeImporters]);

  const handleAdd = React.useCallback(() => { setEditingItem(null); setDialogOpen(true); }, []);
  const handleEdit = React.useCallback((item: Importer) => { setEditingItem(item); setDialogOpen(true); }, []);
  const handleDeleteRequest = React.useCallback((systemId: SystemId) => { setIdToDelete(systemId); setIsAlertOpen(true); }, []);
  const handleToggleActive = React.useCallback((item: Importer) => { const na = !item.isActive; update.mutate({ systemId: item.systemId, data: { isActive: na } }, { onSuccess: () => toast.success(na ? '─É├ú k├¡ch hoß║ít' : '─É├ú tß║»t'), onError: (err) => toast.error(err.message) }); }, [update]);
  const handleToggleDefault = React.useCallback((item: Importer) => { if (!item.isDefault) { update.mutate({ systemId: item.systemId, data: { isDefault: true } }, { onSuccess: () => toast.success('─É├ú ─æß║╖t l├ám mß║╖c ─æß╗ïnh'), onError: (err) => toast.error(err.message) }); } }, [update]);
  const confirmDelete = () => { if (idToDelete) { remove.mutate(idToDelete, { onSuccess: () => toast.success('─É├ú x├│a ─æ╞ín vß╗ï nhß║¡p khß║⌐u'), onError: (err) => toast.error(err.message) }); } setIsAlertOpen(false); setIdToDelete(null); };

  const handleSubmit = (values: ImporterFormValues) => {
    const payload = { ...values, id: asBusinessId(values.id) };
    if (editingItem) { update.mutate({ systemId: editingItem.systemId, data: payload }, { onSuccess: () => toast.success('─É├ú cß║¡p nhß║¡t ─æ╞ín vß╗ï nhß║¡p khß║⌐u'), onError: (err) => toast.error(err.message) }); }
    else { create.mutate(payload, { onSuccess: () => toast.success('─É├ú th├¬m ─æ╞ín vß╗ï nhß║¡p khß║⌐u mß╗¢i'), onError: (err) => toast.error(err.message) }); }
    setDialogOpen(false);
  };

  const columns = React.useMemo(() => getImporterColumns({ onEdit: handleEdit, onDelete: handleDeleteRequest, onToggleActive: handleToggleActive, onToggleDefault: handleToggleDefault }), [handleDeleteRequest, handleEdit, handleToggleActive, handleToggleDefault]);

  React.useEffect(() => { if (!isActive) return; onRegisterActions([<SettingsActionButton key="add-importer" onClick={handleAdd}><Plus className="mr-2 h-4 w-4" /> Th├¬m ─æ╞ín vß╗ï nhß║¡p khß║⌐u</SettingsActionButton>]); }, [handleAdd, isActive, onRegisterActions]);

  return (
