    else { create.mutate({ ...payload, isActive: values.isActive ?? true, isDeleted: false }, { onSuccess: () => toast.success('─É├ú th├¬m ─æiß╗âm l╞░u kho mß╗¢i'), onError: (err) => toast.error(err.message) }); }
    setIsFormOpen(false);
  };

  const columns = React.useMemo(() => getStorageLocationColumns({ onEdit: handleEdit, onDelete: handleDeleteRequest, onToggleDefault: handleToggleDefault, onToggleActive: handleToggleActive }), [handleDeleteRequest, handleEdit, handleToggleDefault, handleToggleActive]);

  React.useEffect(() => { if (!isActive) return; onRegisterActions([<SettingsActionButton key="add-storage-location" onClick={handleAddNew}><Plus className="mr-2 h-4 w-4" /> Th├¬m ─æiß╗âm l╞░u kho</SettingsActionButton>]); }, [handleAddNew, isActive, onRegisterActions]);

  return (
    <>
      <Card><CardHeader className="flex flex-row items-center justify-between"><div><CardTitle>─Éiß╗âm l╞░u kho</CardTitle><CardDescription>Quß║ún l├╜ c├íc ─æiß╗âm l╞░u kho trong kho h├áng</CardDescription></div></CardHeader><CardContent><SimpleSettingsTable data={activeLocations} columns={columns} emptyTitle="Ch╞░a c├│ ─æiß╗âm l╞░u kho" emptyDescription="Th├¬m ─æiß╗âm l╞░u kho ─æß║ºu ti├¬n ─æß╗â quß║ún l├╜ vß╗ï tr├¡ h├áng h├│a" emptyAction={<Button size="sm" onClick={handleAddNew}>Th├¬m ─æiß╗âm l╞░u kho</Button>} /></CardContent></Card>
      <StorageLocationFormDialog open={isFormOpen} onOpenChange={setIsFormOpen} initialData={editingLocation} onSubmit={handleFormSubmit} existingIds={existingIds} />
      <AlertDialog open={isAlertOpen} onOpenChange={setIsAlertOpen}><AlertDialogContent><AlertDialogHeader><AlertDialogTitle>X├íc nhß║¡n x├│a</AlertDialogTitle><AlertDialogDescription>Bß║ín c├│ chß║»c chß║»n muß╗æn x├│a ─æiß╗âm l╞░u kho n├áy?</AlertDialogDescription></AlertDialogHeader><AlertDialogFooter><AlertDialogCancel onClick={() => setIsAlertOpen(false)}>Hß╗ºy</AlertDialogCancel><AlertDialogAction onClick={confirmDelete}>X├│a</AlertDialogAction></AlertDialogFooter></AlertDialogContent></AlertDialog>
