      if (otherUnits.length > 0) { const nd = otherUnits[0]; update.mutate({ systemId: unit.systemId, data: { ...unit, isDefault: false } }); update.mutate({ systemId: nd.systemId, data: { ...nd, isDefault: true } }); toast.success(`─É├ú chuyß╗ân mß║╖c ─æß╗ïnh sang "${nd.name}"`); }
