  const handleToggleActive = React.useCallback((unit: Unit) => { const na = unit.isActive === false ? true : false; update.mutate({ systemId: unit.systemId, data: { ...unit, isActive: na } }); toast.success(na ? '─É├ú k├¡ch hoß║ít' : '─É├ú tß║»t'); }, [update]);
