      <Dialog open={isFormOpen} onOpenChange={setIsFormOpen}><DialogContent><DialogHeader><DialogTitle>{editingUnit ? 'Chß╗ënh sß╗¡a ─É╞ín vß╗ï t├¡nh' : 'Th├¬m ─É╞ín vß╗ï t├¡nh'}</DialogTitle></DialogHeader><UnitForm initialData={editingUnit} onSubmit={handleFormSubmit} /><DialogFooter><Button type="button" variant="outline" onClick={() => setIsFormOpen(false)}>Hß╗ºy</Button><Button type="submit" form="unit-form">L╞░u</Button></DialogFooter></DialogContent></Dialog>
      <AlertDialog open={isAlertOpen} onOpenChange={setIsAlertOpen}><AlertDialogContent><AlertDialogHeader><AlertDialogTitle>Bß║ín c├│ chß║»c chß║»n muß╗æn x├│a?</AlertDialogTitle><AlertDialogDescription>H├ánh ─æß╗Öng n├áy kh├┤ng thß╗â ─æ╞░ß╗úc ho├án t├íc.</AlertDialogDescription></AlertDialogHeader><AlertDialogFooter><AlertDialogCancel>Hß╗ºy</AlertDialogCancel><AlertDialogAction onClick={confirmDelete}>X├│a</AlertDialogAction></AlertDialogFooter></AlertDialogContent></AlertDialog>
