    { label: "─É├ính dß║Ñu ─æ├ú thanh to├ín", onSelect: rows => { rows.forEach(p => update.mutate({ systemId: p.systemId, data: { status: "─É├ú thanh to├ín" as PenaltyStatus } })); toast.success("─É├ú cß║¡p nhß║¡t trß║íng th├íi", { description: `${rows.length} phiß║┐u phß║ít ─æ├ú chuyß╗ân sang "─É├ú thanh to├ín"` }); setRowSelection({}) } },
    { label: "Hß╗ºy phiß║┐u phß║ít", onSelect: rows => { rows.forEach(p => update.mutate({ systemId: p.systemId, data: { status: "─É├ú hß╗ºy" as PenaltyStatus } })); toast.success("─É├ú cß║¡p nhß║¡t trß║íng th├íi", { description: `${rows.length} phiß║┐u phß║ít ─æ├ú hß╗ºy` }); setRowSelection({}) } }
  ]
  const handleRowClick = (row: Penalty) => router.push(`/penalties/${row.systemId}`)

  const MobilePenaltyCard = ({ penalty }: { penalty: Penalty }) => {
    const statusVariant = { 'Ch╞░a thanh to├ín': 'warning', '─É├ú thanh to├ín': 'success', '─É├ú hß╗ºy': 'secondary' }[penalty.status] as "warning" | "success" | "secondary" || 'secondary'
    return (
      <Card className="hover:shadow-md transition-shadow cursor-pointer" onClick={() => handleRowClick(penalty)}>
