            <div className="flex items-center gap-3"><span className="font-bold text-destructive text-sm">{formatCurrency(penalty.amount)} ─æ</span>{penalty.category && <Badge variant="outline" className="text-xs">{penaltyCategoryLabels[penalty.category]}</Badge>}</div>
            <div className="flex items-center text-muted-foreground"><Calendar className="h-3 w-3 mr-1" />{formatDate(penalty.issueDate)}</div>
          </div>
          <div className="text-xs text-muted-foreground mt-2 pt-2 border-t">Ng╞░ß╗¥i lß║¡p: {penalty.issuerName}</div>
        </CardContent>
      </Card>
    )
  }

  return (
    <div className="flex flex-col w-full h-full">
