import * as React from 'react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '../../../../components/ui/card';
import { Label } from '../../../../components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '../../../../components/ui/select';
import { Button } from '../../../../components/ui/button';
import { Save } from 'lucide-react';
import { toast } from 'sonner';
import { usePkgxSettings, usePkgxPriceMappingMutations, usePkgxLogMutations } from '../hooks/use-pkgx-settings';
import { useAllPricingPolicies } from '../../pricing/hooks/use-all-pricing-policies';
import { PKGX_PRICE_FIELDS } from '../constants';
import type { SystemId } from '../../../../lib/id-types';

export function PriceMappingTab() {
  const { data: settings } = usePkgxSettings();
  const { updatePriceMapping } = usePkgxPriceMappingMutations({ onSuccess: () => {} });
  const { addLog } = usePkgxLogMutations();
  const { data: pricingPolicies = [] } = useAllPricingPolicies();

  // Filter only selling price policies
  const sellingPolicies = pricingPolicies.filter((p) => p.type === 'B├ín h├áng' && p.isActive);

  const handleChange = (field: keyof NonNullable<typeof settings>['priceMapping'], value: string) => {
    updatePriceMapping.mutate({ field, policyId: value === 'none' ? null : (value as SystemId) });
  };

  const handleSave = () => {
    // Log the mapping save
    const priceMapping = settings?.priceMapping ?? {};
    const _mappingSummary = PKGX_PRICE_FIELDS
      .filter(pf => priceMapping[pf.key as keyof NonNullable<typeof settings>['priceMapping']])
      .map(pf => {
        const policyId = priceMapping[pf.key as keyof NonNullable<typeof settings>['priceMapping']];
        const policy = pricingPolicies.find(p => p.systemId === policyId);
        return `${pf.field} ΓåÆ ${policy?.name || policyId}`;
      })
      .join(', ');
    
    addLog.mutate({
      action: 'save_mapping',
      status: 'success',
      message: '─É├ú l╞░u mapping bß║úng gi├í',
      details: {
        total: PKGX_PRICE_FIELDS.filter(pf => priceMapping[pf.key as keyof NonNullable<typeof settings>['priceMapping']]).length,
      }
    });
    
    toast.success('─É├ú l╞░u mapping bß║úng gi├í');
  };

  const getPolicyName = (policyId: SystemId | null) => {
    if (!policyId) return '-- Kh├┤ng ├íp dß╗Ñng --';
    const policy = pricingPolicies.find((p) => p.systemId === policyId);
    return policy?.name || policyId;
  };

  return (
    <Card>
      <CardHeader>
        <CardTitle className="text-lg">Mapping Bß║úng gi├í HRM ΓåÆ PKGX</CardTitle>
        <CardDescription>
          Chß╗ìn bß║úng gi├í trong HRM t╞░╞íng ß╗⌐ng vß╗¢i mß╗ùi loß║íi gi├í tr├¬n PKGX
        </CardDescription>
      </CardHeader>
      <CardContent className="space-y-6">
        {PKGX_PRICE_FIELDS.map((priceField) => (
          <div key={priceField.key} className="grid grid-cols-1 md:grid-cols-2 gap-4 items-start">
            <div>
              <Label className="text-base font-medium">{priceField.label}</Label>
              <p className="text-sm text-muted-foreground">{priceField.description}</p>
            </div>
            <Select
              value={(settings?.priceMapping ?? {})[priceField.key as keyof NonNullable<typeof settings>['priceMapping']] || 'none'}
              onValueChange={(value) => handleChange(priceField.key as keyof NonNullable<typeof settings>['priceMapping'], value)}
            >
              <SelectTrigger>
                <SelectValue placeholder="Chß╗ìn bß║úng gi├í..." />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="none">-- Kh├┤ng ├íp dß╗Ñng --</SelectItem>
                {sellingPolicies.map((policy) => (
                  <SelectItem key={policy.systemId} value={policy.systemId}>
                    {policy.name}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>
        ))}

        <div className="pt-4 border-t">
          <h4 className="font-medium mb-2">T├│m tß║»t mapping hiß╗çn tß║íi:</h4>
          <div className="bg-muted p-4 rounded-lg text-sm space-y-1">
            {PKGX_PRICE_FIELDS.map((priceField) => (
              <div key={priceField.key} className="flex justify-between">
                <span className="text-muted-foreground">{priceField.field}:</span>
                <span className="font-medium">
                  {getPolicyName((settings?.priceMapping as any)?.[priceField.key])}
                </span>
              </div>
            ))}
          </div>
        </div>

        <div className="flex justify-end pt-4">
          <Button onClick={handleSave}>
            <Save className="h-4 w-4 mr-2" />
            L╞░u mapping
          </Button>
        </div>
      </CardContent>
    </Card>
  );
}

import * as React from "react";
import { asBusinessId, type SystemId } from "@/lib/id-types";
import { usePricingPolicies, usePricingPolicyMutations } from "./hooks/use-pricing";
import type { PricingPolicy } from '@/lib/types/prisma-extended';
import { PricingPolicyForm, type PricingPolicyFormValues } from "./form";
import { PricingTable } from "./pricing-table";
import { Button } from "../../../components/ui/button";
import { Dialog, DialogContent, DialogFooter, DialogHeader, DialogTitle } from "../../../components/ui/dialog";
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle } from "../../../components/ui/alert-dialog";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "../../../components/ui/tabs";
import { toast } from 'sonner';
import { SettingsActionButton } from "../../../components/settings/SettingsActionButton";
import { PlusCircle } from "lucide-react";

interface PricingPolicyContentProps {
    isActive: boolean;
    onRegisterActions: (actions: React.ReactNode[]) => void;
}

export function PricingPolicyContent({ isActive, onRegisterActions }: PricingPolicyContentProps) {
    const { data: queryData, isLoading, error } = usePricingPolicies({ limit: 1000 });
    const data = queryData?.data ?? [];
    
    console.log('PricingPolicyContent - Query State:', { 
        isLoading, 
        hasError: !!error, 
        error,
        dataLength: data.length,
        queryData 
    });
    
    const { create, update, remove, setDefault } = usePricingPolicyMutations({
        onSuccess: () => {},
        onError: (err) => toast.error(err.message)
    });

    const [isFormOpen, setIsFormOpen] = React.useState(false);
    const [editingPolicy, setEditingPolicy] = React.useState<PricingPolicy | null>(null);
    const [isAlertOpen, setIsAlertOpen] = React.useState(false);
    const [idToDelete, setIdToDelete] = React.useState<SystemId | null>(null);
    const [innerTab, setInnerTab] = React.useState('all');

    // Register actions when tab is active or on mount
    React.useEffect(() => {
        onRegisterActions([
            <SettingsActionButton key="add" onClick={() => setIsFormOpen(true)}>
                <PlusCircle className="h-4 w-4" />
                Tß║ío ch├¡nh s├ích gi├í
            </SettingsActionButton>
        ]);
    }, [onRegisterActions]);

    const _handleAddNew = () => {
        setEditingPolicy(null);
        setIsFormOpen(true);
    };
    
    const handleEdit = React.useCallback((policy: PricingPolicy) => {
        setEditingPolicy(policy);
        setIsFormOpen(true);
    }, []);
    
    const handleDeleteRequest = React.useCallback((systemId: SystemId) => {
        setIdToDelete(systemId);
        setIsAlertOpen(true);
    }, []);
    
    const confirmDelete = () => {
        if (idToDelete) {
            const policy = data.find(p => p.systemId === idToDelete);
            remove.mutate(idToDelete, {
                onSuccess: () => toast.success(`─É├ú x├│a ch├¡nh s├ích gi├í "${policy?.name}"`),
                onError: (err) => toast.error(err.message)
            });
        }
        setIsAlertOpen(false);
        setIsFormOpen(false);
        setIdToDelete(null);
    };

    const handleFormSubmit = (values: PricingPolicyFormValues) => {
        const normalized = {
            id: asBusinessId(values.id.trim().toUpperCase()),
            name: values.name.trim(),
            description: values.description?.trim() || undefined,
            type: values.type,
            isActive: values.isActive,
            isDefault: values.isDefault,
        };

        console.log('handleFormSubmit - Creating/Updating:', normalized);

        if (editingPolicy) {
            update.mutate({ systemId: editingPolicy.systemId, data: normalized }, {
                onSuccess: (data) => {
                    console.log('Update success:', data);
                    toast.success(`─É├ú cß║¡p nhß║¡t ch├¡nh s├ích gi├í "${normalized.name}"`);
                    setIsFormOpen(false);
                },
                onError: (err) => {
                    console.error('Update error:', err);
                    toast.error(err.message);
                }
            });
        } else {
            create.mutate(normalized, {
                onSuccess: (data) => {
                    console.log('Create success:', data);
                    toast.success(`─É├ú th├¬m ch├¡nh s├ích gi├í "${normalized.name}"`);
                    setIsFormOpen(false);
                },
                onError: (err) => {
                    console.error('Create error:', err);
                    toast.error(err.message);
                }
            });
        }
    };
    
    const handleSetDefault = React.useCallback((systemId: SystemId) => {
        const policy = data.find(p => p.systemId === systemId);
        setDefault.mutate(systemId, {
            onSuccess: () => policy && toast.success(`─É├ú ─æß║╖t "${policy.name}" l├ám gi├í mß║╖c ─æß╗ïnh`),
            onError: (err) => toast.error(err.message)
        });
    }, [data, setDefault]);
    
    const handleToggleActive = React.useCallback((policy: PricingPolicy, isActive: boolean) => {
        update.mutate({ systemId: policy.systemId, data: { ...policy, isActive } }, {
            onSuccess: () => toast.success(isActive ? `─É├ú k├¡ch hoß║ít "${policy.name}"` : `─É├ú tß║»t "${policy.name}"`),
            onError: (err) => toast.error(err.message)
        });
    }, [update]);
    
    const sellingPoliciesForTab = React.useMemo(() => data.filter(p => p.type === 'B├ín h├áng'), [data]);
    const purchasingPoliciesForTab = React.useMemo(() => data.filter(p => p.type === 'Nhß║¡p h├áng'), [data]);

    return (
        <>
            <Tabs value={innerTab} onValueChange={setInnerTab} className="w-full">
                <TabsList className="grid w-full grid-cols-3">
                    <TabsTrigger value="selling">B├ín h├áng</TabsTrigger>
                    <TabsTrigger value="purchasing">Nhß║¡p h├áng</TabsTrigger>
                    <TabsTrigger value="all">Tß║Ñt cß║ú</TabsTrigger>
                </TabsList>
                <TabsContent value="selling" className="space-y-4">
                    <p className="text-sm text-muted-foreground">
                        C├íc ch├¡nh s├ích gi├í ├íp dß╗Ñng cho viß╗çc b├ín h├áng
                    </p>
                    <PricingTable
                        data={sellingPoliciesForTab}
                        allData={data}
                        onEdit={handleEdit}
                        onDelete={handleDeleteRequest}
                        onSetDefault={handleSetDefault}
                        onToggleActive={handleToggleActive}
                    />
                </TabsContent>
                <TabsContent value="purchasing" className="space-y-4">
                    <p className="text-sm text-muted-foreground">
                        C├íc ch├¡nh s├ích gi├í ├íp dß╗Ñng cho viß╗çc nhß║¡p h├áng
                    </p>
                    <PricingTable
                        data={purchasingPoliciesForTab}
                        allData={data}
                        onEdit={handleEdit}
                        onDelete={handleDeleteRequest}
                        onSetDefault={handleSetDefault}
                        onToggleActive={handleToggleActive}
                    />
                </TabsContent>
                <TabsContent value="all" className="space-y-4">
                    <p className="text-sm text-muted-foreground">
                        Tß║Ñt cß║ú c├íc ch├¡nh s├ích gi├í trong hß╗ç thß╗æng
                    </p>
                    <PricingTable
                        data={data}
                        allData={data}
                        onEdit={handleEdit}
                        onDelete={handleDeleteRequest}
                        onSetDefault={handleSetDefault}
                        onToggleActive={handleToggleActive}
                    />
                </TabsContent>
            </Tabs>

            <Dialog open={isFormOpen} onOpenChange={setIsFormOpen}>
                <DialogContent>
                    <DialogHeader>
                        <DialogTitle>{editingPolicy ? 'Cß║¡p nhß║¡t ch├¡nh s├ích gi├í' : 'Th├¬m ch├¡nh s├ích gi├í'}</DialogTitle>
                    </DialogHeader>
                    <React.Fragment key={editingPolicy?.systemId || 'new'}>
                        <PricingPolicyForm initialData={editingPolicy} onSubmit={handleFormSubmit} />
                    </React.Fragment>

                    <DialogFooter className="flex-col-reverse sm:flex-row sm:justify-between sm:space-x-2">
                        {editingPolicy && (
                            <Button 
                                type="button" 
                                variant="destructive" 
                                onClick={() => handleDeleteRequest(editingPolicy.systemId)}
                                className="sm:mr-auto h-9"
                            >
                                X├│a
                            </Button>
                        )}
                        <div className="flex flex-col-reverse gap-2 sm:flex-row sm:justify-end">
                            <Button type="button" variant="outline" onClick={() => setIsFormOpen(false)} className="h-9">
                                Tho├ít
                            </Button>
                            <Button type="submit" form="pricing-policy-form" className="h-9">
                                X├íc nhß║¡n
                            </Button>
                        </div>
                    </DialogFooter>
                </DialogContent>
            </Dialog>

            <AlertDialog open={isAlertOpen} onOpenChange={setIsAlertOpen}>
                <AlertDialogContent>
                    <AlertDialogHeader>
                        <AlertDialogTitle>Bß║ín c├│ chß║»c chß║»n muß╗æn x├│a?</AlertDialogTitle>
                        <AlertDialogDescription>H├ánh ─æß╗Öng n├áy kh├┤ng thß╗â ─æ╞░ß╗úc ho├án t├íc.</AlertDialogDescription>
                    </AlertDialogHeader>
                    <AlertDialogFooter>
                        <AlertDialogCancel className="h-9">Hß╗ºy</AlertDialogCancel>
                        <AlertDialogAction onClick={confirmDelete} className="h-9">X├│a</AlertDialogAction>
                    </AlertDialogFooter>
                </AlertDialogContent>
            </AlertDialog>
        </>
    );
}

'use client';

import * as React from "react";
import { asBusinessId, type SystemId } from "@/lib/id-types";
import { useTaxes, useTaxMutations } from "../taxes/hooks/use-taxes";
import type { Tax } from "../taxes/types";
import { TaxTable } from "./tax-table";
import { Button } from "../../../components/ui/button";
import { Dialog, DialogContent, DialogFooter, DialogHeader, DialogTitle, DialogDescription } from "../../../components/ui/dialog";
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle } from "../../../components/ui/alert-dialog";
import { Input } from "../../../components/ui/input";
import { Switch } from "../../../components/ui/switch";
import { Textarea } from "../../../components/ui/textarea";
import { toast } from 'sonner';
import { SettingsActionButton } from "../../../components/settings/SettingsActionButton";
import { PlusCircle, Percent } from "lucide-react";
import { useForm } from "react-hook-form";
import { Form, FormControl, FormDescription, FormField, FormItem, FormLabel, FormMessage } from "../../../components/ui/form";
import { NumberInput } from "../../../components/ui/number-input";

interface TaxContentProps {
    isActive: boolean;
    onRegisterActions: (actions: React.ReactNode[]) => void;
}

type TaxFormValues = {
    id: string;
    name: string;
    rate: number;
    isDefaultSale: boolean;
    isDefaultPurchase: boolean;
    description?: string;
};

export function TaxContent({ isActive, onRegisterActions }: TaxContentProps) {
    const { data: queryData } = useTaxes({ limit: 1000 });
    const data = queryData?.data ?? [];
    const { create, update, remove, setDefaultSale, setDefaultPurchase } = useTaxMutations({
        onSuccess: () => {},
        onError: (err) => toast.error(err.message)
    });

    const [isFormOpen, setIsFormOpen] = React.useState(false);
    const [editingTax, setEditingTax] = React.useState<Tax | null>(null);
    const [isAlertOpen, setIsAlertOpen] = React.useState(false);
    const [idToDelete, setIdToDelete] = React.useState<SystemId | null>(null);

    const form = useForm<TaxFormValues>({
        defaultValues: {
            id: '',
            name: '',
            rate: 0,
            isDefaultSale: false,
            isDefaultPurchase: false,
            description: '',
        },
    });

    const handleAddNew = () => {
        setEditingTax(null);
        form.reset({
            id: '',
            name: '',
            rate: 0,
            isDefaultSale: false,
            isDefaultPurchase: false,
            description: '',
        });
        setIsFormOpen(true);
    };

    // Register actions when component mounts or onRegisterActions changes
    React.useEffect(() => {
        onRegisterActions([
            <SettingsActionButton key="add" onClick={handleAddNew}>
                <PlusCircle className="h-4 w-4" />
                Th├¬m thuß║┐
            </SettingsActionButton>
        ]);
    }, [onRegisterActions]);
    
    const handleEdit = React.useCallback((tax: Tax) => {
        setEditingTax(tax);
        form.reset({
            id: tax.id,
            name: tax.name,
            rate: tax.rate,
            isDefaultSale: tax.isDefaultSale,
            isDefaultPurchase: tax.isDefaultPurchase,
            description: tax.description || '',
        });
        setIsFormOpen(true);
    }, [form]);
    
    const handleDeleteRequest = React.useCallback((systemId: SystemId) => {
        setIdToDelete(systemId);
        setIsAlertOpen(true);
    }, []);
    
    const confirmDelete = () => {
        if (idToDelete) {
            const tax = data.find(t => t.systemId === idToDelete);
            remove.mutate(idToDelete, {
                onSuccess: () => toast.success(`─É├ú x├│a thuß║┐ "${tax?.name}"`),
                onError: (err) => toast.error(err.message)
            });
        }
        setIsAlertOpen(false);
        setIsFormOpen(false);
        setIdToDelete(null);
    };

    const handleFormSubmit = (values: TaxFormValues) => {
        const payload = {
            id: asBusinessId(values.id.trim().toUpperCase()),
            name: values.name.trim(),
            rate: values.rate,
            isDefaultSale: values.isDefaultSale,
            isDefaultPurchase: values.isDefaultPurchase,
            description: values.description?.trim() || undefined,
        };
        
        if (editingTax) {
            update.mutate({ systemId: editingTax.systemId, data: payload }, {
