type ReceiptTypesPageContentProps = {
  isActive: boolean;
  onRegisterActions: RegisterTabActions;
};

export function ReceiptTypesPageContent({ isActive, onRegisterActions }: ReceiptTypesPageContentProps) {
  const { data: queryData } = useReceiptTypes({ limit: 1000 });
  const data = queryData?.data ?? [];
  const { create, update, remove } = useReceiptTypeMutations({
    onSuccess: () => toast.success("Thao t├íc th├ánh c├┤ng"),
    onError: (err) => toast.error(err.message)
  });
  
  const [isFormOpen, setIsFormOpen] = React.useState(false);
  const [editingItem, setEditingItem] = React.useState<ReceiptType | null>(null);
  const [isAlertOpen, setIsAlertOpen] = React.useState(false);
  const [idToDelete, setIdToDelete] = React.useState<SystemId | null>(null);

  const handleAddNew = React.useCallback(() => {
    setEditingItem(null);
    setIsFormOpen(true);
  }, []);
  
  const handleEdit = React.useCallback((item: ReceiptType) => {
    setEditingItem(item);
    setIsFormOpen(true);
  }, []);

  const handleDeleteRequest = React.useCallback((systemId: SystemId) => {
    setIdToDelete(systemId);
    setIsAlertOpen(true);
  }, []);
  
  const handleToggleDefault = React.useCallback((item: ReceiptType, isDefault: boolean) => {
    if (isDefault) {
      // Tß║»t mß║╖c ─æß╗ïnh cß╗ºa tß║Ñt cß║ú c├íc loß║íi kh├íc
      data.forEach(d => {
        if (d.systemId !== item.systemId && d.isDefault) {
          update.mutate({ systemId: d.systemId, data: { ...d, isDefault: false } });
        }
      });
      update.mutate({ systemId: item.systemId, data: { ...item, isDefault: true } });
      toast.success(`─É├ú ─æß║╖t "${item.name}" l├ám mß║╖c ─æß╗ïnh`);
    } else {
      const other = data.find(d => d.systemId !== item.systemId && d.isActive);
      if (other) {
        update.mutate({ systemId: item.systemId, data: { ...item, isDefault: false } });
        update.mutate({ systemId: other.systemId, data: { ...other, isDefault: true } });
        toast.success(`─É├ú chuyß╗ân mß║╖c ─æß╗ïnh sang "${other.name}"`);
      } else {
        toast.error("Phß║úi c├│ ├¡t nhß║Ñt mß╗Öt loß║íi phiß║┐u thu mß║╖c ─æß╗ïnh");
      }
    }
  }, [data, update]);

  const handleToggleStatus = React.useCallback((item: ReceiptType, isActive: boolean) => {
    update.mutate({ systemId: item.systemId, data: { ...item, isActive } });
    toast.success(isActive ? `─É├ú k├¡ch hoß║ít "${item.name}"` : `─É├ú tß║»t "${item.name}"`);
  }, [update]);
  
  const confirmDelete = () => {
    if (idToDelete) {
      const item = data.find(d => d.systemId === idToDelete);
      remove.mutate(idToDelete);
      toast.success(`─É├ú x├│a "${item?.name}"`);
    }
    setIsAlertOpen(false);
    setIdToDelete(null);
  };
  
  const handleFormSubmit = (values: ReceiptTypeFormValues) => {
    try {
      const now = new Date().toISOString();
      const normalized = {
        id: asBusinessId(values.id.trim().toUpperCase()),
        name: values.name.trim(),
        description: values.description?.trim() || undefined,
        isBusinessResult: values.isBusinessResult,
        isActive: values.isActive,
        color: values.color?.trim() || undefined,
      } satisfies Omit<ReceiptType, 'systemId' | 'createdAt'>;

      if (editingItem) {
        update.mutate({
          systemId: editingItem.systemId,
          data: {
            ...editingItem,
            ...normalized,
          }
        });
      } else {
        create.mutate({
          ...normalized,
          createdAt: now,
        });
      }
      setIsFormOpen(false);
    } catch (error) {
      toast.error("C├│ lß╗ùi xß║úy ra", {
        description: error instanceof Error ? error.message : "Lß╗ùi kh├┤ng x├íc ─æß╗ïnh",
      });
    }
  };

  const columns = React.useMemo(
    () =>
      getReceiptTypeColumns({
        onEdit: handleEdit,
        onToggleDefault: handleToggleDefault,
        onToggleStatus: handleToggleStatus,
        onDelete: handleDeleteRequest,
      }),
    [handleEdit, handleToggleDefault, handleToggleStatus, handleDeleteRequest]
  );

  React.useEffect(() => {
    if (!isActive) {
      return;
    }

    onRegisterActions([
      <SettingsActionButton key="add-receipt-type" onClick={handleAddNew}>
        <Plus className="mr-2 h-4 w-4" /> Th├¬m loß║íi phiß║┐u thu
      </SettingsActionButton>,
    ]);
  }, [handleAddNew, isActive, onRegisterActions]);

  return (
    <div className="space-y-4">
      <div className="rounded-md border bg-background">
        <SimpleSettingsTable
          data={data}
          columns={columns}
          emptyTitle="Ch╞░a c├│ dß╗» liß╗çu"
          emptyDescription="Th├¬m loß║íi phiß║┐u thu ─æß║ºu ti├¬n ─æß╗â bß║»t ─æß║ºu cß║Ñu h├¼nh"
          emptyAction={
            <Button size="sm" onClick={handleAddNew}>
              Th├¬m loß║íi mß╗¢i
            </Button>
          }
        />
      </div>
      <Dialog open={isFormOpen} onOpenChange={setIsFormOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>{editingItem ? 'Cß║¡p nhß║¡t loß║íi phiß║┐u thu' : 'Th├¬m loß║íi phiß║┐u thu'}</DialogTitle>
          </DialogHeader>
          <ReceiptTypeForm initialData={editingItem} onSubmit={handleFormSubmit} />
          <DialogFooter>
            <Button type="button" variant="outline" className="h-9" onClick={() => setIsFormOpen(false)}>─É├│ng</Button>
            <Button type="submit" form="receipt-type-form" className="h-9">L╞░u</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      <AlertDialog open={isAlertOpen} onOpenChange={setIsAlertOpen}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>X├íc nhß║¡n x├│a?</AlertDialogTitle>
            <AlertDialogDescription>
              H├ánh ─æß╗Öng n├áy kh├┤ng thß╗â ho├án t├íc. Loß║íi phiß║┐u thu sß║╜ bß╗ï x├│a v─⌐nh viß╗àn.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Hß╗ºy</AlertDialogCancel>
            <AlertDialogAction onClick={confirmDelete}>X├│a</AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

