    toast.success(isActive ? "─É├ú k├¡ch hoß║ít" : "─É├ú ngß╗½ng hoß║ít ─æß╗Öng");
  }, [data, update]);
  
  const confirmDelete = () => {
    if (idToDelete) {
      remove.mutate(idToDelete, {
        onSuccess: () => toast.success("─É├ú x├│a th├ánh c├┤ng"),
        onError: (err) => toast.error(err.message)
      });
    }
    setIsAlertOpen(false);
    setIdToDelete(null);
  };
  
  const handleFormSubmit = (values: TargetGroupFormValues) => {
    try {
      const name = values.name.trim();
      const normalizedId = values.id?.trim().toUpperCase();
      if (editingItem) {
        update.mutate({
          systemId: editingItem.systemId,
          data: {
            name,
            id: normalizedId ? asBusinessId(normalizedId) : editingItem.id,
          }
        }, {
          onSuccess: () => toast.success("Cß║¡p nhß║¡t th├ánh c├┤ng"),
          onError: (err) => toast.error(err.message)
        });
      } else {
        create.mutate({
          id: normalizedId ? asBusinessId(normalizedId) : asBusinessId(""),
          name,
          isActive: true,
        }, {
          onSuccess: () => toast.success("Th├¬m mß╗¢i th├ánh c├┤ng"),
          onError: (err) => toast.error(err.message)
        });
      }
      setIsFormOpen(false);
    } catch (error) {
      toast.error("C├│ lß╗ùi xß║úy ra", {
        description: error instanceof Error ? error.message : "Lß╗ùi kh├┤ng x├íc ─æß╗ïnh",
      });
    }
  };

  React.useEffect(() => {
    if (!isActive) {
      return;
    }

    onRegisterActions([
      <SettingsActionButton key="add-target-group" onClick={handleAddNew}>
        <Plus className="mr-2 h-4 w-4" /> Th├¬m nh├│m ─æß╗æi t╞░ß╗úng
      </SettingsActionButton>,
    ]);
  }, [handleAddNew, isActive, onRegisterActions]);

  const columns = React.useMemo(
    () => getTargetGroupColumns({
      onEdit: handleEdit,
      onDelete: handleDeleteRequest,
      onToggleStatus: handleToggleStatus,
      onToggleDefault: handleToggleDefault,
    }),
    [handleEdit, handleDeleteRequest, handleToggleStatus, handleToggleDefault]
  );

  return (
    <div className="space-y-4">
      <div className="rounded-md border">
        <SimpleSettingsTable
          data={data}
          columns={columns}
          emptyTitle="Ch╞░a c├│ nh├│m ─æß╗æi t╞░ß╗úng"
          emptyDescription="Th├¬m nh├│m ─æß╗æi t╞░ß╗úng ─æß║ºu ti├¬n ─æß╗â ph├ón loß║íi"
          emptyAction={
            <Button size="sm" onClick={handleAddNew}>
              Th├¬m nh├│m ─æß╗æi t╞░ß╗úng
            </Button>
          }
        />
      </div>
      
      <Dialog open={isFormOpen} onOpenChange={setIsFormOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>{editingItem ? 'Cß║¡p nhß║¡t nh├│m ─æß╗æi t╞░ß╗úng' : 'Th├¬m nh├│m ─æß╗æi t╞░ß╗úng'}</DialogTitle>
          </DialogHeader>
          <TargetGroupForm initialData={editingItem} onSubmit={handleFormSubmit} />
          <DialogFooter>
            <Button type="button" variant="outline" onClick={() => setIsFormOpen(false)}>Hß╗ºy</Button>
            <Button type="submit" form="target-group-form">L╞░u</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      <AlertDialog open={isAlertOpen} onOpenChange={setIsAlertOpen}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>X├íc nhß║¡n x├│a?</AlertDialogTitle>
            <AlertDialogDescription>
              H├ánh ─æß╗Öng n├áy kh├┤ng thß╗â ho├án t├íc. Nh├│m ─æß╗æi t╞░ß╗úng sß║╜ bß╗ï x├│a v─⌐nh viß╗àn.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Hß╗ºy</AlertDialogCancel>
            <AlertDialogAction onClick={confirmDelete}>X├│a</AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

