import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '../../../../components/ui/select';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '../../../../components/ui/table';
import { Plus, Trash2, RefreshCw, Loader2 } from 'lucide-react';
import { toast } from 'sonner';
import { useTrendtechSettings, useTrendtechBrandMappingMutations, useTrendtechLogMutations, useTrendtechBrandMutations } from '../hooks/use-trendtech-settings';
import { useActiveBrands } from '@/features/brands/hooks/use-all-brands';
import { nanoid } from 'nanoid';
import { asSystemId } from '@/lib/id-types';

export function BrandMappingTab() {
  const { data: settings } = useTrendtechSettings();
  const { addBrandMapping, deleteBrandMapping } = useTrendtechBrandMappingMutations({
    onSuccess: () => {},
  });
  const { setBrands } = useTrendtechBrandMutations({
    onSuccess: () => {},
  });
  const { addLog } = useTrendtechLogMutations();
  const { data: hrmBrands = [] } = useActiveBrands();
  const [isSyncing, setIsSyncing] = React.useState(false);
  const trendtechBrands = settings?.brands ?? [];
  const mappings = settings?.brandMappings ?? [];

  // Get unmapped HRM brands
  const unmappedHrmBrands = React.useMemo(() => {
    const mappedIds = new Set(mappings.map((m) => m.hrmBrandSystemId));
    return hrmBrands.filter((b) => !mappedIds.has(asSystemId(b.systemId)));
  }, [hrmBrands, mappings]);

  const handleSyncBrands = async () => {
    setIsSyncing(true);
    try {
      // TODO: Fetch brands from Trendtech API
      // const brands = await fetchTrendtechBrands();
      // await setBrands.mutateAsync(brands);
      toast.success('─É├ú ─æß╗ông bß╗Ö danh s├ích th╞░╞íng hiß╗çu tß╗½ Trendtech');
    } catch (error) {
      toast.error('Lß╗ùi ─æß╗ông bß╗Ö th╞░╞íng hiß╗çu: ' + (error instanceof Error ? error.message : 'Unknown'));
    } finally {
      setIsSyncing(false);
    }
  };

  const handleAddMapping = (hrmBrandId: string, trendtechBrandId: string) => {
    const hrmBrand = hrmBrands.find((b) => b.systemId === hrmBrandId);
    const trendtechBrand = trendtechBrands.find((b) => b.id === parseInt(trendtechBrandId, 10));
    
    if (!hrmBrand || !trendtechBrand) return;
    
    addBrandMapping.mutate({
      id: nanoid(),
      hrmBrandSystemId: asSystemId(hrmBrand.systemId),
      hrmBrandName: hrmBrand.name,
      trendtechBrandId: trendtechBrand.id,
      trendtechBrandName: trendtechBrand.name,
    });
    
    addLog.mutate({
      action: 'save_mapping',
      status: 'success',
      message: `─É├ú mapping: ${hrmBrand.name} ΓåÆ ${trendtechBrand.name}`,
      details: { brandId: trendtechBrand.id },
    });
    
    toast.success(`─É├ú mapping: ${hrmBrand.name} ΓåÆ ${trendtechBrand.name}`);
  };

  const handleDeleteMapping = (id: string) => {
    const mapping = mappings.find((m) => m.id === id);
    deleteBrandMapping.mutate(id);
    
    addLog.mutate({
      action: 'save_mapping',
      status: 'info',
      message: `─É├ú x├│a mapping: ${mapping?.hrmBrandName}`,
      details: {},
    });
    
    toast.success('─É├ú x├│a mapping');
  };

  return (
    <div className="space-y-6">
      {/* Sync Card */}
      <Card>
        <CardHeader>
          <CardTitle className="text-lg">Danh s├ích th╞░╞íng hiß╗çu Trendtech</CardTitle>
          <CardDescription>
            ─Éß╗ông bß╗Ö danh s├ích th╞░╞íng hiß╗çu tß╗½ website Trendtech
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm">Sß╗æ th╞░╞íng hiß╗çu: <Badge>{trendtechBrands.length}</Badge></p>
            </div>
            <Button onClick={handleSyncBrands} disabled={isSyncing || !settings?.enabled}>
              {isSyncing ? (
                <><Loader2 className="h-4 w-4 mr-2 animate-spin" />─Éang ─æß╗ông bß╗Ö...</>
              ) : (
                <><RefreshCw className="h-4 w-4 mr-2" />─Éß╗ông bß╗Ö tß╗½ Trendtech</>
              )}
            </Button>
          </div>
          
          {!settings?.enabled && (
            <p className="text-sm text-amber-600">
              Vui l├▓ng bß║¡t t├¡ch hß╗úp Trendtech trong tab Cß║Ñu h├¼nh chung ─æß╗â ─æß╗ông bß╗Ö
            </p>
          )}
        </CardContent>
      </Card>

      {/* Mapping Table */}
      <Card>
        <CardHeader>
          <CardTitle className="text-lg">Mapping th╞░╞íng hiß╗çu</CardTitle>
          <CardDescription>
            Li├¬n kß║┐t th╞░╞íng hiß╗çu HRM vß╗¢i th╞░╞íng hiß╗çu Trendtech
          </CardDescription>
        </CardHeader>
        <CardContent>
          {mappings.length === 0 ? (
            <div className="text-center py-8 text-muted-foreground">
              Ch╞░a c├│ mapping n├áo. Th├¬m mapping b├¬n d╞░ß╗¢i.
            </div>
          ) : (
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Th╞░╞íng hiß╗çu HRM</TableHead>
                  <TableHead>ΓåÆ</TableHead>
                  <TableHead>Th╞░╞íng hiß╗çu Trendtech</TableHead>
                  <TableHead className="w-[100px]">Thao t├íc</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {mappings.map((mapping) => (
                  <TableRow key={mapping.id}>
                    <TableCell>{mapping.hrmBrandName}</TableCell>
                    <TableCell>ΓåÆ</TableCell>
                    <TableCell>
                      {mapping.trendtechBrandName}
                      <Badge variant="outline" className="ml-2">ID: {mapping.trendtechBrandId}</Badge>
                    </TableCell>
                    <TableCell>
                      <Button
                        variant="ghost"
                        size="icon"
                        onClick={() => handleDeleteMapping(mapping.id)}
                      >
                        <Trash2 className="h-4 w-4 text-red-500" />
                      </Button>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          )}
        </CardContent>
      </Card>

      {/* Add Mapping Card */}
      <Card>
        <CardHeader>
          <CardTitle className="text-lg">Th├¬m mapping mß╗¢i</CardTitle>
        </CardHeader>
        <CardContent>
          <AddMappingForm
            unmappedHrmBrands={unmappedHrmBrands}
            trendtechBrands={trendtechBrands.map(b => ({ id: String(b.id), name: b.name }))}
            onAdd={handleAddMapping}
          />
        </CardContent>
      </Card>
    </div>
  );
}

function AddMappingForm({
  unmappedHrmBrands,
  trendtechBrands,
  onAdd,
}: {
  unmappedHrmBrands: Array<{ systemId: string; name: string }>;
  trendtechBrands: Array<{ id: string; name: string }>;
  onAdd: (hrmId: string, trendtechId: string) => void;
}) {
  const [selectedHrm, setSelectedHrm] = React.useState('');
  const [selectedTrendtech, setSelectedTrendtech] = React.useState('');

  const handleAdd = () => {
    if (selectedHrm && selectedTrendtech) {
      onAdd(selectedHrm, selectedTrendtech);
      setSelectedHrm('');
      setSelectedTrendtech('');
    }
  };

  return (
    <div className="flex items-end gap-4">
      <div className="flex-1 space-y-2">
        <label className="text-sm font-medium">Th╞░╞íng hiß╗çu HRM</label>
        <Select value={selectedHrm} onValueChange={setSelectedHrm}>
          <SelectTrigger>
            <SelectValue placeholder="Chß╗ìn th╞░╞íng hiß╗çu HRM..." />
          </SelectTrigger>
          <SelectContent>
            {unmappedHrmBrands.map((brand) => (
              <SelectItem key={brand.systemId} value={brand.systemId}>
                {brand.name}
              </SelectItem>
            ))}
          </SelectContent>
        </Select>
      </div>

      <div className="flex-1 space-y-2">
        <label className="text-sm font-medium">Th╞░╞íng hiß╗çu Trendtech</label>
        <Select value={selectedTrendtech} onValueChange={setSelectedTrendtech}>
          <SelectTrigger>
            <SelectValue placeholder="Chß╗ìn th╞░╞íng hiß╗çu Trendtech..." />
          </SelectTrigger>
          <SelectContent>
            {trendtechBrands.map((brand) => (
              <SelectItem key={brand.id} value={brand.id.toString()}>
                {brand.name} (ID: {brand.id})
              </SelectItem>
            ))}
          </SelectContent>
        </Select>
      </div>

      <Button onClick={handleAdd} disabled={!selectedHrm || !selectedTrendtech}>
        <Plus className="h-4 w-4 mr-2" />
        Th├¬m
      </Button>
    </div>
  );
}

