            <SelectValue placeholder="Chß╗ìn danh mß╗Ñc HRM..." />
          </SelectTrigger>
          <SelectContent>
            {unmappedHrmCategories.map((cat) => (
              <SelectItem key={cat.systemId} value={cat.systemId}>
                {cat.name}
              </SelectItem>
            ))}
          </SelectContent>
        </Select>
      </div>

      <div className="flex-1 space-y-2">
        <label className="text-sm font-medium">Danh mß╗Ñc Trendtech</label>
        <Select value={selectedTrendtech} onValueChange={setSelectedTrendtech}>
          <SelectTrigger>
            <SelectValue placeholder="Chß╗ìn danh mß╗Ñc Trendtech..." />
          </SelectTrigger>
          <SelectContent>
            {trendtechCategories.map((cat) => (
              <SelectItem key={cat.id} value={cat.id.toString()}>
                {cat.name} (ID: {cat.id})
              </SelectItem>
            ))}
          </SelectContent>
        </Select>
      </div>

      <Button onClick={handleAdd} disabled={!selectedHrm || !selectedTrendtech}>
        <Plus className="h-4 w-4 mr-2" />
        Th├¬m
      </Button>
    </div>
  );
}

