          details: { 
            url: localApiUrl, 
            responseTime: Date.now() - testStartTime,
            total: stats?.totalProducts || 0,
          },
        });
        toast.success(`Kß║┐t nß╗æi th├ánh c├┤ng! Sß║ún phß║⌐m: ${stats?.totalProducts || 0}, Danh mß╗Ñc: ${stats?.totalCategories || 0}`);
      } else {
        setConnectionStatus.mutate({ status: 'error', error: testResult.error });
        addLog.mutate({
          action: 'test_connection',
          status: 'error',
          message: `Lß╗ùi x├íc thß╗▒c: ${testResult.error}`,
          details: { url: localApiUrl, error: testResult.error },
        });
        toast.error(`Lß╗ùi: ${testResult.error}`);
      }
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : 'Kh├┤ng thß╗â kß║┐t nß╗æi';
      setConnectionStatus.mutate({ status: 'error', error: errorMessage });
      addLog.mutate({
        action: 'test_connection',
        status: 'error',
        message: `Lß╗ùi kß║┐t nß╗æi: ${errorMessage}`,
        details: { error: errorMessage, responseTime: Date.now() - startTime },
      });
      toast.error(`Kh├┤ng thß╗â kß║┐t nß╗æi ─æß║┐n server Trendtech: ${errorMessage}`);
    } finally {
      setIsTesting(false);
    }
  };
  
  const getStatusBadge = () => {
    switch (settings?.connectionStatus) {
      case 'connected':
        return <Badge variant="default" className="bg-green-500"><CheckCircle2 className="h-3 w-3 mr-1" />─É├ú kß║┐t nß╗æi</Badge>;
      case 'error':
        return <Badge variant="destructive"><XCircle className="h-3 w-3 mr-1" />Lß╗ùi kß║┐t nß╗æi</Badge>;
      default:
        return <Badge variant="secondary">Ch╞░a kß║┐t nß╗æi</Badge>;
    }
  };

  return (
    <div className="space-y-6">
      {/* API Connection Card */}
      <Card>
        <CardHeader>
          <CardTitle className="text-lg">Th├┤ng tin kß║┐t nß╗æi API</CardTitle>
          <CardDescription>Cß║Ñu h├¼nh kß║┐t nß╗æi vß╗¢i website Trendtech (Next.js)</CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="space-y-2">
            <Label htmlFor="apiUrl">API URL</Label>
            <Input
              id="apiUrl"
              value={localApiUrl}
              onChange={(e) => setLocalApiUrl(e.target.value)}
              placeholder="https://trendtech.vn/api/hrm"
            />
            <p className="text-sm text-muted-foreground">
              URL API endpoint cß╗ºa Trendtech (VD: https://trendtech.vn/api/hrm)
            </p>
          </div>
          
          <div className="space-y-2">
            <Label htmlFor="apiKey">API Key</Label>
            <div className="flex gap-2">
              <div className="relative flex-1">
                <Input
                  id="apiKey"
                  type={showApiKey ? 'text' : 'password'}
                  value={localApiKey}
                  onChange={(e) => setLocalApiKey(e.target.value)}
                  placeholder="Nhß║¡p API Key..."
                  className="pr-10"
                />
                <Button
                  type="button"
                  variant="ghost"
                  size="icon"
                  className="absolute right-0 top-0 h-full"
                  onClick={() => setShowApiKey(!showApiKey)}
                >
                  {showApiKey ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                </Button>
              </div>
            </div>
          </div>
          
          <div className="flex items-center gap-2 pt-2">
            <Button onClick={handleSaveConfig} variant="default">
              <Save className="h-4 w-4 mr-2" />
              L╞░u cß║Ñu h├¼nh
            </Button>
            <Button onClick={handleTestConnection} variant="outline" disabled={isTesting}>
              {isTesting ? (
                <Loader2 className="h-4 w-4 mr-2 animate-spin" />
              ) : (
                <RefreshCw className="h-4 w-4 mr-2" />
              )}
              Test Connection
            </Button>
          </div>
          
          <div className="flex items-center gap-2 pt-2">
            <span className="text-sm text-muted-foreground">Trß║íng th├íi:</span>
            {getStatusBadge()}
          </div>
        </CardContent>
      </Card>

      {/* Integration Status Card */}
      <Card>
        <CardHeader>
          <CardTitle className="text-lg">Trß║íng th├íi t├¡ch hß╗úp</CardTitle>
          <CardDescription>Bß║¡t/tß║»t ─æß╗ông bß╗Ö vß╗¢i Trendtech</CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="flex items-center justify-between">
            <div>
              <Label className="text-base">Bß║¡t t├¡ch hß╗úp Trendtech</Label>
              <p className="text-sm text-muted-foreground">Cho ph├⌐p ─æß╗ông bß╗Ö sß║ún phß║⌐m vß╗¢i website</p>
            </div>
            <Switch
              checked={settings?.enabled ?? false}
              onCheckedChange={(checked) => {
                setEnabled.mutate(checked);
                addLog.mutate({
                  action: 'save_config',
                  status: 'info',
                  message: checked ? '─É├ú bß║¡t t├¡ch hß╗úp Trendtech' : '─É├ú tß║»t t├¡ch hß╗úp Trendtech',
                  details: {},
                });
                toast.success(checked ? '─É├ú bß║¡t t├¡ch hß╗úp Trendtech' : '─É├ú tß║»t t├¡ch hß╗úp Trendtech');
              }}
            />
          </div>
          
          <div className="flex items-center justify-between">
            <div>
              <Label className="text-base">Bß║¡t Auto Sync</Label>
              <p className="text-sm text-muted-foreground">Tß╗▒ ─æß╗Öng ─æß╗ông bß╗Ö dß╗» liß╗çu theo lß╗ïch</p>
            </div>
            <Switch
              checked={settings?.syncSettings?.autoSyncEnabled ?? false}
              onCheckedChange={(checked) => {
                updateSyncSetting.mutate({ key: 'autoSyncEnabled', value: checked });
