// ============================================

export function WarrantySettingsPage() {
  const [activeTab, setActiveTab] = React.useState('sla');
  const { headerActions, registerActions } = useTabActionRegistry(activeTab);

  // Fetch settings from React Query
  const { data: settings, isLoading: isLoadingSettings } = useWarrantySettings();
  const { updateSection } = useWarrantySettingsMutations();

  const registerSlaActions = React.useMemo(() => registerActions('sla'), [registerActions]);
  const registerTemplateActions = React.useMemo(() => registerActions('templates'), [registerActions]);
  const registerNotificationActions = React.useMemo(() => registerActions('notifications'), [registerActions]);
  const registerPublicTrackingActions = React.useMemo(() => registerActions('public-tracking'), [registerActions]);
  const registerCardColorActions = React.useMemo(() => registerActions('card-colors'), [registerActions]);

  // Get stored values from React Query
  const storedSla = settings.sla;
  const storedTemplates = settings.templates as ResponseTemplate[];
  const storedNotifications = settings.notifications;
  const storedPublicTracking = settings.publicTracking;
  const storedCardColors = settings.cardColors;

  // SLA State - cast to proper type
  const [sla, setSLA] = React.useState<SLASettings>(storedSla as any);

  // Templates State
  const [templates, setTemplates] = React.useState<ResponseTemplate[]>(storedTemplates);
  const [editingTemplate, setEditingTemplate] = React.useState<ResponseTemplate | null>(null);
  const [isAddingTemplate, setIsAddingTemplate] = React.useState(false);
  const [showDeleteDialog, setShowDeleteDialog] = React.useState(false);
  const [templateToDelete, setTemplateToDelete] = React.useState<string | null>(null);
  const [showEditDialog, setShowEditDialog] = React.useState(false);

  // Notifications State
  const [notifications, setNotifications] = React.useState<NotificationSettings>(storedNotifications as any);

  // Public Tracking State
  const [publicTracking, setPublicTracking] = React.useState<PublicTrackingSettings>(storedPublicTracking);

  // Card Colors State
  const [cardColors, setCardColors] = React.useState<CardColorSettings>(storedCardColors as any);

  React.useEffect(() => {
    setSLA(storedSla as any);
  }, [storedSla]);

  React.useEffect(() => {
    setTemplates(storedTemplates);
  }, [storedTemplates]);

  React.useEffect(() => {
    setNotifications(storedNotifications as any);
  }, [storedNotifications]);

  React.useEffect(() => {
    setPublicTracking(storedPublicTracking);
  }, [storedPublicTracking]);

  React.useEffect(() => {
    setCardColors(storedCardColors as any);
  }, [storedCardColors]);

  useSettingsPageHeader({
    title: 'C├ái ─æß║╖t bß║úo h├ánh',
    actions: headerActions,
  });

  // ============================================
  // SLA HANDLERS
  // ============================================

  const handleSLAChange = (priority: keyof SLASettings, field: 'responseTime' | 'resolveTime', value: string) => {
    const numValue = parseInt(value) || 0;
    setSLA(prev => ({
      ...prev,
      [priority]: {
        ...prev[priority],
        [field]: numValue,
      }
    }));
  };

  const handleSaveSLA = () => {
    // Validation
    const priorities: Array<keyof SLASettings> = ['low', 'medium', 'high', 'urgent'];
    for (const priority of priorities) {
      if (sla[priority].responseTime <= 0) {
        toast.error('Lß╗ùi validation', {
          description: `Thß╗¥i gian phß║ún hß╗ôi cho mß╗⌐c ${priority} phß║úi lß╗¢n h╞ín 0`,
        });
        return;
      }
      if (sla[priority].resolveTime <= 0) {
        toast.error('Lß╗ùi validation', {
          description: `Thß╗¥i gian xß╗¡ l├╜ cho mß╗⌐c ${priority} phß║úi lß╗¢n h╞ín 0`,
        });
        return;
      }
    }

    updateSection.mutate(
      { type: 'sla-targets', data: sla as any },
      {
        onSuccess: () => {
          toast.success('─É├ú l╞░u c├ái ─æß║╖t SLA', {
            description: 'Thß╗¥i gian phß║ún hß╗ôi v├á giß║úi quyß║┐t ─æ├ú ─æ╞░ß╗úc cß║¡p nhß║¡t.',
          });
        },
      }
    );
  };

  const _handleResetSLA = () => {
    const defaults = clone(defaultSLA);
    setSLA(defaults);
    updateSection.mutate(
      { type: 'sla-targets', data: defaults as any },
      {
        onSuccess: () => {
          toast.info('─É├ú ─æß║╖t lß║íi mß║╖c ─æß╗ïnh', {
            description: 'C├ái ─æß║╖t SLA ─æ├ú ─æ╞░ß╗úc kh├┤i phß╗Ñc vß╗ü gi├í trß╗ï mß║╖c ─æß╗ïnh.',
          });
        },
      }
    );
  };

  // ============================================
  // TEMPLATE HANDLERS
  // ============================================

  const handleAddTemplate = () => {
    setEditingTemplate({
      id: Date.now().toString(),
      name: '',
      content: '',
      category: 'general',
      order: templates.length + 1,
    });
    setIsAddingTemplate(true);
    setShowEditDialog(true);
  };

  const handleSaveTemplate = () => {
    if (!editingTemplate) return;

    // Validation
    if (!editingTemplate.name.trim()) {
      toast.error('Lß╗ùi validation', {
        description: 'Vui l├▓ng nhß║¡p t├¬n mß║½u.',
      });
      return;
    }

    if (!editingTemplate.content.trim()) {
      toast.error('Lß╗ùi validation', {
        description: 'Vui l├▓ng nhß║¡p nß╗Öi dung mß║½u.',
      });
      return;
    }

    let updatedTemplates: ResponseTemplate[];
    
    if (isAddingTemplate) {
      updatedTemplates = [...templates, editingTemplate];
    } else {
      updatedTemplates = templates.map(t => 
        t.id === editingTemplate.id ? editingTemplate : t
      );
    }

    setTemplates(updatedTemplates);
    updateSection.mutate(
      { type: 'reminder-templates', data: updatedTemplates },
      {
        onSuccess: () => {
          toast.success(isAddingTemplate ? '─É├ú th├¬m mß║½u' : '─É├ú cß║¡p nhß║¡t mß║½u', {
            description: `Mß║½u "${editingTemplate.name}" ─æ├ú ─æ╞░ß╗úc l╞░u.`,
          });
        },
      }
    );

    setEditingTemplate(null);
    setIsAddingTemplate(false);
    setShowEditDialog(false);
  };

  const handleDeleteTemplate = (id: string) => {
    setTemplateToDelete(id);
    setShowDeleteDialog(true);
  };

  const confirmDeleteTemplate = () => {
    if (!templateToDelete) return;
    
    const template = templates.find(t => t.id === templateToDelete);
    const updatedTemplates = templates.filter(t => t.id !== templateToDelete);
    setTemplates(updatedTemplates);
    updateSection.mutate(
      { type: 'reminder-templates', data: updatedTemplates },
      {
        onSuccess: () => {
          toast.success('─É├ú x├│a mß║½u', {
            description: `Mß║½u "${template?.name}" ─æ├ú ─æ╞░ß╗úc x├│a.`,
          });
        },
      }
    );
    
    setShowDeleteDialog(false);
    setTemplateToDelete(null);
  };

  const handleCancelEdit = () => {
    setEditingTemplate(null);
    setIsAddingTemplate(false);
    setShowEditDialog(false);
  };

  // ============================================
  // NOTIFICATION HANDLERS
  // ============================================

  const handleNotificationChange = (key: keyof NotificationSettings) => {
    setNotifications(prev => ({
      ...prev,
      [key]: !prev[key],
    }));
  };

  const handleSaveNotifications = () => {
    updateSection.mutate(
      { type: 'notifications', data: notifications as any },
      {
        onSuccess: () => {
          toast.success('─É├ú l╞░u c├ái ─æß║╖t th├┤ng b├ío', {
            description: 'C├íc t├╣y chß╗ìn th├┤ng b├ío ─æ├ú ─æ╞░ß╗úc cß║¡p nhß║¡t.',
          });
        },
      }
    );
  };

  // ============================================
  // PUBLIC TRACKING HANDLERS
  // ============================================

  const handlePublicTrackingChange = (key: keyof PublicTrackingSettings) => {
    setPublicTracking(prev => ({
      ...prev,
      [key]: !prev[key],
    }));
  };

  const handleSavePublicTracking = () => {
    updateSection.mutate(
      { type: 'tracking', data: publicTracking },
      {
        onSuccess: () => {
          // Show different message based on enabled state
          if (publicTracking.enabled) {
            toast.success('─É├ú bß║¡t tracking c├┤ng khai', {
              description: 'Kh├ích h├áng giß╗¥ c├│ thß╗â theo d├╡i tiß║┐n ─æß╗Ö bß║úo h├ánh qua link c├┤ng khai.',
            });
          } else {
            toast.success('─É├ú tß║»t tracking c├┤ng khai', {
              description: 'T├¡nh n─âng tracking c├┤ng khai ─æ├ú ─æ╞░ß╗úc v├┤ hiß╗çu h├│a.',
            });
          }
        },
      }
    );
  };

  // ============================================
  // CARD COLOR HANDLERS
  // ============================================

  const handleCardColorChange = (category: 'statusColors' | 'overdueColor', key: string, value: string) => {
    if (category === 'overdueColor') {
      setCardColors(prev => ({ ...prev, overdueColor: value }));
    } else {
      setCardColors(prev => ({
        ...prev,
        statusColors: { ...prev.statusColors, [key]: value }
      }));
    }
  };

  const handleCardColorToggle = (key: 'enableStatusColors' | 'enableOverdueColor') => {
    setCardColors(prev => ({ ...prev, [key]: !prev[key] }));
  };

  const handleSaveCardColors = () => {
    updateSection.mutate(
      { type: 'cardColors', data: cardColors },
      {
        onSuccess: () => {
          toast.success('─É├ú l╞░u m├áu card', {
            description: 'C├ái ─æß║╖t m├áu sß║»c card bß║úo h├ánh ─æ├ú ─æ╞░ß╗úc cß║¡p nhß║¡t. Refresh trang ─æß╗â xem thay ─æß╗òi.',
          });
        },
      }
    );
  };

  const _handleResetCardColors = () => {
    const defaults = clone(defaultCardColors);
    setCardColors(defaults);
    updateSection.mutate(
      { type: 'cardColors', data: defaults },
      {
        onSuccess: () => {
          toast.info('─É├ú ─æß║╖t lß║íi mß║╖c ─æß╗ïnh', {
            description: 'M├áu card ─æ├ú ─æ╞░ß╗úc kh├┤i phß╗Ñc vß╗ü gi├í trß╗ï mß║╖c ─æß╗ïnh.',
          });
        },
      }
    );
  };

  // ============================================
  // RENDER
  // ============================================

    React.useEffect(() => {
      if (activeTab !== 'sla') {
        return;
      }

      registerSlaActions([
        <SettingsActionButton key="save" onClick={handleSaveSLA}>
          <Save className="h-4 w-4" /> L╞░u c├ái ─æß║╖t
