export function StockLocationsPage() {
  const { data: queryData } = useStockLocations({ limit: 1000 });
  const data = queryData?.data ?? [];
  const { create, update, remove } = useStockLocationMutations({
    onSuccess: () => toast.success('Th├ánh c├┤ng'),
    onError: (err) => toast.error(err.message)
  });
  const { data: branches } = useAllBranches();
  
  const [isFormOpen, setIsFormOpen] = React.useState(false);
  const [editingItem, setEditingItem] = React.useState<StockLocation | null>(null);
  const [isAlertOpen, setIsAlertOpen] = React.useState(false);
  const [idToDelete, setIdToDelete] = React.useState<SystemId | null>(null);
  
  const [pagination, setPagination] = React.useState({ pageIndex: 0, pageSize: 20 });
  
  // Γ£à Sß╗¡ dß╗Ñng useColumnVisibility hook thay v├¼ localStorage trß╗▒c tiß║┐p
  const defaultColumnVisibility = React.useMemo(() => {
    const cols = getColumns(() => {}, () => {}, branches);
    const initial: Record<string, boolean> = {};
    cols.forEach(c => { if (c.id) initial[c.id] = true; });
    return initial;
  }, [branches]);
  const [columnVisibility, setColumnVisibility] = useColumnVisibility('stock-locations', defaultColumnVisibility);
  
  const handleAddNew = React.useCallback(() => { setEditingItem(null); setIsFormOpen(true); }, []);
  const handleEdit = React.useCallback((item: StockLocation) => { setEditingItem(item); setIsFormOpen(true); }, []);
  const handleDeleteRequest = React.useCallback((id: string) => { setIdToDelete(asSystemId(id)); setIsAlertOpen(true); }, []);
  
  const _locationSummary = React.useMemo(() => {
    if (!data.length) {
      return 'Ch╞░a c├│ ─æiß╗âm l╞░u kho n├áo, h├úy tß║ío ─æiß╗âm ─æß║ºu ti├¬n ─æß╗â g├ín cho chi nh├ính.';
    }
    const uniqueBranches = new Set(data.map((item) => item.branchSystemId)).size;
    const defaultBranchName = branches.find((b) => b.isDefault)?.name;
    const branchLabel = uniqueBranches ? `${uniqueBranches} chi nh├ính` : 'Ch╞░a g├ín chi nh├ính';
    const defaultBranchLabel = defaultBranchName ? ` ΓÇó Chi nh├ính mß║╖c ─æß╗ïnh: ${defaultBranchName}` : '';
    return `${data.length} ─æiß╗âm l╞░u kho ΓÇó ${branchLabel}${defaultBranchLabel}`;
  }, [data, branches]);

  const headerActions = React.useMemo(() => ([
    <SettingsActionButton key="add" onClick={handleAddNew}>
      <PlusCircle className="h-4 w-4" />
      Th├¬m ─æiß╗âm l╞░u kho
    </SettingsActionButton>
  ]), [handleAddNew]);

  useSettingsPageHeader({
    title: 'Vß╗ï tr├¡ kho',
    actions: headerActions,
  });
  
  const confirmDelete = () => { if (idToDelete) remove.mutate(idToDelete); setIsAlertOpen(false); };
  
  const handleFormSubmit = (values: StockLocationFormValues) => {
    if (editingItem) {
      update.mutate({ systemId: editingItem.systemId, data: values });
    } else {
      create.mutate(values);
    }
    setIsFormOpen(false);
  };
  
  const columns = React.useMemo(() => getColumns(handleEdit, handleDeleteRequest, branches), [handleEdit, handleDeleteRequest, branches]);
  
  const pageCount = Math.ceil(data.length / pagination.pageSize);
  const paginatedData = React.useMemo(() => data.slice(pagination.pageIndex * pagination.pageSize, (pagination.pageIndex + 1) * pagination.pageSize), [data, pagination]);

  return (
    <div className="space-y-4">
      <Card>
        <CardHeader className="pb-4">
          <CardTitle>Danh s├ích ─æiß╗âm l╞░u kho</CardTitle>
          <CardDescription>Theo d├╡i mapping vß╗ï tr├¡ giß╗»a chi nh├ính v├á khu vß╗▒c l╞░u trß╗».</CardDescription>
        </CardHeader>
        <CardContent>
          <ResponsiveDataTable
            columns={columns}
            data={paginatedData}
            pageCount={pageCount}
            pagination={pagination}
            setPagination={setPagination}
            rowCount={data.length}
            rowSelection={{}}
            setRowSelection={() => {}}
            sorting={{id: 'createdAt', desc: true}}
            setSorting={() => {}}
            allSelectedRows={[]}
            expanded={{}}
            setExpanded={() => {}} 
            columnVisibility={columnVisibility}
            setColumnVisibility={setColumnVisibility} 
            columnOrder={[]}
            setColumnOrder={()=>{}}
            pinnedColumns={[]}
            setPinnedColumns={()=>{}}
            autoGenerateMobileCards
          />
        </CardContent>
      </Card>
      
      <Dialog open={isFormOpen} onOpenChange={setIsFormOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>{editingItem ? 'Cß║¡p nhß║¡t ─æiß╗âm l╞░u kho' : 'Th├¬m ─æiß╗âm l╞░u kho'}</DialogTitle>
          </DialogHeader>
          <StockLocationForm initialData={editingItem} onSubmit={handleFormSubmit} />
          <DialogFooter>
            <Button type="button" variant="outline" onClick={() => setIsFormOpen(false)}>Tho├ít</Button>
            <Button type="submit" form="stock-location-form">L╞░u</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
      
      <AlertDialog open={isAlertOpen} onOpenChange={setIsAlertOpen}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Bß║ín c├│ chß║»c chß║»n muß╗æn x├│a?</AlertDialogTitle>
            <AlertDialogDescription>H├ánh ─æß╗Öng n├áy kh├┤ng thß╗â ─æ╞░ß╗úc ho├án t├íc.</AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Hß╗ºy</AlertDialogCancel>
            <AlertDialogAction onClick={confirmDelete}>X├│a</AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

