                          </TableCell>
                          <TableCell className="text-muted-foreground">
                            {item.note || '-'}
                          </TableCell>
                        </TableRow>
                      );
                    })}
                  </TableBody>
                </Table>
              </div>
              
              <Separator className="my-4" />
              
              <div className="flex justify-end">
                <div className="text-right space-y-1">
                  <p className="text-body-sm text-muted-foreground">Tß╗òng sß╗æ l╞░ß╗úng chuyß╗ân: {totalQuantity}</p>
                  {transfer.status === 'completed' && totalReceived !== totalQuantity && (
                    <p className="text-body-sm text-muted-foreground">
                      ─É├ú nhß║¡n: {totalReceived}
                    </p>
                  )}
                  <p className="text-h3 font-bold">Tß╗òng gi├í trß╗ï: {formatCurrency(totalValue)}</p>
                </div>
              </div>
            </CardContent>
          </Card>

      {/* Comments - Full Width */}
      <Comments
        entityType="stock-transfer"
        entityId={transfer.systemId}
        comments={comments}
        onAddComment={handleAddComment}
        onUpdateComment={handleUpdateComment}
        onDeleteComment={handleDeleteComment}
        currentUser={commentCurrentUser}
        title="B├¼nh luß║¡n"
        placeholder="Th├¬m b├¼nh luß║¡n vß╗ü phiß║┐u chuyß╗ân kho..."
      />

      {/* Activity History - Full Width */}
      <ActivityHistory
        history={buildHistoryEntries(transfer)}
        title="Lß╗ïch sß╗¡ hoß║ít ─æß╗Öng"
        emptyMessage="Ch╞░a c├│ hoß║ít ─æß╗Öng"
      />

      {/* Confirm Transfer Dialog */}
      <AlertDialog open={confirmTransferOpen} onOpenChange={setConfirmTransferOpen}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>X├íc nhß║¡n chuyß╗ân h├áng khß╗Åi kho?</AlertDialogTitle>
            <AlertDialogDescription>
              Hß╗ç thß╗æng sß║╜ trß╗½ tß╗ôn kho tß║íi chi nh├ính <strong>{transfer.fromBranchName}</strong> v├á 
              ghi nhß║¡n h├áng ─æang vß╗ü tß║íi chi nh├ính <strong>{transfer.toBranchName}</strong>.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Hß╗ºy</AlertDialogCancel>
            <AlertDialogAction onClick={handleConfirmTransfer}>
