            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      {/* Confirm Receive Dialog */}
      <Dialog open={confirmReceiveOpen} onOpenChange={setConfirmReceiveOpen}>
        <DialogContent className="max-w-2xl">
          <DialogHeader>
            <DialogTitle>X├íc nhß║¡n nhß║¡n h├áng v├áo kho</DialogTitle>
            <DialogDescription>
              Nhß║¡p sß╗æ l╞░ß╗úng thß╗▒c tß║┐ nhß║¡n ─æ╞░ß╗úc cho tß╗½ng sß║ún phß║⌐m
            </DialogDescription>
          </DialogHeader>
          
          <div className="overflow-x-auto max-h-[400px]">
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Sß║ún phß║⌐m</TableHead>
                  <TableHead className="text-center w-[100px]">SL chuyß╗ân</TableHead>
                  <TableHead className="text-center w-[120px]">SL nhß║¡n</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {transfer.items.map((item, index) => (
                  <TableRow key={index}>
                    <TableCell>
                      <p className="font-medium">{item.productName}</p>
                      <p className="text-sm text-muted-foreground">{item.productId}</p>
                    </TableCell>
                    <TableCell className="text-center">{item.quantity}</TableCell>
                    <TableCell>
                      <Input
                        type="number"
                        min={0}
                        max={item.quantity}
                        value={receiveItems.find(r => r.productSystemId === item.productSystemId)?.receivedQuantity ?? item.quantity}
                        onChange={(e) => {
                          const value = parseInt(e.target.value) || 0;
                          setReceiveItems(prev => prev.map(r => 
                            r.productSystemId === item.productSystemId 
                              ? { ...r, receivedQuantity: Math.min(value, item.quantity) }
                              : r
                          ));
                        }}
                        className="h-9 w-full text-center"
                      />
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </div>
          
          <DialogFooter>
            <Button variant="outline" className="h-9" onClick={() => setConfirmReceiveOpen(false)}>
              Hß╗ºy
            </Button>
            <Button className="h-9" onClick={handleConfirmReceive}>
              X├íc nhß║¡n nhß║¡n h├áng
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Cancel Dialog */}
      <Dialog open={cancelDialogOpen} onOpenChange={setCancelDialogOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Hß╗ºy phiß║┐u chuyß╗ân kho?</DialogTitle>
            <DialogDescription>
              {transfer.status === 'transferring' 
                ? 'Hß╗ç thß╗æng sß║╜ ho├án lß║íi tß╗ôn kho vß╗ü chi nh├ính chuyß╗ân.'
                : 'Phiß║┐u chuyß╗ân kho sß║╜ bß╗ï hß╗ºy.'
              }
            </DialogDescription>
          </DialogHeader>
          
          <div className="space-y-2">
            <Label>L├╜ do hß╗ºy</Label>
            <Textarea
              value={cancelReason}
              onChange={(e) => setCancelReason(e.target.value)}
              placeholder="Nhß║¡p l├╜ do hß╗ºy phiß║┐u..."
              rows={3}
            />
          </div>
          
          <DialogFooter>
            <Button variant="outline" className="h-9" onClick={() => setCancelDialogOpen(false)}>
              ─É├│ng
            </Button>
            <Button variant="destructive" className="h-9" onClick={handleCancel}>
              X├íc nhß║¡n hß╗ºy
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      <ImagePreviewDialog
        images={previewImage ? [previewImage.url] : []}
        open={!!previewImage}
        onOpenChange={(open) => !open && setPreviewImage(null)}
        title={previewImage?.title}
      />
    </div>
  );
}

'use client'
import * as React from 'react';
