                }}
                placeholder={selectedProvince ? "Chß╗ìn Ph╞░ß╗¥ng/X├ú" : "Chß╗ìn tß╗ënh tr╞░ß╗¢c"}
                searchPlaceholder="T├¼m ph╞░ß╗¥ng/x├ú..."
                emptyPlaceholder="Kh├┤ng t├¼m thß║Ñy"
                disabled={!selectedProvince}
                estimatedItemHeight={36}
              />
            </div>
          </div>

          <DialogFooter className="gap-2">
            <Button
