  const handleSubmit = (values: SupplierFormValues) => {
    const normalizedId = values.id ? asBusinessId(values.id) : supplier?.id ?? asBusinessId('');
    const payload = {
      ...values,
      id: normalizedId,
      taxCode: values.taxCode ?? '',
      email: values.email ?? '',
