  const handleCancel = React.useCallback(() => {
    router.push(ROUTES.PROCUREMENT.SUPPLIERS);
  }, [router]);

  const isEditing = Boolean(supplier);

  const breadcrumb = React.useMemo<BreadcrumbItem[]>(() => {
    const currentPath = isEditing && supplierSystemId
      ? generatePath(ROUTES.PROCUREMENT.SUPPLIER_EDIT, { systemId: supplierSystemId })
      : ROUTES.PROCUREMENT.SUPPLIER_NEW;
    return [
      { label: 'Trang chß╗º', href: ROUTES.ROOT },
      { label: 'Nh├á cung cß║Ñp', href: ROUTES.PROCUREMENT.SUPPLIERS },
      { label: isEditing ? 'Chß╗ënh sß╗¡a' : 'Th├¬m mß╗¢i', href: currentPath, isCurrent: true },
    ];
  }, [isEditing, supplierSystemId]);

  usePageHeader({
    title: isEditing ? 'Chß╗ënh sß╗¡a nh├á cung cß║Ñp' : 'Th├¬m nh├á cung cß║Ñp',
    subtitle: isEditing ? `Cß║¡p nhß║¡t th├┤ng tin cho ${supplier?.name}` : 'Tß║ío mß╗¢i nh├á cung cß║Ñp v├á thiß║┐t lß║¡p c├┤ng nß╗ú ─æß║ºu kß╗│.',
    backPath: ROUTES.PROCUREMENT.SUPPLIERS,
    breadcrumb,
    actions: [
      <Button key="cancel" variant="outline" className="h-9 gap-2" onClick={handleCancel}>
