              hour: '2-digit',
              minute: '2-digit',
              hour12: false
            }}
            allDayText="Cß║ú ng├áy"
            noEventsText="Kh├┤ng c├│ c├┤ng viß╗çc"
            moreLinkText={(num) => `+${num} c├┤ng viß╗çc`}
            nowIndicator={true}
          />
        </CardContent>
      </Card>

      {/* Legend */}
      <Card>
        <CardContent className="p-4">
          <div className="text-sm font-semibold mb-2">Ch├║ th├¡ch:</div>
          <div className="grid grid-cols-2 md:grid-cols-4 gap-3 text-xs">
            <div className="flex items-center gap-2">
              <div className="w-4 h-4 rounded" style={{ backgroundColor: '#6B7280' }}></div>
              <span>─Éß╗Ö ╞░u ti├¬n Thß║Ñp</span>
            </div>
            <div className="flex items-center gap-2">
              <div className="w-4 h-4 rounded" style={{ backgroundColor: '#3B82F6' }}></div>
              <span>─Éß╗Ö ╞░u ti├¬n Trung b├¼nh</span>
            </div>
            <div className="flex items-center gap-2">
              <div className="w-4 h-4 rounded" style={{ backgroundColor: '#F59E0B' }}></div>
              <span>─Éß╗Ö ╞░u ti├¬n Cao</span>
            </div>
            <div className="flex items-center gap-2">
              <div className="w-4 h-4 rounded" style={{ backgroundColor: '#EF4444' }}></div>
              <span>─Éß╗Ö ╞░u ti├¬n Khß║⌐n cß║Ñp</span>
            </div>
          </div>
          <div className="text-xs text-muted-foreground mt-2">
            ≡ƒÆí K├⌐o thß║ú ─æß╗â thay ─æß╗òi ng├áy, k├⌐o g├│c ─æß╗â thay ─æß╗òi deadline. Viß╗ün tr├íi thß╗â hiß╗çn trß║íng th├íi.
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

'use client'

