// Helper functions - defined outside component to avoid hoisting issues
const getPriorityVariant = (priority: TaskPriority): "default" | "secondary" | "warning" | "destructive" => {
  const map = { 'Thß║Ñp': 'secondary', 'Trung b├¼nh': 'default', 'Cao': 'warning', 'Khß║⌐n cß║Ñp': 'destructive' } as const;
  return map[priority];
};

const getStatusVariant = (status: TaskStatus): "default" | "secondary" | "warning" | "success" | "outline" => {
  const map = { 
    'Ch╞░a bß║»t ─æß║ºu': 'outline', 
    '─Éang thß╗▒c hiß╗çn': 'warning', 
    '─Éang chß╗¥': 'secondary', 
    'Ho├án th├ánh': 'success', 
    '─É├ú hß╗ºy': 'default' 
  } as const;
  return map[status];
};

export function TaskDetailPage() {
  const { systemId } = useParams<{ systemId: string }>();
  const routeSystemId = React.useMemo(() => (systemId ? asSystemId(systemId) : undefined), [systemId]);
  const router = useRouter();
  
  const { data: task, isLoading } = useTaskById(routeSystemId);
  const { remove: removeMutation, update: updateMutation } = useTaskMutations();
  
  // Wrapper functions for legacy interface
  const remove = React.useCallback((systemId: string) => {
    removeMutation.mutate(systemId);
  }, [removeMutation]);
  
  const update = React.useCallback((systemId: string, data: Partial<Task>) => {
    updateMutation.mutate({ systemId, data });
  }, [updateMutation]);
  
  const approveTask = React.useCallback((systemId: string, comment?: string) => {
    updateMutation.mutate({ systemId, data: { status: 'Ho├án th├ánh' } });
    // Note: comment parameter not used - consider adding to activities/comments
  }, [updateMutation]);
  
  const rejectTask = React.useCallback((systemId: string, reason: string) => {
    updateMutation.mutate({ systemId, data: { status: '─Éang thß╗▒c hiß╗çn', rejectionReason: reason } });
  }, [updateMutation]);
  
  const { isAdmin, employee } = useAuth();
  const { data: allEmployees } = useAllEmployees();
  const [isDeleteDialogOpen, setIsDeleteDialogOpen] = React.useState(false);
  const [showApprovalDialog, setShowApprovalDialog] = React.useState(false);
  const [showEvidenceViewer, setShowEvidenceViewer] = React.useState(false);

  // Get all employees for @mention in comments
  const employeeMentions = React.useMemo(() => {
    return allEmployees
      .filter(e => !e.isDeleted)
      .map(e => ({
        id: e.systemId,
        label: e.fullName,
        avatar: e.avatarUrl,
      }));
  }, [allEmployees]);
  
  // Check if current user can edit this task
  const canEdit = React.useMemo(() => {
    if (isAdmin) return true;
    if (!task || !employee) return false;
    return task.assigneeId === employee.systemId;
  }, [isAdmin, task, employee]);

  const actions = React.useMemo(() => {
    if (!task) return [];
    
    const actionButtons: React.ReactNode[] = [];
    
    // Admin approval buttons for pending tasks
    if (isAdmin && task.approvalStatus === 'pending' && task.completionEvidence) {
      actionButtons.push(
        <Button 
          key="view-evidence" 
