    );
  }, [task]);

  usePageHeader({
    title: task ? task.title : 'Chi tiß║┐t c├┤ng viß╗çc',
    badge: statusBadge,
    backPath: '/tasks',
    breadcrumb: task ? [
      { label: 'Trang chß╗º', href: '/', isCurrent: false },
      { label: 'Quß║ún l├╜ c├┤ng viß╗çc', href: '/tasks', isCurrent: false },
      { label: task.title, href: `/tasks/${task.systemId}`, isCurrent: true }
    ] : undefined,
    actions,
  });

  // All hooks must be called before any early returns (React hooks rules)
  // SLA calculation
  const slaSettings = React.useMemo(() => loadSLASettings(), []);
  
  const slaDeadlines = React.useMemo(() => {
    // Check all required conditions
    if (!task?.priority || !task?.startDate) return null;
    
    const slaConfig = slaSettings[task.priority];
