          </div>

          {/* Effort */}
          {(task.estimatedHours || task.actualHours) && (
            <>
              <Separator />
              <div className="grid grid-cols-2 gap-4">
                {task.estimatedHours && (
                  <div>
                    <div className="text-body-sm font-medium">Giß╗¥ ╞░ß╗¢c t├¡nh</div>
                    <div className="text-h3 font-bold">{task.estimatedHours}h</div>
                  </div>
                )}
                {task.actualHours && (
                  <div>
                    <div className="text-body-sm font-medium">Giß╗¥ thß╗▒c tß║┐</div>
                    <div className="text-h3 font-bold">
                      {(() => {
                        const totalHours = task.actualHours;
                        const hours = Math.floor(totalHours);
                        const minutes = Math.floor((totalHours % 1) * 60);
                        const seconds = Math.floor((((totalHours % 1) * 60) % 1) * 60);
                        
                        const parts: string[] = [];
                        if (hours > 0) parts.push(`${hours} giß╗¥`);
                        if (minutes > 0) parts.push(`${minutes} ph├║t`);
                        if (seconds > 0) parts.push(`${seconds} gi├óy`);
                        
                        return parts.length > 0 ? parts.join(' ') : '0 gi├óy';
                      })()}
                    </div>
                  </div>
                )}
              </div>
            </>
          )}

          {/* Subtasks */}
          <Separator />
          <div>
            <h3 className="font-semibold mb-3">Danh s├ích c├┤ng viß╗çc con</h3>
            <SubtaskList
              subtasks={(task.subtasks || []).map((st, idx) => ({
                ...st,
                order: idx,
                createdAt: new Date(task.createdAt || new Date().toISOString()),
              }))}
              onAdd={(title) => {
                if (!canEdit) {
                  toast.error('Bß║ín kh├┤ng c├│ quyß╗ün chß╗ënh sß╗¡a c├┤ng viß╗çc n├áy');
                  return;
                }
                const currentSubtasks = task.subtasks || [];
                const newSubtask = {
                  id: `subtask-${Date.now()}`,
                  title,
                  completed: false,
                  order: currentSubtasks.length,
                  createdAt: new Date().toISOString(),
                };
                const updatedSubtasks = [...currentSubtasks, newSubtask];
                
                // Call update with just subtasks field
                update(task.systemId, { 
                  subtasks: updatedSubtasks
                });
                toast.success('─É├ú th├¬m subtask');
              }}
              onUpdate={(subtaskId, updates) => {
                if (!canEdit) {
                  toast.error('Bß║ín kh├┤ng c├│ quyß╗ün chß╗ënh sß╗¡a c├┤ng viß╗çc n├áy');
                  return;
                }
                const updatedSubtasks = (task.subtasks || []).map(s =>
                  s.id === subtaskId ? { ...s, ...updates } : s
                );
                update(task.systemId, { 
                  ...task, 
                  subtasks: updatedSubtasks
                });
              }}
              onDelete={(subtaskId) => {
                if (!canEdit) {
                  toast.error('Bß║ín kh├┤ng c├│ quyß╗ün chß╗ënh sß╗¡a c├┤ng viß╗çc n├áy');
                  return;
                }
                const updatedSubtasks = (task.subtasks || []).filter(s => s.id !== subtaskId);
                const completedCount = updatedSubtasks.filter(s => s.completed).length;
                const newProgress = updatedSubtasks.length > 0 
                  ? Math.round((completedCount / updatedSubtasks.length) * 100)
                  : 0;
                update(task.systemId, { 
                  ...task, 
                  subtasks: updatedSubtasks,
                  progress: newProgress
                });
                toast.success('─É├ú x├│a subtask');
              }}
              onReorder={(reorderedSubtasks) => {
                if (!canEdit) return;
                const updatedSubtasks = reorderedSubtasks.map(({ id, title, completed }) => ({ id, title, completed }));
                update(task.systemId, { 
                  ...task, 
                  subtasks: updatedSubtasks
                });
              }}
              onToggleComplete={(subtaskId, completed) => {
                if (!canEdit) {
                  toast.error('Bß║ín kh├┤ng c├│ quyß╗ün chß╗ënh sß╗¡a c├┤ng viß╗çc n├áy');
                  return;
                }
                
                const updatedSubtasks = (task.subtasks || []).map(s =>
                  s.id === subtaskId ? { ...s, completed } : s
                );
                // Calculate new progress based on completed subtasks
                const completedCount = updatedSubtasks.filter(s => s.completed).length;
                const newProgress = updatedSubtasks.length > 0 
                  ? Math.round((completedCount / updatedSubtasks.length) * 100)
                  : 0;
                
                update(task.systemId, { 
                  ...task, 
                  subtasks: updatedSubtasks,
                  progress: newProgress
                });
              }}
              readonly={!canEdit || task.status === 'Ho├án th├ánh' || task.status === '─É├ú hß╗ºy'}
            />
          </div>
        </CardContent>
      </Card>

      {/* Comments Section */}
      <Card>
        <CardContent className="p-6">
          <Comments
            entityType="tasks"
            entityId={task.systemId}
            comments={(task.comments || []).map(c => ({
              ...c,
              author: {
                systemId: c.userId,
                name: c.userName,
              },
              createdAt: new Date(c.createdAt),
            }))}
            currentUser={employee ? {
              systemId: employee.systemId,
              name: employee.fullName,
            } : undefined}
            onAddComment={(content) => {
              if (!canEdit) {
                toast.error('Bß║ín kh├┤ng c├│ quyß╗ün th├¬m comment cho c├┤ng viß╗çc n├áy');
                return;
              }
              
              const newComment = {
                id: `comment-${Date.now()}`,
                taskId: task.systemId,
