        </CardContent>
      </Card>

      <AlertDialog open={isDeleteDialogOpen} onOpenChange={setIsDeleteDialogOpen}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>X├│a c├┤ng viß╗çc?</AlertDialogTitle>
            <AlertDialogDescription>
              Bß║ín c├│ chß║»c muß╗æn x├│a c├┤ng viß╗çc "{task.title}"? H├ánh ─æß╗Öng n├áy kh├┤ng thß╗â ho├án t├íc.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Hß╗ºy</AlertDialogCancel>
            <AlertDialogAction onClick={handleDelete} className="bg-destructive text-destructive-foreground hover:bg-destructive/90">
              X├│a
