import * as React from 'react';
import { usePaymentStore } from '../../../../payments/store';
import { useAllReceipts } from '../../../../receipts/hooks/use-all-receipts';
import { useOrderMutations } from '../../../../orders/hooks/use-order-mutations';
import { useAllOrders } from '../../../../orders/hooks/use-all-orders';
import { useWarrantyMutations } from '../../../hooks/use-warranties';
import { useWarrantyFinder } from '../../../hooks/use-all-warranties';
import { useAllPaymentTypes } from '../../../../settings/payments/types/hooks/use-all-payment-types';
import { useAllPaymentMethods } from '../../../../settings/payments/hooks/use-all-payment-methods';
import { useAllCashAccounts } from '../../../../cashbook/hooks/use-all-cash-accounts';
import { useAuth } from '../../../../../contexts/auth-context';
import { asSystemId } from '@/lib/id-types';
import { calculateWarrantyProcessingState } from '../../logic/processing';

/**
 * Hook quß║ún l├╜ c├íc stores v├á computed values cho PaymentVoucherDialog
 */
export function usePaymentVoucherStores(warrantySystemId: string) {
  const { add: addPayment, data: payments } = usePaymentStore();
  const { data: receipts } = useAllReceipts();
  const { data: orders } = useAllOrders();
  const { update: updateOrder } = useOrderMutations();
  const { update: updateWarranty } = useWarrantyMutations();
  const { findById: findWarrantyById } = useWarrantyFinder();
  const { data: paymentTypes } = useAllPaymentTypes();
  const { data: paymentMethods } = useAllPaymentMethods();
  const { accounts } = useAllCashAccounts();
  const { employee: authEmployee } = useAuth();

  const currentUserSystemId = authEmployee?.systemId ?? 'SYSTEM';
  const currentUserName = authEmployee?.fullName || authEmployee?.id || 'Hß╗ç thß╗æng';

  // Get warranty payment types
  const warrantyRefundType = React.useMemo(() => 
    paymentTypes.find(t => t.id === 'HOANTIEN_BH' && t.isActive),
    [paymentTypes]
  );

  const warrantyOrderDeductionType = React.useMemo(() => 
    paymentTypes.find(t => t.id === 'TRAVAO_DONHANG' && t.isActive),
    [paymentTypes]
  );

  // Get default payment method (Tiß╗ün mß║╖t)
  const defaultPaymentMethod = React.useMemo(() => 
    paymentMethods.find(m => m.isDefault && m.isActive) || paymentMethods.find(m => m.isActive),
    [paymentMethods]
  );

  // Get default cash account
  const defaultCashAccount = React.useMemo(() => 
    accounts.find(a => a.type === 'cash' && a.isDefault && a.isActive) || 
    accounts.find(a => a.type === 'cash' && a.isActive),
    [accounts]
  );

  // Get ticket v├á t├¡nh remaining amount
  const ticket = React.useMemo(() => 
    findWarrantyById(asSystemId(warrantySystemId)),
    [findWarrantyById, warrantySystemId]
  );
  
  const actualRemainingAmount = React.useMemo(() => {
    if (!ticket) return 0;
    
    const totalPaymentFromTicket = ticket.products.reduce((sum, p) => {
      if (p.resolution === 'out_of_stock') {
        return sum + ((p.quantity || 0) * (p.unitPrice || 0));
      }
      return sum;
    }, 0) + (ticket.shippingFee || 0);
    
    const state = calculateWarrantyProcessingState(ticket, payments, receipts, totalPaymentFromTicket);
    return state.remainingAmount;
  }, [ticket, payments, receipts]);

  return {
    // Store data
    payments,
    receipts,
    orders,
    paymentTypes,
    paymentMethods,
    accounts,
    ticket,
    
    // Store actions
    addPayment,
    updateOrder,
    addHistory: (systemId: string, action: string, user: string, note?: string) => {},
    
    // Computed values
    warrantyRefundType,
    warrantyOrderDeductionType,
    defaultPaymentMethod,
    defaultCashAccount,
    actualRemainingAmount,
    currentUserSystemId,
    currentUserName,
  };
}

/**
 * Cancel Warranty Dialog
 * Dialog ─æß╗â hß╗ºy phiß║┐u bß║úo h├ánh vß╗¢i l├╜ do
 */

import * as React from 'react';
import { toast } from 'sonner';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from '../../../../components/ui/alert-dialog';
import { Textarea } from '../../../../components/ui/textarea';
import type { WarrantyTicket, WarrantyHistory } from '../../types';
import { useWarrantyMutations } from '../../hooks/use-warranties';
import { useWarrantyFinder } from '../../hooks/use-all-warranties';
import { asSystemId } from '@/lib/id-types';
import { useAllReceipts } from '../../../receipts/hooks/use-all-receipts';
import { useAllOrders } from '../../../orders/hooks/use-all-orders';
import { usePaymentMutations } from '../../../payments/hooks/use-payments';
import { useReceiptMutations } from '../../../receipts/hooks/use-receipts';
import { useOrderMutations } from '../../../orders/hooks/use-order-mutations';
import { useAuth } from '../../../../contexts/auth-context';
import { toISODateTime, getCurrentDate } from '../../../../lib/date-utils';

interface WarrantyCancelDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  ticket: WarrantyTicket | null;
  onCancelled?: (ticket: WarrantyTicket) => void;
}

export function WarrantyCancelDialog({ open, onOpenChange, ticket, onCancelled }: WarrantyCancelDialogProps) {
  const [cancelReason, setCancelReason] = React.useState('');
  const { user: currentUser } = useAuth();
  const { update: updateWarranty } = useWarrantyMutations({
    onUpdateSuccess: () => toast.success('─É├ú hß╗ºy phiß║┐u bß║úo h├ánh'),
    onError: (err) => toast.error(err.message)
  });
  const { update: updatePayment } = usePaymentMutations();
  const { update: updateReceipt } = useReceiptMutations();
  const { update: updateOrder } = useOrderMutations();
  const { findById } = useWarrantyFinder();
  const { data: allPayments = [] } = useAllReceipts();
  const { data: receipts = [] } = useAllReceipts();
  const { data: orders = [] } = useAllOrders();

  const handleCancel = React.useCallback(async () => {
    
    if (!currentUser) {
      toast.error('Vui l├▓ng ─æ─âng nhß║¡p');
      return;
    }

    if (!ticket || !cancelReason.trim()) {
      toast.error('Vui l├▓ng nhß║¡p l├╜ do hß╗ºy phiß║┐u');
      return;
    }

    try {
      const timestamp = toISODateTime(getCurrentDate());
      // Γ£à ROLLBACK KHO khi hß╗ºy - Ph├ón biß╗çt theo trß║íng th├íi
      const { rollbackWarrantyStock, uncommitWarrantyStock } = await import('../../store/stock-management');
      
      // Check nß║┐u ─æ├ú xuß║Ñt kho (completed hoß║╖c returned sau khi completed)
      const hasDeductedStock = ticket.stockDeducted || ticket.status === 'completed';
      
      if (hasDeductedStock) {
        // ─É├ú xuß║Ñt kho ΓåÆ Ho├án h├áng vß╗ü kho
        (rollbackWarrantyStock as any)(ticket, ticket.systemId);
      } else if (ticket.status === 'pending' || ticket.status === 'processed') {
        // Ch╞░a xuß║Ñt kho, chß╗ë uncommit (giß║úi ph├│ng h├áng giß╗» chß╗ù)
        (uncommitWarrantyStock as any)(ticket, ticket.systemId);
      } else if (ticket.status === 'returned') {
        // ─É├ú trß║ú h├áng nh╞░ng ch╞░a kß║┐t th├║c ΓåÆ vß║½n ─æang giß╗» h├áng thay thß║┐
        (uncommitWarrantyStock as any)(ticket, ticket.systemId);
      }
      // incomplete: kh├┤ng l├ám g├¼ cß║ú (ch╞░a commit)
      
      // CANCEL ALL PAYMENT & RECEIPT VOUCHERS linked to this warranty
      const relatedPayments = allPayments.filter(p => 
        p.linkedWarrantySystemId === ticket.systemId && 
        p.status !== 'cancelled'
      );
      const relatedReceipts = receipts.filter(r => 
        r.linkedWarrantySystemId === ticket.systemId && 
        r.status !== 'cancelled'
      );
      
      
      const allVouchers = [...relatedPayments, ...relatedReceipts];
      
      if (allVouchers.length > 0) {
        const cancelledCount = { payments: 0, receipts: 0 };
        
        // Soft delete payments - update status to 'cancelled' + save cancelReason in description
        relatedPayments.forEach(payment => {
          const newDescription = `[Hß╗ªY] ${cancelReason}${payment.description ? ` | Gß╗æc: ${payment.description}` : ''}`;
          
          (updatePayment as any).mutate({
            systemId: payment.systemId,
            status: 'cancelled',
            cancelledAt: timestamp,
            description: newDescription,
          });
          cancelledCount.payments++;
          
          // Γ£à UPDATE ORDER: Remove payment from order.payments and decrease paidAmount
          if (payment.linkedOrderSystemId) {
            const order = orders.find(o => o.systemId === payment.linkedOrderSystemId);
            if (order) {
              // Remove this payment from order.payments array
              const updatedPayments = order.payments.filter(p => p.systemId !== payment.systemId);
              
              // Decrease paidAmount (payment.amount is negative, so we subtract it back)
              const newPaidAmount = (order.paidAmount || 0) - Math.abs(payment.amount);
              
              
              updateOrder.mutate({
                id: payment.linkedOrderSystemId,
                payments: updatedPayments,
                paidAmount: Math.max(0, newPaidAmount), // Ensure not negative
              });
            }
          }
        });
        
        // Soft delete receipts - update status to 'cancelled' + save cancelReason in description
        relatedReceipts.forEach(receipt => {
          updateReceipt.mutate({
            systemId: receipt.systemId,
            data: {
              ...receipt,
              status: 'cancelled',
              cancelledAt: timestamp,
              description: `[Hß╗ªY] ${cancelReason}${receipt.description ? ` | Gß╗æc: ${receipt.description}` : ''}`,
            }
          });
          cancelledCount.receipts++;
        });
        
        const voucherList = allVouchers.map(v => `${v.id} (${v.amount.toLocaleString('vi-VN')}─æ)`).join(', ');
        
        toast.warning(`─É├ú hß╗ºy ${cancelledCount.payments} phiß║┐u chi v├á ${cancelledCount.receipts} phiß║┐u thu`, {
          description: voucherList,
          duration: 5000
        });
        
        const addHistory = (systemId: string, action: string, user: string, note?: string) => {};
        addHistory(
          ticket.systemId,
          `≡ƒùæ∩╕Å Hß╗ºy ${allVouchers.length} phiß║┐u thu/chi (${cancelledCount.payments} phiß║┐u chi, ${cancelledCount.receipts} phiß║┐u thu)`,
          currentUser.name ?? 'Unknown',
          `Danh s├ích: ${voucherList}`
        );
      }
      
      // Update warranty ticket status to 'cancelled'
      const latestTicket = findById(ticket.systemId);
      if (!latestTicket) {
        toast.error('Kh├┤ng t├¼m thß║Ñy phiß║┐u');
        return;
      }

      const newHistory: WarrantyHistory = {
        systemId: asSystemId(`history_${Date.now()}`),
        action: 'Hß╗ºy phiß║┐u bß║úo h├ánh',
        actionLabel: '─É├ú hß╗ºy phiß║┐u',
        entityType: 'status',
        performedBy: currentUser.name ?? 'Unknown',
        performedAt: timestamp,
        note: `L├╜ do: ${cancelReason}`,
      };

      const updatedTicket: WarrantyTicket = {
        ...latestTicket,
        status: 'cancelled',
        cancelledAt: timestamp,
        cancelReason,
        linkedOrderSystemId: undefined,
        stockDeducted: false,
        history: [...latestTicket.history, newHistory],
      };

      (updateWarranty as any).mutate({ systemId: ticket.systemId, data: updatedTicket });
      onCancelled?.(updatedTicket);
      
      onOpenChange(false);
      setCancelReason('');
      toast.success('─É├ú hß╗ºy phiß║┐u bß║úo h├ánh');
    } catch (error) {
      console.error('Failed to cancel ticket:', error);
      toast.error('Kh├┤ng thß╗â hß╗ºy phiß║┐u');
    }
  }, [ticket, cancelReason, updateWarranty, currentUser, findById, onOpenChange, orders, onCancelled]);

  return (
    <AlertDialog open={open} onOpenChange={onOpenChange}>
      <AlertDialogContent>
        <AlertDialogHeader>
          <AlertDialogTitle>X├íc nhß║¡n hß╗ºy phiß║┐u bß║úo h├ánh</AlertDialogTitle>
          <AlertDialogDescription>
            Bß║ín c├│ chß║»c chß║»n muß╗æn hß╗ºy phiß║┐u bß║úo h├ánh n├áy? Vui l├▓ng nhß║¡p l├╜ do hß╗ºy.
          </AlertDialogDescription>
        </AlertDialogHeader>
        <Textarea
          value={cancelReason}
          onChange={(e) => setCancelReason(e.target.value)}
          placeholder="Nhß║¡p l├╜ do hß╗ºy phiß║┐u (bß║»t buß╗Öc)..."
          className="min-h-[100px]"
        />
        <AlertDialogFooter>
          <AlertDialogCancel onClick={() => setCancelReason('')}>Hß╗ºy</AlertDialogCancel>
          <AlertDialogAction
            onClick={handleCancel}
            className="bg-destructive hover:bg-destructive/90"
          >
            Hß╗ºy phiß║┐u
          </AlertDialogAction>
        </AlertDialogFooter>
      </AlertDialogContent>
    </AlertDialog>
  );
}

