const detectDirectSettlementType = (paymentMethod?: { id?: string; name: string } | null): Exclude<SettlementType, 'mixed'> => {
  if (!paymentMethod) {
    return 'cash';
  }

  const normalizedId = paymentMethod.id?.toUpperCase() || '';
  const normalizedName = paymentMethod.name.toLowerCase();

  if (normalizedId === 'TIEN_MAT' || normalizedName.includes('tiß╗ün mß║╖t')) {
    return 'cash';
  }

  if (normalizedId === 'VI_DIEN_TU' || normalizedName.includes('momo') || normalizedName.includes('v├¡')) {
    return 'transfer';
  }

  return 'transfer';
};

