/**
 * Reopen From Cancelled Dialog
 * Dialog ─æß╗â mß╗ƒ lß║íi phiß║┐u bß║úo h├ánh tß╗½ trß║íng th├íi ─æ├ú hß╗ºy
 */

import * as React from 'react';
import { toast } from 'sonner';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from '../../../../components/ui/alert-dialog';
import { Textarea } from '../../../../components/ui/textarea';
import type { WarrantyTicket, WarrantyHistory } from '../../types';
import { useWarrantyMutations } from '../../hooks/use-warranties';
import { useWarrantyFinder } from '../../hooks/use-all-warranties';
import { useProducts } from '../../../products/hooks/use-products';
import { useProductMutations } from '../../../products/hooks/use-products';
import { useAuth } from '../../../../contexts/auth-context';
import { toISODateTime, getCurrentDate } from '../../../../lib/date-utils';
import { asSystemId, type SystemId } from '../../../../lib/id-types';
import { getMaxSystemIdCounter } from '../../../../lib/id-utils';

interface WarrantyReopenFromCancelledDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  ticket: WarrantyTicket | null;
}

const HISTORY_ID_PREFIX = 'WARRANTYHISTORY';

const generateHistorySystemId = (historyEntries: WarrantyHistory[] = []): SystemId => {
  const latestCounter = getMaxSystemIdCounter(historyEntries, HISTORY_ID_PREFIX);
  return asSystemId(`${HISTORY_ID_PREFIX}${String(latestCounter + 1).padStart(6, '0')}`);
};

export function WarrantyReopenFromCancelledDialog({ open, onOpenChange, ticket }: WarrantyReopenFromCancelledDialogProps) {
  const [reopenReason, setReopenReason] = React.useState('');
  const { user, employee } = useAuth();
  const performerName = employee?.fullName ?? user?.name ?? 'Hß╗ç thß╗æng';
  const performerSystemId = employee?.systemId ?? user?.employeeId;
  const { update } = useWarrantyMutations({
    onUpdateSuccess: () => toast.success('─É├ú mß╗ƒ lß║íi phiß║┐u bß║úo h├ánh'),
    onError: (err) => toast.error(err.message)
  });
  const { update: updateProduct } = useProductMutations();
  const { findById } = useWarrantyFinder();
  const { data: productsData } = useProducts({ limit: 1000 });
  const products = productsData?.data ?? [];

  const handleReopen = React.useCallback(() => {
    if (!ticket || !reopenReason.trim()) {
      toast.error('Vui l├▓ng nhß║¡p l├╜ do mß╗ƒ lß║íi phiß║┐u');
      return;
    }

    try {
      // Γ£à RE-COMMIT STOCK: Commit stock again when reopening from cancelled
      const replacedProducts = ticket.products.filter(p => p.resolution === 'replace');
      
      if (replacedProducts.length > 0) {
        replacedProducts.forEach(warrantyProduct => {
          const fallbackProduct = warrantyProduct.productSystemId
            ? products.find(p => p.systemId === warrantyProduct.productSystemId)
            : warrantyProduct.sku
              ? products.find(p => p.id === warrantyProduct.sku)
              : undefined;

          const productSystemId = warrantyProduct.productSystemId ?? fallbackProduct?.systemId;

          if (!productSystemId) {
            return;
          }

          const product = products.find(p => p.systemId === productSystemId);
          if (!product) return;

          const quantityToCommit = warrantyProduct.quantity || 1;
          const branchInventory = (product as any).inventory?.find((inv: any) => inv.branchSystemId === ticket.branchSystemId);
          
          if (branchInventory) {
            updateProduct.mutate({
              systemId: productSystemId,
              inventory: (product as any).inventory?.map((inv: any) => 
                  inv.branchSystemId === ticket.branchSystemId
                    ? { ...inv, committed: inv.committed + quantityToCommit }
                    : inv
                )
            });
          }
        });
        
        toast.info('─É├ú giß╗» h├áng cho phiß║┐u bß║úo h├ánh', {
          description: `${replacedProducts.length} sß║ún phß║⌐m ─æ├ú ─æ╞░ß╗úc giß╗» lß║íi trong kho`,
          duration: 3000
        });
      }
      
      // Γ£à Add history entry WITH REASON
      const inventoryNote = replacedProducts.length > 0 
        ? ` (─É├ú giß╗» lß║íi ${replacedProducts.length} sß║ún phß║⌐m)` 
        : '';
      
      // Γ£à Get latest ticket from store to avoid stale history
      const latestTicket = findById(ticket.systemId);
      if (!latestTicket) {
        toast.error('Kh├┤ng t├¼m thß║Ñy phiß║┐u');
        return;
      }
      
      const newHistory: WarrantyHistory = {
        systemId: generateHistorySystemId(latestTicket.history ?? []),
        action: 'Mß╗ƒ lß║íi phiß║┐u tß╗½ trß║íng th├íi ─É├ú hß╗ºy',
        actionLabel: '─É├ú mß╗ƒ lß║íi phiß║┐u tß╗½ trß║íng th├íi ─É├ú hß╗ºy',
        entityType: 'status',
        performedBy: performerName,
        performedBySystemId: performerSystemId ? asSystemId(performerSystemId) : undefined,
        performedAt: toISODateTime(getCurrentDate()),
        note: `L├╜ do mß╗ƒ lß║íi: ${reopenReason}${inventoryNote}`,
      };

      (update as any).mutate({ systemId: ticket.systemId, data: {
        cancelledAt: undefined,
        status: 'pending', // Γ£à Reset to pending (ready to process) instead of incomplete
        returnedAt: undefined, // Γ£à Clear returnedAt timestamp
        processedAt: undefined, // Γ£à Clear processedAt timestamp
        processingStartedAt: undefined, // Γ£à Clear processingStartedAt timestamp
        linkedOrderSystemId: undefined, // Γ£à Clear order link
        history: [...latestTicket.history, newHistory],
      }});
      
      onOpenChange(false);
      setReopenReason('');
      toast.success('─É├ú mß╗ƒ lß║íi phiß║┐u bß║úo h├ánh');
    } catch (error) {
      console.error('Failed to reopen ticket:', error);
      toast.error('Kh├┤ng thß╗â mß╗ƒ lß║íi phiß║┐u');
    }
  }, [ticket, reopenReason, update, performerName, performerSystemId, findById, onOpenChange]);

  return (
    <AlertDialog open={open} onOpenChange={onOpenChange}>
      <AlertDialogContent>
        <AlertDialogHeader>
          <AlertDialogTitle>X├íc nhß║¡n mß╗ƒ lß║íi phiß║┐u</AlertDialogTitle>
          <AlertDialogDescription>
            Bß║ín c├│ chß║»c chß║»n muß╗æn mß╗ƒ lß║íi phiß║┐u bß║úo h├ánh n├áy? Vui l├▓ng nhß║¡p l├╜ do mß╗ƒ lß║íi.
          </AlertDialogDescription>
        </AlertDialogHeader>
        <Textarea
          value={reopenReason}
          onChange={(e) => setReopenReason(e.target.value)}
          placeholder="Nhß║¡p l├╜ do mß╗ƒ lß║íi phiß║┐u (bß║»t buß╗Öc)..."
          className="min-h-[100px]"
        />
        <AlertDialogFooter>
          <AlertDialogCancel onClick={() => setReopenReason('')}>Hß╗ºy</AlertDialogCancel>
          <AlertDialogAction onClick={handleReopen}>
            Mß╗ƒ lß║íi
          </AlertDialogAction>
        </AlertDialogFooter>
      </AlertDialogContent>
    </AlertDialog>
  );
}

/**
 * Reopen From Returned Dialog
 * Dialog ─æß╗â mß╗ƒ lß║íi phiß║┐u bß║úo h├ánh tß╗½ trß║íng th├íi ─æ├ú trß║ú/kß║┐t th├║c
 */

import * as React from 'react';
import { toast } from 'sonner';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from '../../../../components/ui/alert-dialog';
import { Textarea } from '../../../../components/ui/textarea';
import type { WarrantyTicket } from '../../types';
import { useWarrantyMutations } from '../../hooks/use-warranties';
import { useAuth } from '../../../../contexts/auth-context';

interface WarrantyReopenFromReturnedDialogProps {
