}

export function WarrantyReopenFromReturnedDialog({ open, onOpenChange, ticket }: WarrantyReopenFromReturnedDialogProps) {
  const [reopenReason, setReopenReason] = React.useState('');
  const { user: _currentUser } = useAuth();
  const { update } = useWarrantyMutations({
    onUpdateSuccess: () => toast.success('─É├ú mß╗ƒ lß║íi phiß║┐u bß║úo h├ánh'),
    onError: (err) => toast.error(err.message)
  });

  const handleReopen = React.useCallback(() => {
    if (!ticket || !reopenReason.trim()) {
      toast.error('Vui l├▓ng nhß║¡p l├╜ do mß╗ƒ lß║íi');
      return;
    }

    try {
      // Determine target status based on current status
      const targetStatus = ticket.status === 'completed' ? 'returned' : 'processed';
      
      // ΓÜá∩╕Å KH├öNG ─Éß╗ÿNG CHß║áM G├î KHI Mß╗₧ Lß║áI Tß╗¬ COMPLETED
      // L├╜ do:
      // - Kß║┐t th├║c = ─É╞ín ─æ├ú xong, h├áng ─æ├ú xuß║Ñt, tiß╗ün ─æ├ú thanh to├ín
      // - Mß╗ƒ lß║íi CHß╗ê ─æß╗â xem lß║íi, kh├┤ng ─æ╞░ß╗úc sß╗¡a/thay ─æß╗òi g├¼
      // - Nß║┐u muß╗æn ─æiß╗üu chß╗ënh ΓåÆ Phß║úi thao t├íc th├¬m (tß║ío phiß║┐u mß╗¢i, ho├án h├áng thß╗º c├┤ng, etc.)
      if (ticket.status === 'completed') {
        // No-op: Completed tickets are reopened for viewing only
      }
      
      // Γ£à Pass l├╜ do mß╗ƒ lß║íi v├áo note parameter
      (update as any).mutate({ systemId: ticket.systemId, data: { status: targetStatus } });
      
      // Clear returnedAt v├á linkedOrderSystemId only when going back to processed (not from completed)
      if (targetStatus === 'processed') {
        (update as any).mutate({ systemId: ticket.systemId, data: {
          returnedAt: undefined,
          linkedOrderSystemId: undefined,
        }});
      }
      
      onOpenChange(false);
      setReopenReason('');
      toast.success(`─É├ú mß╗ƒ lß║íi phiß║┐u`, {
        description: ticket.status === 'completed' 
          ? 'Phiß║┐u ─æ├ú mß╗ƒ lß║íi ─æß╗â xem. Kh├┤ng thay ─æß╗òi kho h├áng hay thanh to├ín.' 
          : undefined
      });
    } catch (error) {
      console.error('Failed to reopen ticket:', error);
      toast.error('Kh├┤ng thß╗â mß╗ƒ lß║íi phiß║┐u');
    }
  }, [ticket, reopenReason, update, updateStatus, onOpenChange]);

  return (
    <AlertDialog open={open} onOpenChange={onOpenChange}>
      <AlertDialogContent>
        <AlertDialogHeader>
          <AlertDialogTitle>X├íc nhß║¡n mß╗ƒ lß║íi phiß║┐u ─æ├ú trß║ú</AlertDialogTitle>
          <AlertDialogDescription>
            Phiß║┐u n├áy ─æ├ú trß║ú h├áng cho kh├ích. Vui l├▓ng nhß║¡p l├╜ do cß║ºn mß╗ƒ lß║íi.
          </AlertDialogDescription>
        </AlertDialogHeader>
        <Textarea
          value={reopenReason}
          onChange={(e) => setReopenReason(e.target.value)}
          placeholder="Nhß║¡p l├╜ do mß╗ƒ lß║íi (bß║»t buß╗Öc)..."
          className="min-h-[100px]"
        />
        <AlertDialogFooter>
          <AlertDialogCancel onClick={() => setReopenReason('')}>Hß╗ºy</AlertDialogCancel>
          <AlertDialogAction onClick={handleReopen}>
            Mß╗ƒ lß║íi
          </AlertDialogAction>
        </AlertDialogFooter>
      </AlertDialogContent>
    </AlertDialog>
  );
}

