                    <TableHead className="w-[40px]">STT</TableHead>
                    <TableHead className="w-[220px]">T├¬n sß║ún phß║⌐m</TableHead>
                    <TableHead className="w-[90px]">Sß╗æ l╞░ß╗úng</TableHead>
                    <TableHead className="w-[160px]">─É╞ín gi├í</TableHead>
                    <TableHead className="w-[280px]">H├¼nh ß║únh</TableHead>
                    <TableHead className="w-[110px]">Kß║┐t quß║ú</TableHead>
                    <TableHead className="w-[280px]">Ghi ch├║</TableHead>
                    <TableHead className="w-[130px] text-right">Th├ánh tiß╗ün</TableHead>
