    // Allow cancelling at any status except completed
    if (!ticket?.cancelledAt && ticket?.status !== 'completed') {
      actionButtons.push(
        <Button
          key="cancel"
          type="button"
          size="sm"
          variant="outline"
          className="h-9 text-destructive hover:text-destructive"
