      />

      {/* Reminder Modal */}
      <WarrantyReminderDialog
        open={isReminderModalOpen}
        onOpenChange={closeReminderModal}
        ticket={selectedTicket}
        templates={templates}
        onSendReminder={sendReminder}
      />

      {/* X├ôA: Kh├┤ng cß║ºn Remaining Amount Dialog nß╗»a - xß╗¡ l├╜ qua phiß║┐u thu/chi */}

      {/* Template Dialog */}
      <Dialog open={templateDialogOpen} onOpenChange={setTemplateDialogOpen}>
        <DialogContent className="max-w-2xl max-h-[80vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>Mß║½u phß║ún hß╗ôi bß║úo h├ánh</DialogTitle>
            <DialogDescription>
              Chß╗ìn mß║½u phß║ún hß╗ôi ─æß╗â copy nß╗Öi dung. Sß╗¡ dß╗Ñng {'{ticketId}'} ─æß╗â thay m├ú phiß║┐u tß╗▒ ─æß╗Öng.
            </DialogDescription>
          </DialogHeader>
          
          <div className="space-y-4 mt-4">
            {responseTemplates.map((template) => (
              <Card key={template.id} className="hover:shadow-md transition-shadow">
                <CardHeader className="pb-3">
                  <div className="flex items-start justify-between">
                    <CardTitle className="text-h4">{template.name}</CardTitle>
                    <Button
                      size="sm"
                      variant="outline"
                      onClick={() => {
                        // Replace placeholders
                        let content = template.content;
                        if (ticket) {
                          content = content.replace(/{ticketId}/g, ticket.id);
                          content = content.replace(/{customerName}/g, ticket.customerName);
                          content = content.replace(/{trackingCode}/g, ticket.trackingCode);
