export const sapoOrderImportConfig: ImportExportConfig<Order> = {
  entityType: 'orders-sapo',
  entityDisplayName: '─É╞ín h├áng (Sapo)',
  
  fields: sapoOrderFields as unknown as FieldConfig<Order>[],
  
  templateFileName: 'Mau_Sapo_Don_Hang.xlsx',
  sheetName: 'Sheet0',
  
  // Import settings
  upsertKey: 'id',
  allowUpdate: false,  // Chß╗ë th├¬m mß╗¢i
  allowInsert: true,
  
  requirePreview: true,
  maxRows: 5000,  // Sapo export c├│ thß╗â lß╗¢n
  maxErrorsAllowed: 0,
  
  // Pre-transform: Map Sapo column names to internal keys
  preTransformRawRow: (rawRow) => {
    const result: Record<string, unknown> = {};
    
    for (const [sapoCol, value] of Object.entries(rawRow)) {
      const internalKey = SAPO_COLUMN_MAP[sapoCol];
      if (internalKey) {
        result[internalKey] = value;
      } else {
        // Keep original key if no mapping
        result[sapoCol] = value;
      }
    }
    
    return result;
  },
  
  // Validate each row
  validateRow: (row, _index, existingData, mode) => {
    const errors: Array<{ field?: string; message: string }> = [];
    const importRow = row as unknown as SapoOrderImportRow;
    
    // M├ú ─æ╞ín h├áng bß║»t buß╗Öc
    if (!importRow.orderId) {
      errors.push({ field: 'orderId', message: 'M├ú ─æ╞ín h├áng kh├┤ng ─æ╞░ß╗úc ─æß╗â trß╗æng' });
    }
    
    // M├ú h├áng bß║»t buß╗Öc (─æß╗â tß║ío line item)
    if (!importRow.productId && !importRow.productName) {
      errors.push({ field: 'productId', message: 'M├ú h├áng hoß║╖c t├¬n h├áng kh├┤ng ─æ╞░ß╗úc ─æß╗â trß╗æng' });
    }
    
    // Sß╗æ l╞░ß╗úng phß║úi > 0
    if (importRow.quantity !== undefined && importRow.quantity <= 0) {
      errors.push({ field: 'quantity', message: 'Sß╗æ l╞░ß╗úng phß║úi lß╗¢n h╞ín 0' });
    }
    
    // Check duplicate orderId in existing data (warning only)
    if (mode === 'insert-only' && importRow.orderId) {
      const duplicate = existingData.find(o => 
        o.id.toUpperCase() === importRow.orderId.toUpperCase()
      );
      if (duplicate) {
        errors.push({ field: 'orderId', message: `[Warning] M├ú ─æ╞ín h├áng "${importRow.orderId}" ─æ├ú tß╗ôn tß║íi - sß║╜ bß╗Å qua` });
      }
    }
    
    return errors;
  },
  
  // Transform: Group rows by orderId and build Order objects
  beforeImport: async (data: Order[], context?: any) => {
    const importRows = data as unknown as SapoOrderImportRow[];
    
    // Get data from storeContext
    const customers = context?.storeContext?.customerStore?.data || [];
    const products = context?.storeContext?.productStore?.data || [];
    const branches = context?.storeContext?.branchStore?.data || [];
    const employees = context?.storeContext?.employeeStore?.data || [];
    
    // Group rows by orderId
    const orderMap = new Map<string, SapoOrderImportRow[]>();
    
    for (const row of importRows) {
      const orderId = row.orderId?.trim();
      if (!orderId) continue;
      
      if (!orderMap.has(orderId)) {
        orderMap.set(orderId, []);
      }
      orderMap.get(orderId)!.push(row);
    }
    
    // Build Order objects
    const orders: Order[] = [];
    const now = new Date().toISOString();
    const defaultBranch = getDefaultBranch(branches);
    
    for (const [orderId, rows] of orderMap.entries()) {
      if (rows.length === 0) continue;
      
      const firstRow = rows[0];
      
      // Lookup customer
      const customer = findCustomer(firstRow.customerId || '', customers) || findCustomer(firstRow.customerName || '', customers);
      
      // Lookup branch
      const branch = findBranch(firstRow.branchName || '', branches) || defaultBranch;
      
      // Lookup salesperson
      const salesperson = findEmployee(firstRow.salesperson || '', employees) || findEmployee(firstRow.createdByName || '', employees);
      
      // Build line items
      const lineItems: LineItem[] = [];
      for (const row of rows) {
        // Skip if no product info
        if (!row.productId && !row.productName) continue;
        
        const product = findProduct(row.productId || '', products) || findProduct(row.barcode || '', products);
        
        const quantity = Math.max(1, Math.floor(Number(row.quantity) || 1));
        const unitPrice = Number(row.unitPrice) || (product?.sellingPrice ?? 0);
        const discount = Number(row.lineDiscountAmount) || 0;
        
        lineItems.push({
          productSystemId: product?.systemId || asSystemId(''),
          productId: asBusinessId(product?.id || row.productId || ''),
          productName: product?.name || row.productName || '',
          quantity,
          unitPrice,
          discount,
          discountType: 'fixed',
          note: row.productNote,
        });
      }
      
      if (lineItems.length === 0) continue;
      
      // Calculate totals
      const subtotal = lineItems.reduce((sum, item) => {
        return sum + (item.unitPrice * item.quantity) - (item.discount || 0);
      }, 0);
      
      const shippingFee = Number(firstRow.shippingFee) || 0;
      const orderDiscount = Number(firstRow.orderDiscountAmount) || 0;
      const grandTotal = Number(firstRow.grandTotal) || (subtotal + shippingFee - orderDiscount);
      const paidAmount = Number(firstRow.paidAmount) || 0;
      
      // Build shipping address
      const shippingAddress: OrderAddress | undefined = firstRow.shippingStreet ? {
        street: firstRow.shippingStreet,
        ward: firstRow.shippingWard || '',
        district: firstRow.shippingDistrict || '',
        province: firstRow.shippingProvince || '',
        contactName: firstRow.recipientName || firstRow.customerName,
        phone: firstRow.recipientPhone || firstRow.customerPhone,
        formattedAddress: [
          firstRow.shippingStreet,
          firstRow.shippingWard,
          firstRow.shippingDistrict,
          firstRow.shippingProvince
        ].filter(Boolean).join(', '),
      } : undefined;
      
      // Map statuses
      const status = SAPO_ORDER_STATUS_MAP[firstRow.status || ''] || '─Éß║╖t h├áng';
      const paymentStatus = SAPO_PAYMENT_STATUS_MAP[firstRow.paymentStatus || ''] || 'Ch╞░a thanh to├ín';
      const packagingStatus = SAPO_PACKAGING_STATUS_MAP[firstRow.packagingStatus || ''] || 'Ch╞░a ─æ├│ng g├│i';
      const stockOutStatus = SAPO_STOCK_OUT_STATUS_MAP[firstRow.stockOutStatus || ''] || 'Ch╞░a xuß║Ñt kho';
      const returnStatus = SAPO_RETURN_STATUS_MAP[firstRow.returnStatus || ''] || 'Ch╞░a trß║ú h├áng';
      
      // Determine delivery status from package status
      let deliveryStatus: OrderDeliveryStatus = 'Chß╗¥ ─æ├│ng g├│i';
      if (firstRow.packageStatus) {
        deliveryStatus = SAPO_DELIVERY_STATUS_MAP[firstRow.packageStatus] || 'Chß╗¥ ─æ├│ng g├│i';
      } else if (packagingStatus === '─É├ú ─æ├│ng g├│i') {
        deliveryStatus = '─Éang giao h├áng';
      }
      
      // Build Order object
      const order: Order = {
        systemId: asSystemId(''), // Will be generated
        id: asBusinessId(orderId),
        
        // Customer info
        customerSystemId: customer?.systemId || asSystemId(''),
        customerName: customer?.name || firstRow.customerName || 'Kh├ích lß║╗',
        
        // Branch & Staff
        branchSystemId: branch?.systemId || asSystemId(''),
        branchName: branch?.name || firstRow.branchName || '',
        salesperson: salesperson?.fullName || firstRow.salesperson || '',
        salespersonSystemId: salesperson?.systemId || asSystemId(''),
        
        // Dates
        orderDate: parseSapoDate(firstRow.orderDate) || now,
        completedDate: parseSapoDate(firstRow.completedDate),
        createdAt: parseSapoDate(firstRow.orderDate) || now,
        createdBy: salesperson?.systemId || asSystemId('SYSTEM'),
        updatedAt: now,
        updatedBy: asSystemId('SYSTEM'),
        
        // Line items
        lineItems,
        
        // Totals
        subtotal,
        shippingFee,
        tax: 0,
        orderDiscount,
        grandTotal,
        paidAmount,
        codAmount: Number(firstRow.codAmount) || 0,
        
        // Statuses
        status,
        paymentStatus,
        deliveryStatus,
        printStatus: 'Ch╞░a in' as OrderPrintStatus,
        stockOutStatus,
        returnStatus,
        
        // Shipping
        deliveryMethod: (firstRow.carrier ? 'Dß╗ïch vß╗Ñ giao h├áng' : 'Nhß║¡n tß║íi cß╗¡a h├áng') as OrderDeliveryMethod,
        shippingAddress,
        
        // Other
        source: `Sapo: ${firstRow.source || 'Import'}`,
        notes: firstRow.notes,
        tags: firstRow.tags?.split(',').map(t => t.trim()).filter(Boolean),
        
        // Initialize arrays - kh├┤ng tß║ío packagings v├¼ cß║Ñu tr├║c phß╗⌐c tß║íp
        payments: [],
        packagings: [],
      };
      
      orders.push(order);
    }
    
    return orders;
  },
};

