// ============================================

export const orderImportExportConfig: ImportExportConfig<Order> = {
  entityType: 'orders',
  entityDisplayName: '─É╞ín h├áng',
  
  fields: orderFields as unknown as FieldConfig<Order>[],
  
  templateFileName: 'Mau_Nhap_Don_Hang.xlsx',
  sheetName: '─É╞ín h├áng',
  
  // Import settings
  upsertKey: 'id',
  allowUpdate: false,  // Chß╗ë cho ph├⌐p th├¬m mß╗¢i, kh├┤ng update ─æ╞ín h├áng qua import
  allowInsert: true,
  
  requirePreview: true,
  maxRows: 1000,
  maxErrorsAllowed: 0,  // Kh├┤ng cho ph├⌐p lß╗ùi
  
  // Pre-process: Fill empty orderId/customerId from previous row
  // User must fill orderId + customerId on first row of each order
  // Subsequent product rows can leave them empty ΓåÆ will inherit from previous row
  preProcessRows: (rows: unknown[]) => {
    const importRows = rows as OrderImportRow[];
    let currentOrderId = '';
    let currentCustomerId = '';
    
    for (const row of importRows) {
      // If orderId is provided, use it and update current
      if (row.orderId?.trim()) {
        currentOrderId = row.orderId.trim();
        // Also update customerId if provided on the same row
        if (row.customerId?.trim()) {
          currentCustomerId = row.customerId.trim();
        }
      } else if (currentOrderId) {
        // Fill from previous row's orderId (for subsequent product lines)
        row.orderId = currentOrderId;
      }
      // Note: if orderId is empty and no previous orderId ΓåÆ validation will catch it
      
      // Fill customerId if empty (inherit from previous row)
      if (!row.customerId?.trim() && currentCustomerId) {
        row.customerId = currentCustomerId;
      } else if (row.customerId?.trim()) {
        currentCustomerId = row.customerId.trim();
      }
    }
    
    return importRows;
  },
  
  // Validate row (after pre-processing)
  validateRow: (row, _index, existingData, mode) => {
    const errors: Array<{ field?: string; message: string }> = [];
    const importRow = row as unknown as OrderImportRow;
    
    // Check required fields - orderId must be filled on first row of each order
    if (!importRow.orderId) {
      errors.push({ field: 'orderId', message: 'M├ú ─æ╞ín h├áng kh├┤ng ─æ╞░ß╗úc ─æß╗â trß╗æng (bß║»t buß╗Öc ─æiß╗ün ß╗ƒ d├▓ng ─æß║ºu cß╗ºa mß╗ùi ─æ╞ín)' });
    }
    if (!importRow.customerId) {
      errors.push({ field: 'customerId', message: 'M├ú kh├ích h├áng kh├┤ng ─æ╞░ß╗úc ─æß╗â trß╗æng (─æiß╗ün ß╗ƒ d├▓ng ─æß║ºu cß╗ºa mß╗ùi ─æ╞ín)' });
    }
    if (!importRow.productSku) {
      errors.push({ field: 'productSku', message: 'SKU sß║ún phß║⌐m kh├┤ng ─æ╞░ß╗úc ─æß╗â trß╗æng' });
    }
    
    // Validate customer
    if (importRow.customerId) {
      const customer = (findCustomerById as any)(importRow.customerId);
      if (!customer) {
        errors.push({ field: 'customerId', message: `Kh├┤ng t├¼m thß║Ñy kh├ích h├áng "${importRow.customerId}"` });
      }
    }
    
    // Validate product
    if (importRow.productSku) {
      const product = (findProductBySku as any)(importRow.productSku);
      if (!product) {
        errors.push({ field: 'productSku', message: `Kh├┤ng t├¼m thß║Ñy sß║ún phß║⌐m "${importRow.productSku}"` });
      }
    }
    
    // Validate branch if provided
    if (importRow.branchName) {
      const branch = (findBranch as any)(importRow.branchName);
      if (!branch) {
        errors.push({ field: 'branchName', message: `Kh├┤ng t├¼m thß║Ñy chi nh├ính "${importRow.branchName}"` });
      }
    }
    
    // Validate salesperson if provided
    if (importRow.salespersonName) {
      const employee = (findEmployee as any)(importRow.salespersonName);
      if (!employee) {
        errors.push({ field: 'salespersonName', message: `Kh├┤ng t├¼m thß║Ñy nh├ón vi├¬n "${importRow.salespersonName}"` });
      }
    }
    
    // Validate quantity
    if (importRow.quantity !== undefined) {
      const qty = Number(importRow.quantity);
      if (isNaN(qty) || qty <= 0) {
        errors.push({ field: 'quantity', message: 'Sß╗æ l╞░ß╗úng phß║úi l├á sß╗æ d╞░╞íng' });
      }
    }
    
    // Check duplicate order ID in existing data (only in insert-only mode)
    if (mode === 'insert-only' && importRow.orderId) {
      const duplicate = existingData.find(o => 
        o.id.toUpperCase() === importRow.orderId.toUpperCase()
      );
      if (duplicate) {
        errors.push({ field: 'orderId', message: `M├ú ─æ╞ín h├áng "${importRow.orderId}" ─æ├ú tß╗ôn tß║íi` });
      }
    }
    
    return errors;
  },
  
  // Transform: Group rows by orderId and build Order objects
  // This is handled in postTransformRow and beforeImport
  beforeImport: async (data: Order[]) => {
    // data here is actually OrderImportRow[] after field transforms
    const importRows = data as unknown as OrderImportRow[];
    
    // Group rows by orderId
    const orderMap = new Map<string, {
      rows: OrderImportRow[];
      customer?: Customer;
      branch?: ReturnType<typeof findBranch>;
      employee?: ReturnType<typeof findEmployee>;
    }>();
    
    for (const row of importRows) {
      const orderId = row.orderId?.trim().toUpperCase();
      if (!orderId) continue;
      
      if (!orderMap.has(orderId)) {
        const customer = (findCustomerById as any)(row.customerId);
        const branch = row.branchName ? (findBranch as any)(row.branchName) : (getDefaultBranch as any)();
        const employee = row.salespersonName ? (findEmployee as any)(row.salespersonName) : undefined;
        
        orderMap.set(orderId, {
          rows: [],
          customer,
          branch,
          employee,
        });
      }
      orderMap.get(orderId)!.rows.push(row);
    }
    
    // Build Order objects
    const orders: Order[] = [];
    const now = new Date().toISOString();
    
    for (const [orderId, { rows, customer, branch, employee }] of orderMap.entries()) {
      if (!customer || rows.length === 0) continue;
      
      // Build line items
      const lineItems: LineItem[] = [];
      for (const row of rows) {
        const product = (findProductBySku as any)(row.productSku);
        if (!product) continue;
        
        const quantity = Math.max(1, Math.floor(Number(row.quantity) || 1));
        const unitPrice = row.unitPrice ?? product.sellingPrice ?? product.costPrice ?? 0;
        
        lineItems.push({
          productSystemId: product.systemId,
          productId: product.id,
          productName: product.name,
          quantity,
          unitPrice,
          discount: 0,
          discountType: 'fixed',
          note: row.lineNote,
        });
      }
      
      if (lineItems.length === 0) continue;
      
      // Calculate totals
      const subtotal = lineItems.reduce((sum, item) => {
        return sum + (item.unitPrice * item.quantity);
      }, 0);
      
      // Get first row for order-level data
      const firstRow = rows[0];
      
      // Parse order date
      let orderDate = now;
      if (firstRow.orderDate) {
        const parsed = new Date(firstRow.orderDate);
        if (!isNaN(parsed.getTime())) {
          orderDate = parsed.toISOString();
        }
      }
      
      // Build shipping address from customer
      const shippingAddress = getCustomerShippingAddress(customer);
      
      // Parse tags
      const tags = firstRow.tags 
        ? firstRow.tags.split(',').map(t => t.trim()).filter(Boolean)
        : undefined;
      
      const order: Order = {
        systemId: asSystemId(''), // Will be assigned by store
        id: asBusinessId(orderId),
        customerSystemId: customer.systemId,
        customerName: customer.name,
        branchSystemId: branch?.systemId || asSystemId(''),
        branchName: branch?.name || '',
        salespersonSystemId: employee?.systemId || asSystemId(''),
        salesperson: employee?.fullName || '',
        orderDate,
        
        // Statuses - all new orders start with "─Éß║╖t h├áng"
        status: '─Éß║╖t h├áng',
        paymentStatus: 'Ch╞░a thanh to├ín',
        deliveryStatus: 'Chß╗¥ ─æ├│ng g├│i',
        printStatus: 'Ch╞░a in',
        stockOutStatus: 'Ch╞░a xuß║Ñt kho',
        returnStatus: 'Ch╞░a trß║ú h├áng',
        deliveryMethod: 'Dß╗ïch vß╗Ñ giao h├áng',
        
        // Address
        shippingAddress,
        
        // Line items
        lineItems,
        
        // Totals (no discount, no shipping fee from import)
        subtotal,
        shippingFee: 0,
        tax: 0,
        grandTotal: subtotal,
        paidAmount: 0,
        codAmount: 0,
        
        // Arrays
        payments: [],
        packagings: [],
        
        // Optional fields
        notes: firstRow.orderNote,
        source: firstRow.source,
        tags,
        
        // Timestamps
        createdAt: now,
        updatedAt: now,
      };
      
      orders.push(order);
    }
    
    return orders;
  },
};

