    }
    
    if (!receipt.payerTypeName) {
      errors.push({ field: 'payerTypeName', message: 'Loß║íi ─æß╗æi t╞░ß╗úng kh├┤ng ─æ╞░ß╗úc ─æß╗â trß╗æng' });
    }
    
    if (!receipt.payerName?.trim()) {
      errors.push({ field: 'payerName', message: 'Ng╞░ß╗¥i nß╗Öp kh├┤ng ─æ╞░ß╗úc ─æß╗â trß╗æng' });
    }
    
    if (!receipt.paymentReceiptTypeName) {
      errors.push({ field: 'paymentReceiptTypeName', message: 'Loß║íi phiß║┐u thu kh├┤ng ─æ╞░ß╗úc ─æß╗â trß╗æng' });
    }
    
    // Check duplicate
    if (mode === 'insert-only' && receipt.id) {
      const duplicate = existingData.find(r => 
        r.id.toString().toUpperCase() === receipt.id!.toString().toUpperCase()
      );
      if (duplicate) {
        errors.push({ field: 'id', message: `M├ú phiß║┐u "${receipt.id}" ─æ├ú tß╗ôn tß║íi` });
      }
    }
    
    return errors;
  },
  
  // Transform row to Receipt object
  postTransformRow: (row) => {
    const now = new Date().toISOString();
    const defaultBranch = (getDefaultBranch as any)();
    const defaultPaymentMethod = (getDefaultPaymentMethod as any)();
    
    // Lookup entities
    const branch = (findBranch as any)(row.branchName as string) || defaultBranch;
    const receiptType = (findReceiptType as any)(row.paymentReceiptTypeName as string);
    const paymentMethod = (findPaymentMethod as any)(row.paymentMethodName as string) || defaultPaymentMethod;
    const targetGroup = (findTargetGroup as any)(row.payerTypeName as string);
    const payer = (findPayer as any)(row.payerTypeName as string || '', row.payerName as string || '');
    
    return {
      systemId: asSystemId(''), // Will be generated
      id: asBusinessId(String(row.id || '').trim()),
      date: String(row.date || now.split('T')[0]),
      amount: Number(row.amount) || 0,
      
      payerTypeSystemId: targetGroup?.systemId || asSystemId('KHAC'),
      payerTypeName: targetGroup?.name || String(row.payerTypeName || 'Kh├íc'),
      payerName: String(row.payerName || '').trim(),
      payerSystemId: payer?.systemId,
      
      description: String(row.description || '').trim(),
      
      paymentMethodSystemId: paymentMethod?.systemId || asSystemId(''),
      paymentMethodName: paymentMethod?.name || String(row.paymentMethodName || 'Tiß╗ün mß║╖t'),
      
      accountSystemId: asSystemId(''), // Cash account to be set later
      paymentReceiptTypeSystemId: receiptType?.systemId || asSystemId(''),
      paymentReceiptTypeName: receiptType?.name || String(row.paymentReceiptTypeName || ''),
      
      branchSystemId: branch?.systemId || asSystemId(''),
      branchName: branch?.name || '',
      
      createdBy: asSystemId(''),
      createdAt: now,
      
      status: (row.status as ReceiptStatus) || 'completed',
      category: (row.category as ReceiptCategory) || 'other',
    } as Receipt;
  },
};

/**
 * Payroll Engine V3
 *
 * Pure calculation engine - NO ID generation.
 * ID generation is delegated to stores (payroll-batch-store.ts)
 * following ID-GOVERNANCE.md guidelines.
 *
 * Features:
 * - Vietnamese labor law compliant (BHXH, BHYT, BHTN, PIT)
 * - Configurable rates from settings (no hardcoded values)
 * - Better penalty integration (selective penalty deduction)
 * - Complaint tracking via linkedComplaintSystemId
 * - Stricter validation (locked attendance required)
 * - Preview mode for dry-run calculations
 */

import { attendanceSnapshotService, type AttendanceSnapshot } from './attendance-snapshot-service';
import type {
  PayrollComponent,
  PayrollComponentEntry,
  PayrollTotals,
} from './payroll-types';
import type { Penalty } from '@/lib/types/prisma-extended';
import type { SystemId, BusinessId } from './id-types';
import { getEmployeeSettingsSync, getEmployeeSettings as _getEmployeeSettings } from '../features/settings/employees/employee-settings-service';
import type { EmployeeSettings as _EmployeeSettings, InsuranceRates, TaxBracket } from '@/lib/types/prisma-extended';

