// MAIN ENGINE
// =============================================

export const payrollEngine = {
  /**
   * Calculate payroll for multiple employees
   * Returns calculation results - NO IDs generated
   * Store will handle ID generation when saving
   */
  calculate(options: PayrollRunOptions): PayrollCalculationResult {
    const {
      periodMonthKey,
      employees,
      components,
      penaltyMode,
      selectedPenaltySystemIds,
      penalties,
      requireLockedAttendance = true,
      skipAttendanceValidation = false,
    } = options;

    const warnings: PayrollWarning[] = [];
    const errors: PayrollError[] = [];
    const allDeductedPenalties: DeductedPenaltyInfo[] = [];
    const payslips: CalculatedPayslip[] = [];

    // Validate inputs
    if (!components.length) {
      errors.push({
        type: 'validation',
        message: 'Ch╞░a c├│ th├ánh phß║ºn l╞░╞íng n├áo ─æ╞░ß╗úc chß╗ìn',
        fatal: true,
      });
      return {
        success: false,
        payslips: [],
        summary: { totalGross: 0, totalNet: 0, totalPenaltyDeductions: 0, employeeCount: 0 },
        warnings,
        errors,
        penaltiesDeducted: [],
      };
    }

    if (!employees.length) {
      errors.push({
        type: 'validation',
        message: 'Ch╞░a chß╗ìn nh├ón vi├¬n n├áo',
        fatal: true,
      });
      return {
        success: false,
        payslips: [],
        summary: { totalGross: 0, totalNet: 0, totalPenaltyDeductions: 0, employeeCount: 0 },
        warnings,
        errors,
        penaltiesDeducted: [],
      };
    }

    // Process each employee
    for (const employee of employees) {
      // Attendance validation
      if (!skipAttendanceValidation) {
        const attendance = attendanceSnapshotService.getSnapshot({
          monthKey: periodMonthKey,
          employeeSystemId: employee.employeeSystemId,
        });

        if (!attendance) {
          warnings.push({
            type: 'attendance-missing',
            employeeSystemId: employee.employeeSystemId,
            employeeName: employee.employeeName,
            message: `Kh├┤ng c├│ dß╗» liß╗çu chß║Ñm c├┤ng cho ${employee.employeeName} trong kß╗│ ${periodMonthKey}`,
          });
        } else if (requireLockedAttendance && !(attendance as any).locked) {
          warnings.push({
            type: 'attendance-unlocked',
            employeeSystemId: employee.employeeSystemId,
            employeeName: employee.employeeName,
            message: `Chß║Ñm c├┤ng ch╞░a kh├│a cho ${employee.employeeName} trong kß╗│ ${periodMonthKey}`,
          });
        }
      }

      // Calculate
      const { payslip, penalties: deductedPenalties } = calculateForEmployee(
        employee,
        periodMonthKey,
        components,
        penaltyMode,
        selectedPenaltySystemIds,
        penalties
      );

      payslips.push(payslip);
      allDeductedPenalties.push(...deductedPenalties);
    }

    // Calculate summary
    const totalGross = payslips.reduce((sum, p) => sum + p.totals.earnings, 0);
    const totalNet = payslips.reduce((sum, p) => sum + p.totals.netPay, 0);
    const totalPenaltyDeductions = payslips.reduce((sum, p) => sum + (p.totals.penaltyDeductions ?? 0), 0);

    return {
      success: true,
      payslips,
      summary: {
        totalGross,
        totalNet,
        totalPenaltyDeductions,
        employeeCount: payslips.length,
      },
      warnings,
      errors,
      penaltiesDeducted: allDeductedPenalties,
    };
  },

  /**
   * Preview calculation (alias for calculate - no side effects)
   */
  preview(options: PayrollRunOptions): PayrollCalculationResult {
    return this.calculate(options);
  },

  /**
   * Calculate for a single employee
   */
  calculateSingle(
    employee: EmployeePayrollInput,
    periodMonthKey: string,
    components: PayrollComponent[],
    penaltyMode: PenaltySelectionMode = 'none',
    selectedPenaltySystemIds?: SystemId[],
    penalties?: Penalty[]
  ): CalculatedPayslip {
    const { payslip } = calculateForEmployee(
      employee,
      periodMonthKey,
      components,
      penaltyMode,
      selectedPenaltySystemIds,
      penalties
    );
    return payslip;
  },

  /**
   * Get unpaid penalties for an employee
   * @param penalties - Injected penalties array (if not provided, returns empty)
   */
  getUnpaidPenalties(employeeSystemId: SystemId, penalties?: Penalty[]): Penalty[] {
    return collectPenaltiesForEmployee(employeeSystemId, 'all-unpaid', undefined, penalties);
  },

  /**
   * Get unpaid penalties for multiple employees
   * @param penalties - Injected penalties array (if not provided, returns empty)
   */
  getUnpaidPenaltiesMap(employeeSystemIds: SystemId[], penalties?: Penalty[]): Map<SystemId, Penalty[]> {
    const result = new Map<SystemId, Penalty[]>();
    for (const systemId of employeeSystemIds) {
      result.set(systemId, this.getUnpaidPenalties(systemId, penalties));
    }
    return result;
  },

  /**
   * Validate prerequisites before running payroll
   */
  validatePrerequisites(
    periodMonthKey: string,
    employeeSystemIds: SystemId[],
    employeeNames?: Map<SystemId, string>
  ): { valid: boolean; issues: PayrollWarning[] } {
    const issues: PayrollWarning[] = [];

    for (const employeeSystemId of employeeSystemIds) {
      const attendance = attendanceSnapshotService.getSnapshot({
        monthKey: periodMonthKey,
        employeeSystemId,
      });

      const employeeName = employeeNames?.get(employeeSystemId) ?? employeeSystemId;

      if (!attendance) {
        issues.push({
          type: 'attendance-missing',
          employeeSystemId,
          employeeName,
          message: `Kh├┤ng c├│ dß╗» liß╗çu chß║Ñm c├┤ng cho kß╗│ ${periodMonthKey}`,
        });
      } else if (!(attendance as any).locked) {
        issues.push({
          type: 'attendance-unlocked',
          employeeSystemId,
          employeeName,
          message: `Chß║Ñm c├┤ng ch╞░a ─æ╞░ß╗úc kh├│a cho kß╗│ ${periodMonthKey}`,
        });
      }
    }

    return {
      valid: issues.length === 0,
      issues,
    };
  },
};

export default payrollEngine;

