 */
export async function uploadProductImage(
  imageFile: File,
  options?: {
    filenameSlug?: string;
    goodsId?: number;
  },
  settings: PkgxSettings = {} as any
): Promise<ApiResponse<PkgxImageUploadResponse>> {
  const { apiUrl, apiKey, enabled } = getApiConfig(settings);

  if (!enabled) {
    return { success: false, error: 'T├¡ch hß╗úp PKGX ch╞░a ─æ╞░ß╗úc bß║¡t' };
  }

  if (!apiKey) {
    return { success: false, error: 'Ch╞░a cß║Ñu h├¼nh API Key' };
  }

  const url = `${apiUrl}?action=upload_product_image`;
  const formData = new FormData();
  formData.append('image_file', imageFile);

  if (options?.filenameSlug) {
    formData.append('filename_slug', options.filenameSlug);
  }

  if (options?.goodsId) {
    formData.append('goods_id', options.goodsId.toString());
  }

  try {
    const response = await fetch(url, {
      method: 'POST',
      headers: { 'X-API-KEY': apiKey },
      body: formData,
    });

    const data = await response.json();

    if (data.error) {
      return { success: false, error: data.message };
    }

    return { success: true, data };
  } catch (error) {
    return {
      success: false,
      error: error instanceof Error ? error.message : 'Kh├┤ng thß╗â upload ß║únh',
    };
  }
}

