/**
 * Kiß╗âm tra URL c├│ phß║úi l├á URL c├┤ng khai kh├┤ng (kh├┤ng phß║úi localhost/internal)
 */
function isPublicUrl(url: string): boolean {
  try {
    const parsed = new URL(url);
    const hostname = parsed.hostname.toLowerCase();
    
    // Loß║íi bß╗Å c├íc URL nß╗Öi bß╗Ö
    if (hostname === 'localhost' || 
        hostname === '127.0.0.1' ||
        hostname.startsWith('192.168.') ||
        hostname.startsWith('10.') ||
        hostname.endsWith('.local')) {
      return false;
    }
    return true;
  } catch {
    return false;
  }
}

/**
 * Kiß╗âm tra xem URL c├│ phß║úi l├á ß║únh base64 kh├┤ng
 */
function isBase64Image(url: string): boolean {
  return url.startsWith('data:image/');
}

/**
 * Kiß╗âm tra xem URL ─æ├ú l├á URL cß╗ºa PKGX CDN ch╞░a
 */
function isPkgxCdnUrl(url: string): boolean {
  return url.includes('phukiengiaxuong.com.vn/cdn/');
}

/**
 * Xß╗¡ l├╜ HTML ─æß╗â upload tß║Ñt cß║ú ß║únh l├¬n PKGX v├á thay thß║┐ URL
 * 
 * H├ám n├áy sß║╜:
 * 1. T├¼m tß║Ñt cß║ú <img> tags trong HTML
 * 2. Vß╗¢i mß╗ùi ß║únh c├│ src l├á URL c├┤ng khai (kh├┤ng phß║úi localhost):
 *    - Upload l├¬n PKGX qua upload_image_from_url
 *    - Thay thß║┐ src bß║▒ng URL mß╗¢i tr├¬n PKGX CDN
 * 3. Vß╗¢i ß║únh base64: bß╗Å qua (qu├í nß║╖ng, kh├┤ng sync)
 * 4. Vß╗¢i ß║únh ─æ├ú tr├¬n PKGX CDN: giß╗» nguy├¬n
 * 
 * @param html - HTML content cß║ºn xß╗¡ l├╜
 * @param filenamePrefix - Prefix cho t├¬n file (optional)
 * @returns HTML ─æ├ú ─æ╞░ß╗úc xß╗¡ l├╜ vß╗¢i URLs mß╗¢i
 */
export async function processHtmlImagesForPkgx(
  html: string,
  filenamePrefix?: string,
  settings: PkgxSettings = {} as any
): Promise<{ processedHtml: string; uploadedCount: number; skippedCount: number; errors: string[] }> {
  if (!html) {
    return { processedHtml: html, uploadedCount: 0, skippedCount: 0, errors: [] };
  }

  // Regex ─æß╗â t├¼m tß║Ñt cß║ú <img> tags
  const imgRegex = /<img[^>]+src=["']([^"']+)["'][^>]*>/gi;
  
  let processedHtml = html;
  let uploadedCount = 0;
  let skippedCount = 0;
  const errors: string[] = [];
  
  // T├¼m tß║Ñt cß║ú c├íc ß║únh
  const matches: Array<{ fullMatch: string; src: string }> = [];
  let match;
  while ((match = imgRegex.exec(html)) !== null) {
    matches.push({ fullMatch: match[0], src: match[1] });
  }

  // Xß╗¡ l├╜ tß╗½ng ß║únh
  for (let i = 0; i < matches.length; i++) {
    const { fullMatch, src } = matches[i];
    
    // Skip base64 images
    if (isBase64Image(src)) {
      skippedCount++;
      errors.push(`Bß╗Å qua ß║únh base64 (kh├┤ng hß╗ù trß╗ú upload base64)`);
      continue;
    }
    
    // Skip if already on PKGX CDN
    if (isPkgxCdnUrl(src)) {
      skippedCount++;
      continue;
    }
    
    // Skip localhost/internal URLs
    if (!isPublicUrl(src)) {
      skippedCount++;
      errors.push(`Bß╗Å qua URL nß╗Öi bß╗Ö: ${src.substring(0, 50)}...`);
      continue;
    }
    
    // Upload to PKGX
    try {
      const slug = filenamePrefix 
        ? `${filenamePrefix}-desc-img-${i + 1}` 
        : `desc-img-${Date.now()}-${i + 1}`;
      
      const uploadResult = await uploadImageFromUrl(src, { filenameSlug: slug }, settings);
      
      if (uploadResult.success && uploadResult.data?.data?.full_urls?.original) {
        // Replace src in HTML
        const newSrc = uploadResult.data.data.full_urls.original;
        const newImgTag = fullMatch.replace(src, newSrc);
        processedHtml = processedHtml.replace(fullMatch, newImgTag);
        uploadedCount++;
      } else {
        errors.push(`Lß╗ùi upload ß║únh: ${uploadResult.error || 'Unknown error'}`);
        skippedCount++;
      }
    } catch (error) {
      errors.push(`Exception upload ß║únh: ${error instanceof Error ? error.message : String(error)}`);
      skippedCount++;
    }
  }

  return { processedHtml, uploadedCount, skippedCount, errors };
}

