  totalGross?: number;
  totalNet?: number;
  createdAt?: string;
  createdBy?: SystemId;
  reviewedAt?: string;
  reviewedBy?: SystemId;
  lockedAt?: string;
  lockedBy?: SystemId;
  notes?: string;
}

// Interface cho Payslip - flexible
interface PayslipLike {
  systemId: string;
  id: string;
  batchSystemId?: string;
  employeeSystemId: string;
